'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client-ssr';
import { ReviewWithImages } from '@/lib/validations/review-schema';
import { AdminReviewCard } from '@/components/reviews/AdminReviewCard';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { LogOut, Loader2, AlertCircle, CheckCircle2, Clock } from 'lucide-react';

/**
 * Admin Dashboard Page
 * Manage pending and approved reviews
 */
export default function AdminDashboardPage() {
  const [pendingReviews, setPendingReviews] = useState<ReviewWithImages[]>([]);
  const [approvedReviews, setApprovedReviews] = useState<ReviewWithImages[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [user, setUser] = useState<any>(null);
  const router = useRouter();
  const supabase = createClient();

  useEffect(() => {
    checkAuth();
    fetchReviews();
  }, []);

  const checkAuth = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      router.push('/adminaccesspoint');
    } else {
      setUser(user);
    }
  };

  const fetchReviews = async () => {
    setLoading(true);
    setError(null);

    try {
      // Fetch pending reviews
      const pendingResponse = await fetch('/api/reviews/admin/pending');
      if (!pendingResponse.ok) throw new Error('Failed to fetch pending reviews');
      const pendingData = await pendingResponse.json();
      setPendingReviews(pendingData.reviews || []);

      // Fetch approved reviews
      const approvedResponse = await fetch('/api/reviews/admin/approved');
      if (!approvedResponse.ok) throw new Error('Failed to fetch approved reviews');
      const approvedData = await approvedResponse.json();
      setApprovedReviews(approvedData.reviews || []);

    } catch (err: any) {
      console.error('Error fetching reviews:', err);
      setError(err.message || 'Failed to load reviews');
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (reviewId: string) => {
    try {
      const response = await fetch('/api/reviews/admin/approve', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ reviewId })
      });

      if (!response.ok) throw new Error('Failed to approve review');

      // Refresh reviews
      await fetchReviews();
    } catch (err: any) {
      console.error('Error approving review:', err);
      alert('Failed to approve review');
    }
  };

  const handleUnapprove = async (reviewId: string) => {
    try {
      const response = await fetch('/api/reviews/admin/unapprove', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ reviewId })
      });

      if (!response.ok) throw new Error('Failed to unapprove review');

      // Refresh reviews
      await fetchReviews();
    } catch (err: any) {
      console.error('Error unapproving review:', err);
      alert('Failed to unapprove review');
    }
  };

  const handleDelete = async (reviewId: string) => {
    try {
      const response = await fetch('/api/reviews/admin/reject', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ reviewId })
      });

      if (!response.ok) throw new Error('Failed to delete review');

      // Refresh reviews
      await fetchReviews();
    } catch (err: any) {
      console.error('Error deleting review:', err);
      alert('Failed to delete review');
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    router.push('/adminaccesspoint');
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-purple-600" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900">
      {/* Header */}
      <div className="bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
        <div className="container mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            <h1 className="text-2xl font-bold">Review Management Dashboard</h1>
            <Button onClick={handleLogout} variant="outline">
              <LogOut className="mr-2 h-4 w-4" />
              Logout
            </Button>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        {error && (
          <Alert className="mb-6 bg-red-50 border-red-200">
            <AlertCircle className="h-4 w-4 text-red-600" />
            <AlertDescription className="text-red-800">
              {error}
            </AlertDescription>
          </Alert>
        )}

        {/* Statistics */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-medium text-gray-600 dark:text-gray-400">
                Pending Reviews
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-2">
                <Clock className="w-5 h-5 text-yellow-500" />
                <span className="text-3xl font-bold">{pendingReviews.length}</span>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-medium text-gray-600 dark:text-gray-400">
                Approved Reviews
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-2">
                <CheckCircle2 className="w-5 h-5 text-green-500" />
                <span className="text-3xl font-bold">{approvedReviews.length}</span>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-medium text-gray-600 dark:text-gray-400">
                Total Reviews
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-2">
                <AlertCircle className="w-5 h-5 text-blue-500" />
                <span className="text-3xl font-bold">
                  {pendingReviews.length + approvedReviews.length}
                </span>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Reviews Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Pending Reviews */}
          <div>
            <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
              <Clock className="w-5 h-5 text-yellow-500" />
              Pending Reviews ({pendingReviews.length})
            </h2>
            <div className="space-y-4">
              {pendingReviews.length > 0 ? (
                pendingReviews.map((review) => (
                  <AdminReviewCard
                    key={review.id}
                    review={review}
                    onApprove={handleApprove}
                    onDelete={handleDelete}
                    isApproved={false}
                  />
                ))
              ) : (
                <Card>
                  <CardContent className="p-8 text-center text-gray-500">
                    No pending reviews
                  </CardContent>
                </Card>
              )}
            </div>
          </div>

          {/* Approved Reviews */}
          <div>
            <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
              <CheckCircle2 className="w-5 h-5 text-green-500" />
              Approved Reviews ({approvedReviews.length})
            </h2>
            <div className="space-y-4">
              {approvedReviews.length > 0 ? (
                approvedReviews.map((review) => (
                  <AdminReviewCard
                    key={review.id}
                    review={review}
                    onUnapprove={handleUnapprove}
                    onDelete={handleDelete}
                    isApproved={true}
                  />
                ))
              ) : (
                <Card>
                  <CardContent className="p-8 text-center text-gray-500">
                    No approved reviews yet
                  </CardContent>
                </Card>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Note-a-Day Training Method
 * Focus on one note at a time across the entire fretboard
 */

'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { NOTE_A_DAY_CYCLE, NOTE_COLORS } from '@/lib/fretboard-learning/constants';
import { getAllPositionsOfNote } from '@/lib/fretboard-learning/utils';
import TrainingControlBar from '@/components/fretboard-learning/TrainingControlBar';
import FeedbackOverlay from '@/components/fretboard-learning/FeedbackOverlay';
import SessionSummaryModal from '@/components/fretboard-learning/SessionSummaryModal';
import { FeedbackEvent, SessionStats } from '@/lib/fretboard-learning/types';
import { DifficultyLevel } from '@/lib/fretboard-learning/constants';
import Fretboard from '@/components/Fretboard';
import { NotePosition, NOTES, TUNINGS } from '@/lib/musicTheory';
import { themes } from '@/lib/themes';

type Phase = 'discovery' | 'guided' | 'speed' | 'recall';

export default function NoteADayPage() {
  const router = useRouter();

  // Training state
  const [currentNote, setCurrentNote] = useState<string>('C');
  const [currentPhase, setCurrentPhase] = useState<Phase>('discovery');
  const [isPlaying, setIsPlaying] = useState(false);
  const [difficulty, setDifficulty] = useState<DifficultyLevel>('Easy');
  const [showHints, setShowHints] = useState(true);

  // Phase-specific state
  const [currentStringIndex, setCurrentStringIndex] = useState(0); // For guided practice
  const [discoveryProgress, setDiscoveryProgress] = useState(0); // For discovery animation
  const [speedQuestionPosition, setSpeedQuestionPosition] = useState<{string: number; fret: number} | null>(null);
  const [speedIsTarget, setSpeedIsTarget] = useState(false);
  const [recallFoundPositions, setRecallFoundPositions] = useState<Set<string>>(new Set());
  const [recallTimeLeft, setRecallTimeLeft] = useState(60);

  // Session tracking
  const [elapsedTime, setElapsedTime] = useState(0);
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [feedback, setFeedback] = useState<FeedbackEvent | null>(null);
  const [sessionStats, setSessionStats] = useState<SessionStats | null>(null);
  const [showSummary, setShowSummary] = useState(false);

  // Fretboard settings
  const tuning = TUNINGS[6]['Standard'];
  const theme = themes.dark;

  // Get all positions of the current note on the fretboard (like Individual Notes mode)
  const notePositions = useMemo((): NotePosition[] => {
    const positions: NotePosition[] = [];
    const targetNoteIndex = NOTES.indexOf(currentNote);

    // Find all positions of the target note across all strings and frets
    tuning.forEach((openNote, stringIndex) => {
      const openNoteIndex = NOTES.indexOf(openNote);

      for (let fret = 0; fret <= 24; fret++) {
        const noteIndex = (openNoteIndex + fret) % 12;

        if (noteIndex === targetNoteIndex) {
          positions.push({
            stringIndex,
            fretNumber: fret,
            note: currentNote,
            isRoot: true, // All instances are the target note
          });
        }
      }
    });

    return positions;
  }, [currentNote, tuning]);

  // Load compatible scales when note changes
  // Timer effect
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isPlaying) {
      interval = setInterval(() => {
        setElapsedTime((prev) => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isPlaying]);

  const handlePlayPause = () => {
    setIsPlaying(!isPlaying);
  };

  const handleReset = () => {
    setIsPlaying(false);
    setElapsedTime(0);
    setScore(0);
    setStreak(0);
    setCurrentPhase('discovery');
  };

  const handleDifficultyChange = (newDifficulty: DifficultyLevel) => {
    setDifficulty(newDifficulty);
  };

  const handleToggleHints = () => {
    setShowHints(!showHints);
  };

  const handleNoteChange = (note: string) => {
    setCurrentNote(note);
    setCurrentPhase('discovery');
    setScore(0);
    setStreak(0);
  };

  const handlePhaseChange = (phase: Phase) => {
    setCurrentPhase(phase);
    // Reset phase-specific state
    setCurrentStringIndex(0);
    setDiscoveryProgress(0);
    setSpeedQuestionPosition(null);
    setRecallFoundPositions(new Set());
    setRecallTimeLeft(60);

    // Initialize Speed Drill
    if (phase === 'speed') {
      setTimeout(() => generateSpeedQuestion(), 500);
    }
  };

  // Discovery Phase: Cascade animation
  useEffect(() => {
    if (currentPhase === 'discovery' && isPlaying) {
      const interval = setInterval(() => {
        setDiscoveryProgress((prev) => {
          if (prev >= notePositions.length) {
            clearInterval(interval);
            return prev;
          }
          return prev + 1;
        });
      }, 500); // 500ms delay between each note reveal
      return () => clearInterval(interval);
    }
  }, [currentPhase, isPlaying, notePositions.length]);

  // Guided Practice: Handle fretboard clicks
  const handleGuidedPracticeClick = (stringIndex: number, fretNumber: number) => {
    const targetNote = NOTES[(NOTES.indexOf(tuning[stringIndex]) + fretNumber) % 12];

    if (targetNote === currentNote) {
      // Correct!
      setFeedback({ type: 'correct', message: `Correct! ${currentNote} on string ${stringIndex + 1}` });
      setScore((prev) => prev + 1);
      setStreak((prev) => prev + 1);

      // Move to next string
      if (currentStringIndex < 5) {
        setTimeout(() => {
          setCurrentStringIndex((prev) => prev + 1);
          setFeedback(null);
        }, 1000);
      } else {
        // Completed all strings
        setTimeout(() => {
          setFeedback({ type: 'success', message: 'All strings completed! Moving to Speed Drill...' });
          setTimeout(() => {
            handlePhaseChange('speed');
            setFeedback(null);
          }, 2000);
        }, 1000);
      }
    } else {
      // Incorrect
      setFeedback({ type: 'incorrect', message: `Incorrect. That's ${targetNote}. Try again!` });
      setStreak(0);
    }
  };

  // Speed Drill: Generate random question
  const generateSpeedQuestion = () => {
    const randomString = Math.floor(Math.random() * 6);
    const randomFret = Math.floor(Math.random() * (difficulty === 'Easy' ? 13 : difficulty === 'Medium' ? 18 : 23));
    const noteAtPosition = NOTES[(NOTES.indexOf(tuning[randomString]) + randomFret) % 12];

    setSpeedQuestionPosition({ string: randomString, fret: randomFret });
    setSpeedIsTarget(noteAtPosition === currentNote);
  };

  const handleSpeedAnswer = (answer: boolean) => {
    if (answer === speedIsTarget) {
      setFeedback({ type: 'correct', message: 'Correct!' });
      setScore((prev) => prev + 1);
      setStreak((prev) => prev + 1);
    } else {
      setFeedback({ type: 'incorrect', message: 'Incorrect!' });
      setStreak(0);
    }

    setTimeout(() => {
      generateSpeedQuestion();
      setFeedback(null);
    }, 1000);
  };

  // Recall Phase: Handle fretboard clicks
  const handleRecallClick = (stringIndex: number, fretNumber: number) => {
    const positionKey = `${stringIndex}-${fretNumber}`;
    const targetNote = NOTES[(NOTES.indexOf(tuning[stringIndex]) + fretNumber) % 12];

    if (targetNote === currentNote) {
      if (!recallFoundPositions.has(positionKey)) {
        setRecallFoundPositions((prev) => new Set(prev).add(positionKey));
        setFeedback({ type: 'correct', message: `Found ${currentNote}!` });
        setScore((prev) => prev + 1);
        setTimeout(() => setFeedback(null), 500);
      }
    } else {
      setFeedback({ type: 'incorrect', message: `That's ${targetNote}, not ${currentNote}` });
      setTimeout(() => setFeedback(null), 800);
    }
  };

  // Recall Phase: Timer
  useEffect(() => {
    if (currentPhase === 'recall' && isPlaying && recallTimeLeft > 0) {
      const interval = setInterval(() => {
        setRecallTimeLeft((prev) => {
          if (prev <= 1) {
            clearInterval(interval);
            setIsPlaying(false);
            handleEndSession();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
      return () => clearInterval(interval);
    }
  }, [currentPhase, isPlaying, recallTimeLeft]);

  // Handle fretboard clicks based on current phase
  const handleFretboardClick = (stringIndex: number, fretNumber: number) => {
    if (!isPlaying) return;

    switch (currentPhase) {
      case 'guided':
        if (stringIndex === currentStringIndex) {
          handleGuidedPracticeClick(stringIndex, fretNumber);
        }
        break;
      case 'recall':
        handleRecallClick(stringIndex, fretNumber);
        break;
      default:
        break;
    }
  };

  const handleEndSession = () => {
    setIsPlaying(false);
    const stats: SessionStats = {
      methodId: 'note-a-day',
      startTime: Date.now() - elapsedTime * 1000,
      endTime: Date.now(),
      questionsAttempted: score + 10, // Placeholder
      correctAnswers: score,
      incorrectAnswers: 10,
      hintsUsed: showHints ? 5 : 0,
      currentStreak: streak,
      longestStreak: streak,
      averageResponseTime: 2500,
      weakNotes: [],
    };
    setSessionStats(stats);
    setShowSummary(true);
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white flex flex-col">
      {/* Header */}
      <div className="border-b border-gray-800 bg-[#111111]">
        <div className="px-6 py-4">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold">Note-a-Day Training</h1>
              <p className="text-sm text-gray-400">Master one note at a time</p>
            </div>
            <button
              onClick={() => router.push('/learn/fretboard')}
              className="px-4 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 transition-colors"
            >
              ΓåÉ Back
            </button>
          </div>
        </div>
      </div>

      {/* Control Bar */}
      <TrainingControlBar
        isPlaying={isPlaying}
        onPlayPause={handlePlayPause}
        onReset={handleReset}
        difficulty={difficulty}
        onDifficultyChange={handleDifficultyChange}
        elapsedTime={elapsedTime}
        score={score}
        streak={streak}
        showHints={showHints}
        onToggleHints={handleToggleHints}
      />

      {/* Main Content */}
      <div className="flex-1 flex">
        {/* Left Sidebar - Note Selector */}
        <div className="w-64 bg-[#1a1a1a] border-r border-gray-800 p-4">
          <h3 className="text-lg font-bold mb-4">12-Day Cycle</h3>
          <div className="space-y-2">
            {NOTE_A_DAY_CYCLE.map((note, index) => (
              <button
                key={note}
                onClick={() => handleNoteChange(note)}
                className={`w-full text-left p-3 rounded-lg transition-all ${
                  currentNote === note
                    ? 'bg-purple-600 text-white'
                    : 'bg-gray-800 text-gray-300 hover:bg-gray-700'
                }`}
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div
                      className="w-6 h-6 rounded-full"
                      style={{ backgroundColor: NOTE_COLORS[note] }}
                    />
                    <span className="font-semibold">Day {index + 1}: {note}</span>
                  </div>
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Center - Training Area with Fretboard */}
        <div className="flex-1 p-6 overflow-y-auto">
          <div className="space-y-6">
            {/* Phase Selector */}
            <div className="bg-[#1a1a1a] rounded-xl border border-gray-800 p-4">
              <div className="flex gap-2">
                {[
                  { id: 'discovery', label: 'Discovery', desc: '2 min' },
                  { id: 'guided', label: 'Guided Practice', desc: '3 min' },
                  { id: 'speed', label: 'Speed Drill', desc: '3 min' },
                  { id: 'recall', label: 'Full Recall', desc: '2 min' },
                ].map((phase) => (
                  <button
                    key={phase.id}
                    onClick={() => handlePhaseChange(phase.id as Phase)}
                    className={`flex-1 p-3 rounded-lg transition-all ${
                      currentPhase === phase.id
                        ? 'bg-gradient-to-r from-purple-600 to-blue-600 text-white'
                        : 'bg-gray-800 text-gray-300 hover:bg-gray-700'
                    }`}
                  >
                    <div className="font-semibold">{phase.label}</div>
                    <div className="text-xs opacity-75">{phase.desc}</div>
                  </button>
                ))}
              </div>
            </div>

            {/* Phase-Specific Instructions */}
            <div className="bg-[#1a1a1a] rounded-xl border border-gray-800 p-4">
              {currentPhase === 'discovery' && (
                <div>
                  <h3 className="font-bold text-lg mb-2">Phase 1: Discovery</h3>
                  <p className="text-gray-400">
                    Observe all positions of <span style={{ color: NOTE_COLORS[currentNote] }}>{currentNote}</span> on the fretboard.
                    Notice the diagonal pattern. Press Play to see them cascade in.
                  </p>
                </div>
              )}
              {currentPhase === 'guided' && (
                <div>
                  <h3 className="font-bold text-lg mb-2">Phase 2: Guided Practice</h3>
                  <p className="text-gray-400">
                    Find <span style={{ color: NOTE_COLORS[currentNote] }}>{currentNote}</span> on each string, one at a time.
                    Currently finding on: <span className="font-bold">String {currentStringIndex + 1}</span>
                  </p>
                </div>
              )}
              {currentPhase === 'speed' && (
                <div>
                  <h3 className="font-bold text-lg mb-2">Phase 3: Speed Drill</h3>
                  <p className="text-gray-400">
                    Is the highlighted position <span style={{ color: NOTE_COLORS[currentNote] }}>{currentNote}</span>?
                    Answer Yes or No as fast as you can!
                  </p>
                </div>
              )}
              {currentPhase === 'recall' && (
                <div>
                  <h3 className="font-bold text-lg mb-2">Phase 4: Full Recall</h3>
                  <p className="text-gray-400">
                    Tap every <span style={{ color: NOTE_COLORS[currentNote] }}>{currentNote}</span> you can find in {recallTimeLeft} seconds!
                    Found: {recallFoundPositions.size} / {notePositions.length}
                  </p>
                </div>
              )}
            </div>

            {/* Fretboard Section */}
            <div className="bg-[#1a1a1a] rounded-xl border border-gray-800 p-6">
              <h2 className="text-xl font-bold mb-4">
                Current Note: <span style={{ color: NOTE_COLORS[currentNote] }}>{currentNote}</span>
              </h2>
              <p className="text-gray-400 mb-6">
                Found in {notePositions.length} positions on the fretboard
              </p>

              {/* Fretboard Component */}
              <div className="bg-[#0a0a0a] rounded-lg p-4">
                <Fretboard
                  notePositions={notePositions}
                  tuning={tuning}
                  stringCount={6}
                  theme={theme}
                />
              </div>

              {/* Speed Drill Answer Buttons */}
              {currentPhase === 'speed' && isPlaying && (
                <div className="mt-6 flex gap-4 justify-center">
                  <button
                    onClick={() => handleSpeedAnswer(true)}
                    className="px-8 py-4 rounded-lg bg-green-600 hover:bg-green-700 text-white font-bold text-lg transition-all"
                  >
                    Γ£ô Yes ΓÇö That's {currentNote}
                  </button>
                  <button
                    onClick={() => handleSpeedAnswer(false)}
                    className="px-8 py-4 rounded-lg bg-red-600 hover:bg-red-700 text-white font-bold text-lg transition-all"
                  >
                    Γ£ù No ΓÇö That's not {currentNote}
                  </button>
                </div>
              )}
            </div>
            {/* Recall Phase Results */}
            {currentPhase === 'recall' && !isPlaying && recallTimeLeft === 0 && (
              <div className="bg-[#1a1a1a] rounded-xl border border-gray-800 p-6">
                <h3 className="text-lg font-bold mb-4">Recall Results</h3>
                <div className="text-center">
                  <div className="text-4xl font-bold mb-2">
                    {recallFoundPositions.size} / {notePositions.length}
                  </div>
                  <div className="text-gray-400 mb-4">
                    {Math.round((recallFoundPositions.size / notePositions.length) * 100)}% Accuracy
                  </div>
                  <button
                    onClick={() => handlePhaseChange('discovery')}
                    className="px-6 py-3 rounded-lg bg-purple-600 hover:bg-purple-700 text-white font-bold"
                  >
                    Try Again
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Feedback Overlay */}
      <FeedbackOverlay feedback={feedback} onComplete={() => setFeedback(null)} />

      {/* Session Summary Modal */}
      <SessionSummaryModal
        isOpen={showSummary}
        onClose={() => setShowSummary(false)}
        stats={sessionStats}
        onContinue={() => {
          setShowSummary(false);
          handleReset();
        }}
      />
    </div>
  );
}

/**
 * Octave Shapes Training Method
 * Learn geometric octave patterns across string pairs
 */

'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { OCTAVE_SHAPES, NOTE_COLORS, CHROMATIC_SCALE } from '@/lib/fretboard-learning/constants';
import { calculateOctavePosition, getNoteAtPosition } from '@/lib/fretboard-learning/utils';
import TrainingControlBar from '@/components/fretboard-learning/TrainingControlBar';
import FeedbackOverlay from '@/components/fretboard-learning/FeedbackOverlay';
import SessionSummaryModal from '@/components/fretboard-learning/SessionSummaryModal';
import { FeedbackEvent, SessionStats, OctaveShape } from '@/lib/fretboard-learning/types';
import { DifficultyLevel } from '@/lib/fretboard-learning/constants';
import Fretboard from '@/components/Fretboard';
import { NotePosition, NOTES, TUNINGS } from '@/lib/musicTheory';
import { themes } from '@/lib/themes';

type Phase = 'learn' | 'practice' | 'quiz';

export default function OctaveShapesPage() {
  const router = useRouter();

  // Training state
  const [currentShape, setCurrentShape] = useState<OctaveShape>(OCTAVE_SHAPES[0]);
  const [currentPhase, setCurrentPhase] = useState<Phase>('learn');
  const [isPlaying, setIsPlaying] = useState(false);
  const [difficulty, setDifficulty] = useState<DifficultyLevel>('Easy');
  const [showHints, setShowHints] = useState(true);

  // Phase-specific state
  const [currentNote, setCurrentNote] = useState<string>('C');
  const [currentFret, setCurrentFret] = useState<number>(3);
  const [practiceAttempts, setPracticeAttempts] = useState(0);
  const [quizQuestion, setQuizQuestion] = useState<{rootString: number; rootFret: number; targetString: number} | null>(null);
  const [quizTimeLeft, setQuizTimeLeft] = useState(30);

  // Session tracking
  const [elapsedTime, setElapsedTime] = useState(0);
  const [score, setScore] = useState(0);
  const [streak, setStreak] = useState(0);
  const [feedback, setFeedback] = useState<FeedbackEvent | null>(null);
  const [sessionStats, setSessionStats] = useState<SessionStats | null>(null);
  const [showSummary, setShowSummary] = useState(false);

  // Fretboard settings
  const tuning = TUNINGS[6]['Standard'];
  const theme = themes.dark;

  // Timer effect
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isPlaying) {
      interval = setInterval(() => {
        setElapsedTime((prev) => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isPlaying]);

  const handlePlayPause = () => {
    setIsPlaying(!isPlaying);
  };

  const handleReset = () => {
    setIsPlaying(false);
    setElapsedTime(0);
    setScore(0);
    setStreak(0);
    setCurrentPhase('learn');
  };

  const handleDifficultyChange = (newDifficulty: DifficultyLevel) => {
    setDifficulty(newDifficulty);
  };

  const handleToggleHints = () => {
    setShowHints(!showHints);
  };

  const handleShapeChange = (shape: OctaveShape) => {
    setCurrentShape(shape);
    setCurrentPhase('learn');
    setPracticeAttempts(0);
    setScore(0);
    setStreak(0);
  };

  const handlePhaseChange = (phase: Phase) => {
    setCurrentPhase(phase);
    setPracticeAttempts(0);
    setQuizQuestion(null);
    setQuizTimeLeft(30);

    if (phase === 'quiz') {
      setTimeout(() => generateQuizQuestion(), 500);
    }
  };

  // Calculate octave positions for visualization
  const octavePositions = useMemo(() => {
    const positions: NotePosition[] = [];
    const maxFrets = difficulty === 'Easy' ? 12 : difficulty === 'Medium' ? 17 : 22;

    // Root note positions on the first string of the shape
    const rootString = currentShape.strings[0] - 1; // Convert to 0-indexed
    const targetString = currentShape.strings[1] - 1;

    if (currentPhase === 'learn') {
      // In learn phase, show ALL octave pairs for this shape
      for (let fret = 0; fret <= maxFrets; fret++) {
        const noteAtRoot = NOTES[(NOTES.indexOf(tuning[rootString]) + fret) % 12];

        // Root position
        positions.push({
          stringIndex: rootString,
          fretNumber: fret,
          note: noteAtRoot,
          isRoot: true,
        });

        // Octave position
        const octaveFret = fret + currentShape.fretOffset;
        if (octaveFret <= maxFrets) {
          const noteAtOctave = NOTES[(NOTES.indexOf(tuning[targetString]) + octaveFret) % 12];
          positions.push({
            stringIndex: targetString,
            fretNumber: octaveFret,
            note: noteAtOctave,
            isRoot: false,
          });
        }
      }
    } else if (currentPhase === 'practice') {
      // In practice phase, show only the current note's octave pair
      const noteAtRoot = NOTES[(NOTES.indexOf(tuning[rootString]) + currentFret) % 12];

      positions.push({
        stringIndex: rootString,
        fretNumber: currentFret,
        note: noteAtRoot,
        isRoot: true,
      });

      const octaveFret = currentFret + currentShape.fretOffset;
      if (octaveFret <= maxFrets) {
        const noteAtOctave = NOTES[(NOTES.indexOf(tuning[targetString]) + octaveFret) % 12];
        positions.push({
          stringIndex: targetString,
          fretNumber: octaveFret,
          note: noteAtOctave,
          isRoot: false,
        });
      }
    } else if (currentPhase === 'quiz' && quizQuestion) {
      // In quiz phase, show only the root position
      const noteAtRoot = NOTES[(NOTES.indexOf(tuning[quizQuestion.rootString]) + quizQuestion.rootFret) % 12];

      positions.push({
        stringIndex: quizQuestion.rootString,
        fretNumber: quizQuestion.rootFret,
        note: noteAtRoot,
        isRoot: true,
      });
    }

    return positions;
  }, [currentShape, currentNote, currentPhase, difficulty, tuning, currentFret, quizQuestion]);

  // Practice Phase: Handle fretboard clicks
  const handlePracticeClick = (stringIndex: number, fretNumber: number) => {
    const targetString = currentShape.strings[1] - 1;
    const expectedFret = currentFret + currentShape.fretOffset;

    if (stringIndex === targetString && fretNumber === expectedFret) {
      setFeedback({ type: 'correct', message: `Correct! Octave found at fret ${expectedFret}` });
      setScore((prev) => prev + 1);
      setStreak((prev) => prev + 1);
      setPracticeAttempts((prev) => prev + 1);

      // Move to next position
      setTimeout(() => {
        setCurrentFret((prev) => (prev + 1) % 12);
        setFeedback(null);
      }, 1000);
    } else {
      setFeedback({ type: 'incorrect', message: `Incorrect. Try again!` });
      setStreak(0);
    }
  };

  // Quiz Phase: Generate random question
  const generateQuizQuestion = () => {
    const maxFrets = difficulty === 'Easy' ? 12 : difficulty === 'Medium' ? 17 : 22;
    const rootString = currentShape.strings[0] - 1;
    const targetString = currentShape.strings[1] - 1;
    const rootFret = Math.floor(Math.random() * (maxFrets - currentShape.fretOffset));

    setQuizQuestion({ rootString, rootFret, targetString });
  };

  // Quiz Phase: Handle answer
  const handleQuizAnswer = (stringIndex: number, fretNumber: number) => {
    if (!quizQuestion) return;

    const expectedFret = quizQuestion.rootFret + currentShape.fretOffset;

    if (stringIndex === quizQuestion.targetString && fretNumber === expectedFret) {
      setFeedback({ type: 'correct', message: 'Correct octave!' });
      setScore((prev) => prev + 1);
      setStreak((prev) => prev + 1);

      setTimeout(() => {
        generateQuizQuestion();
        setFeedback(null);
      }, 1000);
    } else {
      setFeedback({ type: 'incorrect', message: 'Incorrect. Try again!' });
      setStreak(0);
    }
  };

  // Quiz Timer
  useEffect(() => {
    if (currentPhase === 'quiz' && isPlaying && quizTimeLeft > 0) {
      const interval = setInterval(() => {
        setQuizTimeLeft((prev) => {
          if (prev <= 1) {
            clearInterval(interval);
            setIsPlaying(false);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
      return () => clearInterval(interval);
    }
  }, [currentPhase, isPlaying, quizTimeLeft]);

  // Handle fretboard clicks
  const handleFretboardClick = (stringIndex: number, fretNumber: number) => {
    if (!isPlaying) return;

    switch (currentPhase) {
      case 'practice':
        handlePracticeClick(stringIndex, fretNumber);
        break;
      case 'quiz':
        handleQuizAnswer(stringIndex, fretNumber);
        break;
      default:
        break;
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white flex flex-col">
      {/* Header */}
      <div className="border-b border-gray-800 bg-[#111111]">
        <div className="px-6 py-4">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold">Octave Shapes Training</h1>
              <p className="text-sm text-gray-400">Master geometric octave patterns</p>
            </div>
            <button
              onClick={() => router.push('/learn/fretboard')}
              className="px-4 py-2 rounded-lg bg-gray-800 hover:bg-gray-700 transition-colors"
            >
              ΓåÉ Back
            </button>
          </div>
        </div>
      </div>

      {/* Control Bar */}
      <TrainingControlBar
        isPlaying={isPlaying}
        onPlayPause={handlePlayPause}
        onReset={handleReset}
        difficulty={difficulty}
        onDifficultyChange={handleDifficultyChange}
        elapsedTime={elapsedTime}
        score={score}
        streak={streak}
        showHints={showHints}
        onToggleHints={handleToggleHints}
      />

      {/* Main Content */}
      <div className="flex-1 flex">
        {/* Left Sidebar - Shape Selector */}
        <div className="w-64 bg-[#1a1a1a] border-r border-gray-800 p-4">
          <h3 className="text-lg font-bold mb-4">Octave Shapes</h3>
          <div className="space-y-2">
            {OCTAVE_SHAPES.map((shape) => (
              <button
                key={shape.id}
                onClick={() => handleShapeChange(shape)}
                className={`w-full text-left p-3 rounded-lg transition-all ${
                  currentShape.id === shape.id
                    ? 'bg-purple-600 text-white'
                    : 'bg-gray-800 text-gray-300 hover:bg-gray-700'
                }`}
              >
                <div className="font-semibold text-sm mb-1">{shape.name}</div>
                <div className="text-xs text-gray-400">
                  Fret offset: +{shape.fretOffset}
                </div>
              </button>
            ))}
          </div>

          {/* Phase Selector */}
          <div className="mt-6">
            <h3 className="text-sm font-bold mb-2 text-gray-400">Training Phase</h3>
            <div className="space-y-1">
              {(['learn', 'practice', 'quiz'] as Phase[]).map((phase) => (
                <button
                  key={phase}
                  onClick={() => handlePhaseChange(phase)}
                  className={`w-full text-left px-3 py-2 rounded text-sm transition-all ${
                    currentPhase === phase
                      ? 'bg-blue-600 text-white'
                      : 'bg-gray-800/50 text-gray-400 hover:bg-gray-800'
                  }`}
                >
                  {phase.charAt(0).toUpperCase() + phase.slice(1)}
                </button>
              ))}
            </div>
          </div>

          {/* Note Selector for Practice */}
          {currentPhase === 'practice' && (
            <div className="mt-6">
              <h3 className="text-sm font-bold mb-2 text-gray-400">Starting Note</h3>
              <select
                value={currentNote}
                onChange={(e) => setCurrentNote(e.target.value)}
                className="w-full px-3 py-2 rounded bg-gray-800 text-white border border-gray-700"
              >
                {CHROMATIC_SCALE.map((note) => (
                  <option key={note} value={note}>{note}</option>
                ))}
              </select>
            </div>
          )}
        </div>

        {/* Center - Training Area */}
        <div className="flex-1 p-6 overflow-y-auto">
          <div className="space-y-6">
            {/* Phase Instructions */}
            <div className="bg-[#1a1a1a] rounded-xl border border-gray-800 p-4">
              {currentPhase === 'learn' && (
                <div>
                  <h3 className="font-bold text-lg mb-2">Shape Gallery (Learn)</h3>
                  <p className="text-gray-400">
                    Study the <span className="font-bold">{currentShape.name}</span> pattern.
                    Notice how the octave is always <span className="font-bold">+{currentShape.fretOffset} frets</span> higher
                    on string {currentShape.strings[1]} compared to string {currentShape.strings[0]}.
                    {currentShape.name.includes('crosses B') && (
                      <span className="text-yellow-400 ml-2">ΓÜá∩╕Å This shape crosses the B string!</span>
                    )}
                  </p>
                </div>
              )}
              {currentPhase === 'practice' && (
                <div>
                  <h3 className="font-bold text-lg mb-2">Shape Practice</h3>
                  <p className="text-gray-400">
                    Find the octave of <span style={{ color: NOTE_COLORS[currentNote] }}>{currentNote}</span> at fret {currentFret}
                    using the {currentShape.name} pattern. Click the correct octave position!
                    <br />
                    <span className="text-sm">Attempts: {practiceAttempts}</span>
                  </p>
                </div>
              )}
              {currentPhase === 'quiz' && (
                <div>
                  <h3 className="font-bold text-lg mb-2">Speed Navigation (Quiz)</h3>
                  <p className="text-gray-400">
                    Find the octave as fast as you can! Time left: <span className="font-bold">{quizTimeLeft}s</span>
                    {quizQuestion && (
                      <span className="block mt-2">
                        Root note is highlighted. Find its octave using {currentShape.name}!
                      </span>
                    )}
                  </p>
                </div>
              )}
            </div>

            {/* Shape Info Card */}
            <div className="bg-[#1a1a1a] rounded-xl border border-gray-800 p-6">
              <h2 className="text-xl font-bold mb-4">{currentShape.name}</h2>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <div className="text-sm text-gray-400 mb-1">String Pair</div>
                  <div className="text-lg font-bold">
                    String {currentShape.strings[0]} ΓåÆ String {currentShape.strings[1]}
                  </div>
                </div>
                <div>
                  <div className="text-sm text-gray-400 mb-1">Fret Offset</div>
                  <div className="text-lg font-bold">+{currentShape.fretOffset} frets</div>
                </div>
              </div>
            </div>

            {/* Interactive Fretboard */}
            <div className="bg-[#1a1a1a] rounded-xl border border-gray-800 p-6">
              <h3 className="text-lg font-bold mb-4">Fretboard</h3>
              <div className="bg-[#0a0a0a] rounded-lg p-4">
                <Fretboard
                  notePositions={octavePositions}
                  tuning={tuning}
                  stringCount={6}
                  theme={theme}
                />
              </div>
            </div>

            {/* Quiz Results */}
            {currentPhase === 'quiz' && !isPlaying && quizTimeLeft === 0 && (
              <div className="bg-[#1a1a1a] rounded-xl border border-gray-800 p-6">
                <h3 className="text-lg font-bold mb-4">Quiz Complete!</h3>
                <div className="text-center">
                  <div className="text-4xl font-bold mb-2">{score}</div>
                  <div className="text-gray-400 mb-4">Octaves Found</div>
                  <button
                    onClick={() => handlePhaseChange('learn')}
                    className="px-6 py-3 rounded-lg bg-purple-600 hover:bg-purple-700 text-white font-bold"
                  >
                    Try Again
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Feedback Overlay */}
      <FeedbackOverlay feedback={feedback} onComplete={() => setFeedback(null)} />

      {/* Session Summary Modal */}
      <SessionSummaryModal
        isOpen={showSummary}
        onClose={() => setShowSummary(false)}
        stats={sessionStats}
        onContinue={() => {
          setShowSummary(false);
          handleReset();
        }}
      />
    </div>
  );
}

