import { normalizeNoteToSharp } from '@/lib/triad-theory';

interface FretboardProps {
  stringCount: 6 | 7;
  tuning: string[];
  notePositions: NotePosition[];
  theme: ThemeConfig;
  isInverted?: boolean;
  fretDotColor?: string;
