  showGuideTones?: boolean;
  showChordGlow?: boolean;
  colorGuideEnabled?: boolean;
  glowOpacity?: number;
  showWhiteBorder?: boolean;
  selectedHarmonization?: 'original' | '3rds' | '5ths' | '6ths' | '7ths';
  showColorfulStrings?: boolean;
