  },
  {
    id: 'song-list',
    title: 'Song Progression List',
    description: 'View and manage your saved key/scale sequence. Use Prev/Next buttons or arrow keys to navigate. Reorder or remove items as needed.',
    targetSelector: '[data-guide="song-list"]',
    position: 'bottom',
    highlightPadding: 12,
  },
  {
    id: 'fretboard',
