    title: 'MIDI Pedal Setup',
    description: 'Connect a MIDI pedal board to switch between scales hands-free. Configure your pedal in the sidebar settings to navigate your song list during performance.',
    targetSelector: '[data-guide="midi-status"]',
    position: 'left',
    highlightPadding: 12,
  },
];

export default function OnboardingGuide({ theme, onClose, onNeverShowAgain, onStepChange }: OnboardingGuideProps) {
  const [currentStep, setCurrentStep] = useState(0);
  const [targetElement, setTargetElement] = useState<HTMLElement | null>(null);
  const [neverShow, setNeverShow] = useState(false);
  const [positionKey, setPositionKey] = useState(0); // Force position recalculation

  const currentGuideStep = GUIDE_STEPS[currentStep];

  // Notify parent when step changes
  useEffect(() => {
    if (onStepChange) {
      onStepChange(currentGuideStep.id);
    }
  }, [currentStep, currentGuideStep.id, onStepChange]);

  // Find and track the target element
  useEffect(() => {
    const findElement = () => {
      const element = document.querySelector(currentGuideStep.targetSelector) as HTMLElement;
      setTargetElement(element);

      if (!element) {
        console.warn(`Guide target not found: ${currentGuideStep.targetSelector}`);
      } else {
        // Force position recalculation when element is found
        setPositionKey(prev => prev + 1);
      }
    };

    findElement();
    // Retry after delays in case elements are still rendering
    // Extended delays for compatible-scales section which loads asynchronously
    const isCompatibleScales = currentGuideStep.id === 'compatible-scales';
    const timer1 = setTimeout(findElement, 100);
    const timer2 = setTimeout(findElement, 300);
    const timer3 = setTimeout(findElement, 500);
    const timer4 = isCompatibleScales ? setTimeout(findElement, 800) : null;
    const timer5 = isCompatibleScales ? setTimeout(findElement, 1200) : null;

    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
      clearTimeout(timer3);
      if (timer4) clearTimeout(timer4);
      if (timer5) clearTimeout(timer5);
    };
  }, [currentStep, currentGuideStep.targetSelector, currentGuideStep.id]);

  // Watch for layout changes and recalculate position
  useEffect(() => {
    if (!targetElement) return;

    const resizeObserver = new ResizeObserver(() => {
      setPositionKey(prev => prev + 1);
    });

    const mutationObserver = new MutationObserver(() => {
      setPositionKey(prev => prev + 1);
    });

    resizeObserver.observe(targetElement);
    mutationObserver.observe(targetElement, {
      childList: true,
      subtree: true,
      attributes: true,
    });

    // Also watch parent containers for layout changes
    let parent = targetElement.parentElement;
    while (parent) {
      resizeObserver.observe(parent);
      parent = parent.parentElement;
      // Only watch up to 3 levels to avoid performance issues
      if (!parent || parent === document.body) break;
    }

    // Add scroll listener to update position on scroll
    let scrollTimeout: NodeJS.Timeout;
    const handleScroll = () => {
      clearTimeout(scrollTimeout);
      scrollTimeout = setTimeout(() => {
        setPositionKey(prev => prev + 1);
      }, 50); // Throttle to 50ms
    };

    window.addEventListener('scroll', handleScroll, true); // Use capture phase

    return () => {
      resizeObserver.disconnect();
      mutationObserver.disconnect();
      window.removeEventListener('scroll', handleScroll, true);
      clearTimeout(scrollTimeout);
    };
  }, [targetElement]);

  // Scroll target element into view with delay for compatible-scales
  useEffect(() => {
    if (targetElement) {
      const isCompatibleScales = currentGuideStep.id === 'compatible-scales';
      const delay = isCompatibleScales ? 600 : 100;

      const timer = setTimeout(() => {
        targetElement.scrollIntoView({ behavior: 'smooth', block: 'center', inline: 'center' });
      }, delay);

      return () => clearTimeout(timer);
    }
  }, [targetElement, currentGuideStep.id]);

  const handleNext = () => {
    if (currentStep < GUIDE_STEPS.length - 1) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handlePrevious = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleClose = () => {
    if (neverShow) {
      onNeverShowAgain();
    } else {
      onClose();
    }
  };

  // Calculate position for the guide card
  const getCardPosition = () => {
    if (!targetElement) {
      return {
        top: '50%',
        left: '50%',
        transform: 'translate(-50%, -50%)',
      };
    }

    const rect = targetElement.getBoundingClientRect();
    const padding = currentGuideStep.highlightPadding || 12;
    const cardWidth = 360;
    const cardHeight = 280; // Increased approximate height
    const offset = 30; // Distance from target element
    const margin = 20; // Minimum margin from viewport edges

    let position: React.CSSProperties = {};
    let calculatedTop = 0;
    let calculatedLeft = 0;
    let useTransform = true;

    const viewportWidth = window.innerWidth;
    const viewportHeight = window.innerHeight;

    switch (currentGuideStep.position) {
      case 'right':
        calculatedTop = rect.top + rect.height / 2;
        calculatedLeft = rect.right + offset;
        position.transform = 'translateY(-50%)';
        break;
      case 'left':
        calculatedTop = rect.top + rect.height / 2;
        calculatedLeft = rect.left - cardWidth - offset;
        position.transform = 'translateY(-50%)';
        break;
      case 'top':
        calculatedTop = rect.top - cardHeight - offset;
        calculatedLeft = rect.left + rect.width / 2;
        position.transform = 'translateX(-50%)';
        break;
      case 'bottom':
        calculatedTop = rect.bottom + offset;
        calculatedLeft = rect.left + rect.width / 2;
        position.transform = 'translateX(-50%)';
        break;
    }

    // Ensure the card stays within viewport bounds with proper margins
    // Handle horizontal positioning
    if (currentGuideStep.position === 'top' || currentGuideStep.position === 'bottom') {
      // For top/bottom positions, center horizontally but keep within bounds
      const halfCardWidth = cardWidth / 2;
      if (calculatedLeft - halfCardWidth < margin) {
        calculatedLeft = margin + halfCardWidth;
      } else if (calculatedLeft + halfCardWidth > viewportWidth - margin) {
        calculatedLeft = viewportWidth - margin - halfCardWidth;
      }
    } else {
      // For left/right positions
      if (calculatedLeft + cardWidth > viewportWidth - margin) {
        calculatedLeft = viewportWidth - cardWidth - margin;
        useTransform = false;
      } else if (calculatedLeft < margin) {
        calculatedLeft = margin;
        useTransform = false;
      }
    }

    // Handle vertical positioning
    if (currentGuideStep.position === 'left' || currentGuideStep.position === 'right') {
      // For left/right positions, center vertically but keep within bounds
      const halfCardHeight = cardHeight / 2;
      if (calculatedTop - halfCardHeight < margin) {
        calculatedTop = margin + halfCardHeight;
      } else if (calculatedTop + halfCardHeight > viewportHeight - margin) {
        calculatedTop = viewportHeight - margin - halfCardHeight;
      }
    } else {
      // For top/bottom positions
      if (calculatedTop + cardHeight > viewportHeight - margin) {
        calculatedTop = viewportHeight - cardHeight - margin;
        useTransform = false;
      } else if (calculatedTop < margin) {
        calculatedTop = margin;
        useTransform = false;
      }
    }

    position.top = `${calculatedTop}px`;
    position.left = `${calculatedLeft}px`;

    if (!useTransform) {
      position.transform = 'none';
    }

    return position;
  };

  // Memoize card position and recalculate when positionKey changes
  const cardPosition = useMemo(() => {
    return getCardPosition();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [targetElement, currentGuideStep.position, positionKey]);

  return (
    <>
      {/* Invisible overlay for click detection only */}
      <div
        className="fixed inset-0 transition-opacity pointer-events-auto"
        style={{
          zIndex: 9998,
          backgroundColor: 'transparent',
        }}
        onClick={handleClose}
      />

      {/* Highlight box around target element */}
      {targetElement && (() => {
        const rect = targetElement.getBoundingClientRect();
        const padding = currentGuideStep.highlightPadding || 12;
        return (
          <div
            key={positionKey} // Force re-render when position changes
            className="fixed pointer-events-none transition-all duration-300"
            style={{
              zIndex: 9999,
              top: `${rect.top - padding}px`,
              left: `${rect.left - padding}px`,
              width: `${rect.width + padding * 2}px`,
              height: `${rect.height + padding * 2}px`,
              border: '3px solid #3b82f6',
              borderRadius: '12px',
              boxShadow: '0 0 0 4px rgba(59, 130, 246, 0.3), 0 0 30px rgba(59, 130, 246, 0.5)',
              animation: 'pulse 2s ease-in-out infinite',
            }}
          />
        );
      })()}

      {/* Pointer line from card to target */}
      {targetElement && (() => {
        const rect = targetElement.getBoundingClientRect();
        const targetCenterX = rect.left + rect.width / 2;
        const targetCenterY = rect.top + rect.height / 2;

        // Calculate card center based on position
        let cardX = parseFloat(cardPosition.left as string || '0');
        let cardY = parseFloat(cardPosition.top as string || '0');

        // Force recalculation by using positionKey
        const _forceUpdate = positionKey;

        // Adjust for transform
        if (cardPosition.transform?.includes('translateX(-50%)')) {
          // Card is centered horizontally, so use the left value as center
        } else if (cardPosition.transform?.includes('translateY(-50%)')) {
          // Card is centered vertically, so use the top value as center
        }

        // Determine line start point based on card position relative to target
        let lineStartX = cardX;
        let lineStartY = cardY;

        switch (currentGuideStep.position) {
          case 'right':
            lineStartX = cardX; // Left edge of card
            lineStartY = cardY; // Center of card (already adjusted by translateY)
            break;
          case 'left':
            lineStartX = cardX + 360; // Right edge of card
            lineStartY = cardY;
            break;
          case 'top':
            lineStartX = cardX; // Center of card (already adjusted by translateX)
            lineStartY = cardY + 250; // Bottom edge of card
            break;
          case 'bottom':
            lineStartX = cardX; // Center of card
            lineStartY = cardY; // Top edge of card
            break;
        }

        return (
          <svg
            className="fixed pointer-events-none"
            style={{
              zIndex: 10000,
              top: 0,
              left: 0,
              width: '100%',
              height: '100%',
            }}
          >
            <defs>
              <marker
                id="arrowhead"
                markerWidth="10"
                markerHeight="10"
                refX="9"
                refY="3"
                orient="auto"
              >
                <polygon points="0 0, 10 3, 0 6" fill="#3b82f6" />
              </marker>
            </defs>
            <line
              x1={lineStartX}
              y1={lineStartY}
              x2={targetCenterX}
              y2={targetCenterY}
              stroke="#3b82f6"
              strokeWidth="3"
              markerEnd="url(#arrowhead)"
              strokeDasharray="8,4"
              style={{
                filter: 'drop-shadow(0 0 8px rgba(59, 130, 246, 0.6))',
              }}
            />
          </svg>
        );
      })()}

      {/* Guide card */}
      <div
        className="fixed rounded-xl shadow-2xl transition-all duration-300"
        style={{
          zIndex: 10001,
          ...cardPosition,
          width: '360px',
          maxWidth: 'calc(100vw - 40px)',
          background: theme.bgSecondary,
          border: `2px solid #3b82f6`,
          boxShadow: '0 20px 60px rgba(0, 0, 0, 0.8), 0 0 0 4px rgba(59, 130, 246, 0.3)',
        }}
      >
        {/* Header */}
        <div
          className="flex items-center justify-between p-4 border-b"
          style={{ borderColor: theme.border }}
        >
          <div className="flex items-center gap-2">
            <div
              className="w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold"
              style={{
                background: 'linear-gradient(135deg, #3b82f6, #8b5cf6)',
                color: '#ffffff',
              }}
            >
              {currentStep + 1}
            </div>
            <h3 className="text-lg font-bold" style={{ color: theme.textPrimary }}>
              {currentGuideStep.title}
            </h3>
          </div>
          <button
            onClick={handleClose}
            className="p-1 rounded-lg hover:bg-opacity-80 transition-all"
            style={{
              background: theme.bgTertiary,
              color: theme.textSecondary,
            }}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="p-4">
          {!targetElement && (
            <div
              className="mb-3 p-2 rounded text-xs"
              style={{
                background: 'rgba(239, 68, 68, 0.1)',
                color: '#ef4444',
                border: '1px solid rgba(239, 68, 68, 0.3)'
              }}
            >
              ΓÜá∩╕Å Target element not visible. You may need to scroll or expand sections to see this feature.
            </div>
          )}
          <p className="text-sm leading-relaxed mb-4" style={{ color: theme.textSecondary }}>
            {currentGuideStep.description}
          </p>

          {/* Progress indicator */}
          <div className="flex gap-1 mb-4">
            {GUIDE_STEPS.map((_, index) => (
              <div
                key={index}
                className="h-1 flex-1 rounded-full transition-all"
                style={{
                  background: index === currentStep ? '#3b82f6' : theme.bgTertiary,
                }}
              />
            ))}
          </div>

          {/* Navigation buttons */}
          <div className="flex items-center justify-between gap-3">
            <button
              onClick={handlePrevious}
              disabled={currentStep === 0}
              className="flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm transition-all disabled:opacity-40 disabled:cursor-not-allowed"
              style={{
                background: theme.bgTertiary,
                color: theme.textPrimary,
                border: `1px solid ${theme.border}`,
              }}
            >
              <ChevronLeft className="w-4 h-4" />
              Previous
            </button>

            <div className="text-xs font-medium" style={{ color: theme.textSecondary }}>
              {currentStep + 1} of {GUIDE_STEPS.length}
            </div>

            <button
              onClick={currentStep === GUIDE_STEPS.length - 1 ? handleClose : handleNext}
              className="flex items-center gap-2 px-4 py-2 rounded-lg font-medium text-sm transition-all"
              style={{
                background: 'linear-gradient(135deg, #3b82f6, #8b5cf6)',
                color: '#ffffff',
              }}
            >
              {currentStep === GUIDE_STEPS.length - 1 ? 'Finish' : 'Next'}
              {currentStep < GUIDE_STEPS.length - 1 && <ChevronRight className="w-4 h-4" />}
            </button>
          </div>

          {/* Never show again checkbox */}
          <div className="mt-4 pt-4 border-t" style={{ borderColor: theme.border }}>
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={neverShow}
                onChange={(e) => setNeverShow(e.target.checked)}
                className="w-4 h-4 rounded"
                style={{ accentColor: '#3b82f6' }}
              />
              <span className="text-xs" style={{ color: theme.textSecondary }}>
                Don't show this guide again
              </span>
            </label>
          </div>
        </div>
      </div>

      {/* Pulse animation */}
      <style jsx>{`
        @keyframes pulse {
          0%, 100% {
            box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.3), 0 0 30px rgba(59, 130, 246, 0.5);
          }
          50% {
            box-shadow: 0 0 0 8px rgba(59, 130, 246, 0.2), 0 0 40px rgba(59, 130, 246, 0.7);
          }
        }
      `}</style>
    </>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { ThemeConfig } from '@/lib/themes';
import { TriadInversion, CAGEDShape } from '@/lib/triad-theory';
import { ChevronLeft, ChevronRight, Eye, EyeOff, Info } from 'lucide-react';

interface TriadCAGEDOptionsProps {
  theme: ThemeConfig;
  selectedInversion: TriadInversion;
  onInversionChange: (inversion: TriadInversion) => void;
  selectedCAGEDShapes: CAGEDShape[];
  onCAGEDShapesChange: (shapes: CAGEDShape[]) => void;
  positionCountsByInversion?: Record<TriadInversion, number>;
  positionCountsByShape?: Record<CAGEDShape, number>;
  showCAGEDGuide?: boolean;
  onCAGEDGuideChange?: (enabled: boolean) => void;
}

export default function TriadCAGEDOptions({
  theme,
  selectedInversion,
  onInversionChange,
  selectedCAGEDShapes,
  onCAGEDShapesChange,
  positionCountsByInversion = { root: 0, first: 0, second: 0 },
  positionCountsByShape = { C: 0, A: 0, G: 0, E: 0, D: 0 },
  showCAGEDGuide = false,
  onCAGEDGuideChange,
}: TriadCAGEDOptionsProps) {
  const [showInfoModal, setShowInfoModal] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const cagedColors: Record<CAGEDShape, string> = {
    C: '#ef4444',
    A: '#f97316',
    G: '#eab308',
    E: '#22c55e',
    D: '#3b82f6',
  };

  const handleShapeToggle = (shape: CAGEDShape) => {
    if (selectedCAGEDShapes.includes(shape)) {
      onCAGEDShapesChange(selectedCAGEDShapes.filter((s) => s !== shape));
    } else {
      onCAGEDShapesChange([...selectedCAGEDShapes, shape]);
    }
  };

  const handlePreviousInversion = () => {
    const inversions: TriadInversion[] = ['root', 'first', 'second'];
    const currentIndex = inversions.indexOf(selectedInversion);
    const prevIndex = (currentIndex - 1 + inversions.length) % inversions.length;
    onInversionChange(inversions[prevIndex]);
  };

  const handleNextInversion = () => {
    const inversions: TriadInversion[] = ['root', 'first', 'second'];
    const currentIndex = inversions.indexOf(selectedInversion);
    const nextIndex = (currentIndex + 1) % inversions.length;
    onInversionChange(inversions[nextIndex]);
  };

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Only handle if the container is focused or a child is focused
      if (!containerRef.current?.contains(document.activeElement)) {
        return;
      }

      if (e.key === 'ArrowLeft') {
        e.preventDefault();
        handlePreviousInversion();
      } else if (e.key === 'ArrowRight') {
        e.preventDefault();
        handleNextInversion();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [selectedInversion, onInversionChange]);

  return (
    <>
      <div
        ref={containerRef}
        tabIndex={0}
        className="rounded-lg p-4 mb-4 focus:outline-none focus:ring-2 transition-all"
        style={{
          background: theme.bgSecondary,
          border: `1px solid ${theme.border}`,
          outlineColor: theme.accentPrimary,
        }}
      >
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center gap-2">
            <svg className="w-4 h-4" style={{ color: theme.textSecondary }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19V6l12-3v13M9 19c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zm12-3c0 1.105-1.343 2-3 2s-3-.895-3-2 1.343-2 3-2 3 .895 3 2zM9 10l12-3" />
            </svg>
            <h3 className="text-sm font-semibold" style={{ color: theme.textPrimary }}>
              Triad & CAGED Options
            </h3>

            {/* CAGED Guide Toggle */}
            {onCAGEDGuideChange && (
              <div className="ml-2 flex items-center gap-2 px-3 py-1 rounded" style={{
                background: theme.bgTertiary,
                border: `1px solid ${theme.border}`,
              }}>
                <span className="text-xs font-semibold" style={{ color: theme.textPrimary }}>
                  CAGED Guide
                </span>
                <button
                  onClick={() => onCAGEDGuideChange(!showCAGEDGuide)}
                  className="relative inline-flex h-6 w-11 items-center rounded-full transition-all shadow-sm"
                  style={{
                    background: showCAGEDGuide ? theme.accentPrimary : '#4b5563',
                    border: `2px solid ${showCAGEDGuide ? theme.accentPrimary : '#6b7280'}`,
                  }}
                  title={showCAGEDGuide ? 'Hide CAGED Guide' : 'Show CAGED Guide'}
                >
                  <span
                    className="inline-block h-5 w-5 transform rounded-full transition-transform shadow-md"
                    style={{
                      background: '#ffffff',
                      transform: showCAGEDGuide ? 'translateX(20px)' : 'translateX(2px)',
                    }}
                  />
                </button>
              </div>
            )}
          </div>

          {/* Info Icon */}
          <button
            onClick={() => setShowInfoModal(true)}
            className="p-1.5 rounded transition-all hover:opacity-80"
            style={{
              background: 'transparent',
              color: theme.textSecondary,
              border: `1px solid ${theme.border}`,
            }}
            title="Show triad color legend"
          >
            <Info className="w-4 h-4" />
          </button>
        </div>

      <div className="flex items-center gap-4 mt-3">
        {/* Triad Positions Section */}
        <div className="flex items-center gap-2">
          <span className="text-xs font-semibold whitespace-nowrap" style={{ color: theme.textSecondary }}>
            Triad Positions:
          </span>

          {/* Previous Button */}
          <button
            onClick={handlePreviousInversion}
            className="p-1.5 rounded transition-all hover:opacity-80"
            style={{
              background: theme.buttonPrimary,
              color: '#ffffff',
            }}
            title="Previous position"
          >
            <ChevronLeft className="w-4 h-4" />
          </button>

          {/* Radio Buttons */}
          <div className="flex gap-1.5">
            {(['root', 'first', 'second'] as const).map((inversion) => {
              const isSelected = selectedInversion === inversion;
              return (
                <button
