import React, { useState, useEffect, useCallback, useRef } from 'react';
import AudioInputSelector from './AudioInputSelector';
import { AudioDeviceManager, AudioDevice, getAudioDeviceManager } from '@/lib/audio/audioDeviceManager';
import { KeyDetectionEngine, KeyDetectionResult } from '@/lib/audio/keyDetectionEngine';
import { getCompatibleScales, ScaleCompatibilityRating } from '@/lib/musicalCompatibility';
import { Theme } from '@/lib/themes';

interface KeyDetectionPanelProps {
  theme: Theme;
  autoRecommendation?: boolean;
  autoSwitchFretboard?: boolean;
  onScaleChange?: (rootNote: string, scaleName: string, chordTones: string[], guideTones: string[]) => void;
  onDetectedKeyChange?: (key: string | null, confidence: number, isListening: boolean) => void;
  onCompatibleScalesChange?: (scales: ScaleCompatibilityRating[]) => void;
  onSelectedScaleChange?: (scale: ScaleCompatibilityRating | null) => void;
  onDetectionStateChange?: (isDetecting: boolean) => void;
  onStartDetectionReady?: (startFn: () => Promise<void>) => void;
  onStopDetectionReady?: (stopFn: () => Promise<void>) => void;
}

export default function KeyDetectionPanel({
  theme,
  autoRecommendation: autoRecommendationProp = false,
  autoSwitchFretboard: autoSwitchFretboardProp = false,
  onScaleChange,
  onDetectedKeyChange,
  onCompatibleScalesChange,
  onSelectedScaleChange,
  onDetectionStateChange,
  onStartDetectionReady,
  onStopDetectionReady,
}: KeyDetectionPanelProps) {
  // Audio device state
  const [devices, setDevices] = useState<AudioDevice[]>([]);
  const [selectedDeviceId, setSelectedDeviceId] = useState<string | null>(null);
  const [isDetecting, setIsDetecting] = useState(false);
  const [bufferDuration, setBufferDuration] = useState<number>(15); // Default 15 seconds

  // Key detection state
  const [detectedKey, setDetectedKey] = useState<string | null>(null);
  const [confidence, setConfidence] = useState<number>(0);
  const [isListening, setIsListening] = useState<boolean>(false);

  // Use props for auto recommendation state (controlled component)
  const autoRecommendation = autoRecommendationProp;
  const autoSwitchFretboard = autoSwitchFretboardProp;

  // Scale compatibility state
  const [compatibleScales, setCompatibleScales] = useState<ScaleCompatibilityRating[]>([]);
  const [selectedScale, setSelectedScale] = useState<ScaleCompatibilityRating | null>(null);

  // Store callbacks in refs to avoid dependency issues
  const onCompatibleScalesChangeRef = useRef(onCompatibleScalesChange);
  const onSelectedScaleChangeRef = useRef(onSelectedScaleChange);
  const onScaleChangeRef = useRef(onScaleChange);

  // Update refs when callbacks change
  useEffect(() => {
    onCompatibleScalesChangeRef.current = onCompatibleScalesChange;
    onSelectedScaleChangeRef.current = onSelectedScaleChange;
    onScaleChangeRef.current = onScaleChange;
  }, [onCompatibleScalesChange, onSelectedScaleChange, onScaleChange]);

  // Managers
  const audioDeviceManagerRef = useRef<AudioDeviceManager | null>(null);
  const keyDetectionEngineRef = useRef<KeyDetectionEngine | null>(null);

  /**
   * Initialize audio device manager
   */
  useEffect(() => {
    audioDeviceManagerRef.current = getAudioDeviceManager({
      sampleRate: 44100,
      channelCount: 1,
      echoCancellation: false,
      noiseSuppression: false,
      autoGainControl: false,
    });

    // Don't load devices on mount - wait for user interaction
    // This prevents automatic permission requests

    // Cleanup on unmount
    return () => {
      if (keyDetectionEngineRef.current) {
        keyDetectionEngineRef.current.cleanup();
      }
      if (audioDeviceManagerRef.current) {
        audioDeviceManagerRef.current.cleanup();
      }
    };
  }, []);

  /**
   * Load available audio devices
   */
  const loadDevices = async () => {
    try {
      if (!audioDeviceManagerRef.current) return;

      const availableDevices = await audioDeviceManagerRef.current.getAudioInputDevices();
      setDevices(availableDevices);

      // Auto-select first device if none selected
      if (availableDevices.length > 0 && !selectedDeviceId) {
        setSelectedDeviceId(availableDevices[0].deviceId);
      }
    } catch (error) {
      console.error('Failed to load audio devices:', error);
      alert('Failed to access audio devices. Please grant microphone permission.');
    }
  };

  /**
   * Handle key detection callback
   */
  const handleKeyDetected = useCallback(async (result: KeyDetectionResult) => {
    console.log('Key detected:', result);

    // Update the display
    setDetectedKey(result.key);
    setConfidence(result.confidence);
    setIsListening(false); // Analysis complete

    // Notify parent of key change
    if (onDetectedKeyChange) {
      onDetectedKeyChange(result.key, result.confidence, false);
    }

    // If auto recommendation is enabled, fetch compatible scales
    if (autoRecommendation) {
      const scales = getCompatibleScales(result.key, 12, 4);
      console.log('Compatible scales fetched:', scales.length);
      setCompatibleScales(scales);

      // Notify parent of compatible scales change
      if (onCompatibleScalesChangeRef.current) {
        onCompatibleScalesChangeRef.current(scales);
      }

      // If auto switch fretboard is enabled, select the top scale
      if (autoSwitchFretboard && scales.length > 0) {
        const topScale = scales[0];
        setSelectedScale(topScale);

        // Notify parent of selected scale change
        if (onSelectedScaleChangeRef.current) {
          onSelectedScaleChangeRef.current(topScale);
        }

        // Notify parent component to update fretboard
        if (onScaleChangeRef.current) {
          onScaleChangeRef.current(
            topScale.rootNote,
            topScale.scaleName,
            topScale.chordTones,
            topScale.guideTones
          );
        }
      }
    } else {
      // Clear compatible scales if auto recommendation is off
      setCompatibleScales([]);
      setSelectedScale(null);

      if (onCompatibleScalesChangeRef.current) {
        onCompatibleScalesChangeRef.current([]);
      }
      if (onSelectedScaleChangeRef.current) {
        onSelectedScaleChangeRef.current(null);
      }
    }

    // Set listening state back to true after a brief delay to show "analyzing" again
    setTimeout(() => {
      setIsListening(true);
      if (onDetectedKeyChange) {
        onDetectedKeyChange(result.key, result.confidence, true);
      }
    }, 500);
  }, [autoRecommendation, autoSwitchFretboard, onDetectedKeyChange]);

  /**
   * Start key detection
   */
  const startDetection = useCallback(async () => {
    try {
      if (!audioDeviceManagerRef.current) {
        alert('Audio device manager not initialized.');
        return;
      }

      // Load devices if not already loaded (this will request permission)
      if (devices.length === 0) {
        await loadDevices();
      }

      if (!selectedDeviceId) {
        alert('Please select an audio input device first.');
        return;
      }

      // Create key detection engine if not exists
      if (!keyDetectionEngineRef.current) {
        keyDetectionEngineRef.current = new KeyDetectionEngine(
          audioDeviceManagerRef.current,
          {
            onKeyDetected: handleKeyDetected,
            onError: (error) => {
              console.error('Key detection error:', error);
              alert('Key detection error: ' + error.message);
              setIsDetecting(false);
            },
            onInitialized: () => {
              console.log('Key detection engine initialized');
            },
            debounceMs: 500,
            minConfidence: 0.3,
            bufferDuration: bufferDuration,
          }
        );
      } else {
        // Update buffer duration if engine already exists
        keyDetectionEngineRef.current.setBufferDuration(bufferDuration);
      }

      // Start detection
      await keyDetectionEngineRef.current.start(selectedDeviceId);
      setIsDetecting(true);
      setIsListening(true); // Start listening for audio

      // Notify parent of detection state change
      if (onDetectionStateChange) {
        onDetectionStateChange(true);
      }

      // Notify parent immediately that we're listening (show "Analyzing..." in UI)
      if (onDetectedKeyChange) {
        onDetectedKeyChange(null, 0, true);
      }
    } catch (error) {
      console.error('Failed to start detection:', error);
      alert('Failed to start key detection: ' + (error as Error).message);
    }
  }, [selectedDeviceId, bufferDuration, handleKeyDetected, onDetectionStateChange, onDetectedKeyChange, devices.length]);

  /**
   * Stop key detection
   */
  const stopDetection = useCallback(async () => {
    try {
      if (keyDetectionEngineRef.current) {
        await keyDetectionEngineRef.current.stop();
      }
      setIsDetecting(false);
      setIsListening(false);

      // Notify parent of detection state change
      if (onDetectionStateChange) {
        onDetectionStateChange(false);
      }

      // Notify parent that we've stopped listening
      if (onDetectedKeyChange) {
        onDetectedKeyChange(detectedKey, confidence, false);
      }
    } catch (error) {
      console.error('Failed to stop detection:', error);
    }
  }, [detectedKey, confidence, onDetectionStateChange, onDetectedKeyChange]);

  // Expose start/stop functions to parent
  useEffect(() => {
    if (onStartDetectionReady) {
      onStartDetectionReady(startDetection);
    }
    if (onStopDetectionReady) {
      onStopDetectionReady(stopDetection);
    }
  }, [onStartDetectionReady, onStopDetectionReady, startDetection, stopDetection]);

  /**
   * Handle scale selection
   */
  const handleScaleSelect = useCallback((scale: ScaleCompatibilityRating) => {
    setSelectedScale(scale);

    // Notify parent of selected scale change
    if (onSelectedScaleChangeRef.current) {
      onSelectedScaleChangeRef.current(scale);
    }

    // Notify parent component
    if (onScaleChangeRef.current) {
      onScaleChangeRef.current(
        scale.rootNote,
        scale.scaleName,
        scale.chordTones,
        scale.guideTones
      );
    }
  }, []);

  /**
   * Effect: Fetch compatible scales when autoRecommendation changes or key is detected
   */
  useEffect(() => {
    if (autoRecommendation && detectedKey) {
      // Fetch compatible scales when enabled
      const scales = getCompatibleScales(detectedKey, 12, 4);
      setCompatibleScales(scales);

      if (onCompatibleScalesChangeRef.current) {
        onCompatibleScalesChangeRef.current(scales);
      }

      // If auto switch is enabled, select the top scale
      if (autoSwitchFretboard && scales.length > 0) {
        const topScale = scales[0];
        setSelectedScale(topScale);

        if (onSelectedScaleChangeRef.current) {
          onSelectedScaleChangeRef.current(topScale);
        }

        if (onScaleChangeRef.current) {
          onScaleChangeRef.current(
            topScale.rootNote,
            topScale.scaleName,
            topScale.chordTones,
            topScale.guideTones
          );
        }
      }
    } else if (!autoRecommendation) {
      // Only clear scales when auto recommendation is explicitly disabled
      // Don't clear when there's just no detected key yet
      setCompatibleScales([]);
      setSelectedScale(null);

      if (onCompatibleScalesChangeRef.current) {
        onCompatibleScalesChangeRef.current([]);
      }
      if (onSelectedScaleChangeRef.current) {
        onSelectedScaleChangeRef.current(null);
      }
    }
  }, [autoRecommendation, autoSwitchFretboard, detectedKey]);

  return (
    <div>
      <AudioInputSelector
        devices={devices}
        selectedDeviceId={selectedDeviceId}
        isDetecting={isDetecting}
        bufferDuration={bufferDuration}
        onDeviceSelect={setSelectedDeviceId}
        onStartDetection={startDetection}
        onStopDetection={stopDetection}
        onRefreshDevices={loadDevices}
        onBufferDurationChange={setBufferDuration}
        theme={theme}
      />
    </div>
  );
}

// Export internal state getters for parent components
export function useKeyDetectionState() {
  return {
    detectedKey: null,
    confidence: 0,
    isListening: false,
    autoRecommendation: false,
    autoSwitchFretboard: false,
    compatibleScales: [],
    selectedScale: null,
  };
}

'use client';

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ChevronDown, Music2, Mic } from 'lucide-react';
import { GuitarPitchDetector } from '@/lib/audio/guitarPitchDetector';
import { DetectedNote } from '@/types/audio';
import { ThemeConfig } from '@/lib/themes';
import GuitarTuner from './GuitarTuner';
import { getAudioDeviceManager } from '@/lib/audio/audioDeviceManager';

interface NoteDetectorSidebarProps {
  theme: ThemeConfig;
  enabled?: boolean;
  onDetectedNoteChange?: (note: string | null, frequency: number | null) => void;
  liveNotesGlowEnabled?: boolean;
  onLiveNotesGlowChange?: (enabled: boolean) => void;
  liveNotesGlowDuration?: number;
  onLiveNotesGlowDurationChange?: (duration: number) => void;
  circleOf5thsGlowDuration?: number;
  onCircleOf5thsGlowDurationChange?: (duration: number) => void;
}

export function NoteDetectorSidebar({
  theme,
  enabled = false,
  onDetectedNoteChange,
  liveNotesGlowEnabled = false,
  onLiveNotesGlowChange,
  liveNotesGlowDuration = 1000,
  onLiveNotesGlowDurationChange,
  circleOf5thsGlowDuration = 1000,
  onCircleOf5thsGlowDurationChange,
}: NoteDetectorSidebarProps) {
  const [isExpanded, setIsExpanded] = useState(false);
  const [isTunerExpanded, setIsTunerExpanded] = useState(false);
  const [devices, setDevices] = useState<MediaDeviceInfo[]>([]);
  const [selectedDeviceId, setSelectedDeviceId] = useState<string>('');
  const [hasPermission, setHasPermission] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [currentNote, setCurrentNote] = useState<DetectedNote>({
    note: null,
    frequency: null,
    confidence: 0,
  });
  const [error, setError] = useState<string | null>(null);
  const [isDeviceDropdownOpen, setIsDeviceDropdownOpen] = useState(false);

  const pitchDetectorRef = useRef<GuitarPitchDetector | null>(null);
  const onDetectedNoteChangeRef = useRef(onDetectedNoteChange);

  // Keep the ref updated with the latest callback
  useEffect(() => {
    onDetectedNoteChangeRef.current = onDetectedNoteChange;
  }, [onDetectedNoteChange]);

  // Initialize guitar pitch detector
  useEffect(() => {
    pitchDetectorRef.current = new GuitarPitchDetector();
    return () => {
      if (pitchDetectorRef.current) {
        pitchDetectorRef.current.stop();
      }
    };
  }, []);

  // Request permission and enumerate devices
  const requestPermissionAndEnumerateDevices = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      stream.getTracks().forEach(track => track.stop());
      setHasPermission(true);
      await enumerateDevices();
    } catch (err) {
      console.error('Error requesting microphone permission:', err);
      setError('Microphone permission denied');
      setHasPermission(false);
    }
  };

  // Enumerate devices
  const enumerateDevices = async () => {
    try {
      const allDevices = await navigator.mediaDevices.enumerateDevices();
      const audioInputs = allDevices.filter(device => device.kind === 'audioinput');
      setDevices(audioInputs);
      if (audioInputs.length > 0 && !selectedDeviceId) {
        setSelectedDeviceId(audioInputs[0].deviceId);
      }
    } catch (err) {
      console.error('Error enumerating devices:', err);
      setError('Failed to enumerate audio devices');
    }
  };

  // Check permission on mount
  useEffect(() => {
    const checkPermission = async () => {
      try {
        const result = await navigator.permissions.query({ name: 'microphone' as PermissionName });
        if (result.state === 'granted') {
          setHasPermission(true);
          await enumerateDevices();
        }
      } catch (err) {
        console.log('Permission API not supported');
      }
    };
    checkPermission();
  }, []);

  // Stable callback for note detection that doesn't cause re-renders
  const handleNoteDetected = useCallback((note: DetectedNote) => {
    setCurrentNote(note);
    // Use the ref to call the latest callback without causing dependency issues
    if (onDetectedNoteChangeRef.current) {
      onDetectedNoteChangeRef.current(note.note, note.frequency);
    }
  }, []);

  // Auto start/stop detection when enabled prop changes
  useEffect(() => {
    const autoStartStop = async () => {
      if (enabled && !isActive && hasPermission && selectedDeviceId) {
        try {
          setError(null);

          // Try to get the shared audio stream from the key detection system
          const audioDeviceManager = getAudioDeviceManager();
          const sharedStream = audioDeviceManager?.getMediaStream();

          if (sharedStream && sharedStream.active) {
            // Use the shared stream from key detection
            console.log('Note Detector (auto-start): Using shared audio stream from key detection');
            await pitchDetectorRef.current?.start(sharedStream, handleNoteDetected);
          } else {
            // Create our own stream
            console.log('Note Detector (auto-start): Creating new audio stream for device:', selectedDeviceId);
            await pitchDetectorRef.current?.start(selectedDeviceId, handleNoteDetected);
          }

          setIsActive(true);
        } catch (err) {
          console.error('Error starting detection:', err);
          setError('Failed to start detection');
          setIsActive(false);
        }
      } else if (!enabled && isActive) {
        pitchDetectorRef.current?.stop();
        setIsActive(false);
        setCurrentNote({ note: null, frequency: null, confidence: 0 });
      }
    };
    autoStartStop();
    // handleNoteDetected is stable (useCallback with no deps), so it's safe to omit from dependencies
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [enabled, isActive, hasPermission, selectedDeviceId]);

  // Start detection
  const handleStart = async () => {
    if (!selectedDeviceId) {
      setError('Please select an audio input device');
      return;
    }

    try {
      setError(null);

      // Try to get the shared audio stream from the key detection system
      const audioDeviceManager = getAudioDeviceManager();
      const sharedStream = audioDeviceManager?.getMediaStream();

      if (sharedStream && sharedStream.active) {
        // Use the shared stream from key detection
        console.log('Note Detector: Using shared audio stream from key detection');
        await pitchDetectorRef.current?.start(sharedStream, handleNoteDetected);
      } else {
        // Create our own stream
        console.log('Note Detector: Creating new audio stream for device:', selectedDeviceId);
        await pitchDetectorRef.current?.start(selectedDeviceId, handleNoteDetected);
      }

      setIsActive(true);
    } catch (err) {
      console.error('Error starting detection:', err);
      setError('Failed to start detection');
      setIsActive(false);
    }
  };

  // Stop detection
  const handleStop = () => {
    pitchDetectorRef.current?.stop();
    setIsActive(false);
    setCurrentNote({ note: null, frequency: null, confidence: 0 });
  };

  const getStatusText = (): string => {
    if (!isActive) return 'Not Active';
    if (currentNote.note) return 'Detecting';
    return 'Listening...';
  };

  const getStatusColor = (): string => {
    if (!isActive) return theme.textSecondary;
    if (currentNote.note) return '#22c55e';
    return '#eab308';
  };

  return (
    <div
      className="rounded-lg p-4 mt-4"
      style={{
        background: theme.bgTertiary,
        border: `1px solid ${theme.border}`,
      }}
    >
      <div className="flex items-center justify-between gap-2 mb-3">
        <div className="flex items-center gap-2">
          <Music2 className="h-5 w-5" style={{ color: theme.textSecondary }} />
          <h3 className="text-sm font-semibold" style={{ color: theme.textPrimary }}>
            Note Detector
          </h3>
        </div>

        {/* Circle of 5ths Glow Duration Input */}
        {onCircleOf5thsGlowDurationChange && (
          <div className="flex items-center gap-2">
            <span className="text-xs" style={{ color: theme.textSecondary }}>Circle:</span>
            <input
              type="number"
              value={circleOf5thsGlowDuration}
              onChange={(e) => {
                const value = parseInt(e.target.value);
                if (!isNaN(value) && value >= 100 && value <= 5000) {
                  onCircleOf5thsGlowDurationChange(value);
                }
              }}
              min="100"
              max="5000"
              step="100"
              className="w-16 px-2 py-1 text-xs rounded border text-center"
              style={{
                background: theme.bgTertiary,
                color: theme.textPrimary,
                border: `1px solid ${theme.border}`,
              }}
            />
            <span className="text-xs" style={{ color: theme.textSecondary }}>ms</span>
          </div>
        )}
      </div>

      {/* Audio Device Selector */}
      {!hasPermission ? (
        <button
          onClick={requestPermissionAndEnumerateDevices}
          className="w-full py-2 px-4 rounded-lg text-sm font-medium transition-all mb-3"
          style={{
            background: theme.bgSecondary,
            color: theme.textPrimary,
            border: `1px solid ${theme.border}`,
          }}
        >
          <Mic className="inline-block w-4 h-4 mr-2" />
          Enable Microphone
        </button>
      ) : (
        <div className="relative mb-3">
          <button
            onClick={() => setIsDeviceDropdownOpen(!isDeviceDropdownOpen)}
            className="w-full py-2 px-4 rounded-lg text-sm font-medium transition-all text-left flex items-center justify-between"
            style={{
              background: theme.bgSecondary,
              color: theme.textPrimary,
              border: `1px solid ${theme.border}`,
            }}
          >
            <span className="truncate">
              {devices.find(d => d.deviceId === selectedDeviceId)?.label || 'Select Device'}
            </span>
            <ChevronDown
              className="w-4 h-4 transition-transform flex-shrink-0"
              style={{
                transform: isDeviceDropdownOpen ? 'rotate(180deg)' : 'rotate(0deg)'
              }}
            />
          </button>
          {isDeviceDropdownOpen && (
            <div
              className="absolute top-full left-0 right-0 mt-1 rounded-lg overflow-hidden z-50 max-h-48 overflow-y-auto"
              style={{
                background: theme.bgSecondary,
                border: `1px solid ${theme.border}`,
                boxShadow: '0 4px 12px rgba(0, 0, 0, 0.3)',
              }}
            >
              {devices.map((device) => (
                <button
                  key={device.deviceId}
                  onClick={() => {
                    setSelectedDeviceId(device.deviceId);
                    setIsDeviceDropdownOpen(false);
                  }}
                  className="w-full py-2 px-4 text-sm font-medium transition-all text-left"
                  style={{
                    background: selectedDeviceId === device.deviceId ? theme.buttonPrimary : 'transparent',
                    color: selectedDeviceId === device.deviceId ? '#ffffff' : theme.textPrimary,
                    borderBottom: `1px solid ${theme.border}`,
                  }}
                  onMouseEnter={(e) => {
                    if (selectedDeviceId !== device.deviceId) {
                      e.currentTarget.style.background = theme.bgTertiary;
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (selectedDeviceId !== device.deviceId) {
                      e.currentTarget.style.background = 'transparent';
                    }
                  }}
                >
                  <span className="truncate block">{device.label}</span>
                </button>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Start/Stop Buttons */}
      <div className="flex gap-2 mb-3">
        <button
          onClick={handleStart}
          disabled={isActive || !hasPermission}
          className="flex-1 py-2 px-4 rounded-lg text-sm font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          style={{
            background: isActive ? theme.bgSecondary : 'linear-gradient(135deg, #22c55e, #16a34a)',
            color: isActive ? theme.textSecondary : '#ffffff',
            border: `1px solid ${isActive ? theme.border : '#16a34a'}`,
          }}
        >
          Start
        </button>
        <button
          onClick={handleStop}
          disabled={!isActive}
          className="flex-1 py-2 px-4 rounded-lg text-sm font-medium transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          style={{
            background: !isActive ? theme.bgSecondary : 'linear-gradient(135deg, #ef4444, #dc2626)',
            color: !isActive ? theme.textSecondary : '#ffffff',
            border: `1px solid ${!isActive ? theme.border : '#dc2626'}`,
          }}
        >
          Stop
        </button>
      </div>

      {/* Live Notes Glow Checkbox */}
      {onLiveNotesGlowChange && (
        <div
          className="w-full flex items-center gap-3 px-4 py-2 rounded-lg transition-all mb-3"
          style={{
            background: theme.bgSecondary,
            color: theme.textPrimary,
            border: `1px solid ${theme.border}`,
          }}
        >
          {/* Checkbox */}
          <button
            onClick={() => onLiveNotesGlowChange(!liveNotesGlowEnabled)}
            className="flex items-center gap-3 flex-1"
          >
            <div
              className="w-4 h-4 rounded border-2 flex items-center justify-center transition-all flex-shrink-0"
              style={{
                borderColor: liveNotesGlowEnabled ? '#f59e0b' : theme.border,
                background: liveNotesGlowEnabled ? '#f59e0b' : 'transparent',
              }}
            >
              {liveNotesGlowEnabled && (
                <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                </svg>
              )}
            </div>
            <span className="text-sm font-medium">Live Notes Glow</span>
          </button>

          {/* Duration Input */}
          {onLiveNotesGlowDurationChange && (
            <div className="flex items-center gap-2">
              <input
                type="number"
                value={liveNotesGlowDuration}
                onChange={(e) => {
                  const value = parseInt(e.target.value);
                  if (!isNaN(value) && value >= 100 && value <= 5000) {
                    onLiveNotesGlowDurationChange(value);
                  }
                }}
                min="100"
                max="5000"
                step="100"
                className="w-16 px-2 py-1 text-xs rounded border text-center"
                style={{
                  background: theme.bgTertiary,
                  color: theme.textPrimary,
                  border: `1px solid ${theme.border}`,
                }}
                onClick={(e) => e.stopPropagation()}
              />
              <span className="text-xs" style={{ color: theme.textSecondary }}>ms</span>
            </div>
          )}
        </div>
      )}

      {/* Expandable Note/Frequency Display */}
      <button
        onClick={() => setIsExpanded(!isExpanded)}
        className="w-full py-2 px-4 rounded-lg text-sm font-medium transition-all text-left flex items-center justify-between"
        style={{
          background: theme.bgSecondary,
          color: theme.textPrimary,
          border: `1px solid ${theme.border}`,
        }}
      >
        <span>Show Detection</span>
        <ChevronDown
          className="w-4 h-4 transition-transform"
          style={{
            transform: isExpanded ? 'rotate(180deg)' : 'rotate(0deg)'
          }}
        />
      </button>

      {/* Expanded Detection Display */}
      {isExpanded && (
        <div
          className="mt-3 p-4 rounded-lg"
          style={{
            background: theme.bgSecondary,
            border: `1px solid ${theme.border}`,
          }}
        >
          {/* Status */}
          <div className="flex items-center justify-center gap-2 mb-4">
            <div
              className="h-2 w-2 rounded-full transition-all"
              style={{
                background: getStatusColor(),
                animation: currentNote.note && isActive ? 'pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite' : 'none',
              }}
            />
            <span className="text-xs font-medium" style={{ color: theme.textSecondary }}>
              {getStatusText()}
            </span>
          </div>

          {/* Note Display */}
          <div
            className="flex items-center justify-center rounded-lg mb-3"
            style={{
              background: theme.bgTertiary,
              border: `2px solid ${currentNote.note && isActive ? '#22c55e' : theme.border}`,
              height: '120px',
            }}
          >
            <div
              className="text-5xl font-bold transition-all"
              style={{
                color: currentNote.note && isActive ? theme.textPrimary : theme.textSecondary,
              }}
            >
              {currentNote.note || '--'}
            </div>
          </div>

          {/* Frequency Display */}
          <div className="text-center">
            <p className="text-xs font-medium mb-1" style={{ color: theme.textSecondary }}>
              Frequency
            </p>
            <p
              className="text-lg font-mono"
              style={{
                color: currentNote.frequency && isActive ? theme.textPrimary : theme.textSecondary,
              }}
            >
              {currentNote.frequency ? `${currentNote.frequency.toFixed(2)} Hz` : '--'}
            </p>
          </div>
        </div>
      )}

      {/* Error Display */}
      {error && (
        <div
          className="mt-3 p-2 rounded text-xs"
          style={{
            background: 'rgba(239, 68, 68, 0.1)',
            color: '#ef4444',
            border: '1px solid rgba(239, 68, 68, 0.3)',
          }}
        >
          {error}
        </div>
      )}

      {/* Tuner Section */}
      <button
        onClick={() => setIsTunerExpanded(!isTunerExpanded)}
        className="w-full flex items-center justify-between py-2 px-4 rounded-lg text-sm font-medium transition-all mt-3"
        style={{
          background: theme.bgSecondary,
          color: theme.textPrimary,
          border: `1px solid ${theme.border}`,
        }}
      >
        <span>Tuner</span>
        <ChevronDown
          className="w-4 h-4 transition-transform"
          style={{
            transform: isTunerExpanded ? 'rotate(180deg)' : 'rotate(0deg)'
          }}
        />
      </button>

      {/* Expanded Tuner Display */}
      {isTunerExpanded && (
        <div
          className="mt-3 rounded-lg overflow-hidden"
          style={{
            background: theme.bgSecondary,
            border: `1px solid ${theme.border}`,
          }}
        >
          <GuitarTuner
            theme={theme}
            frequency={currentNote.frequency}
            note={currentNote.note}
          />
        </div>
      )}
    </div>
  );
}

'use client';

/**
 * Load Nearby Chord Progression Dialog
 */

import { useState, useEffect } from 'react';
import { NearbyChord } from '@/lib/music-theory/neighborhood';
import {
  getUserNearbyProgressions,
  loadNearbyProgression,
  deleteNearbyProgression,
  SavedNearbyProgression,
} from '@/lib/chord-progression/nearby-progressions-service';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Input } from '@/components/ui/input';
import { FolderOpen, Loader2, Trash2, Calendar, Music, Search } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';

interface LoadProgressionDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onLoadSuccess?: (progressionId: string, chords: NearbyChord[], progressionName: string, progressionDescription: string) => void;
}

export default function LoadProgressionDialog({
  open,
  onOpenChange,
  onLoadSuccess,
}: LoadProgressionDialogProps) {
  const [progressions, setProgressions] = useState<SavedNearbyProgression[]>([]);
  const [selectedProgression, setSelectedProgression] = useState<SavedNearbyProgression | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [loadingProgressionId, setLoadingProgressionId] = useState<string | null>(null);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [progressionToDelete, setProgressionToDelete] = useState<string | null>(null);
  const { toast } = useToast();

  useEffect(() => {
    if (open) {
      fetchProgressions();
      setSelectedProgression(null);
      setSearchQuery('');
    }
  }, [open]);

  const fetchProgressions = async () => {
    setIsLoading(true);
    const result = await getUserNearbyProgressions();

    if (result.success && result.progressions) {
      setProgressions(result.progressions);
    } else {
      toast({
        title: 'Error',
        description: result.error || 'Failed to load progressions',
        variant: 'destructive',
      });
    }

    setIsLoading(false);
  };

  const handleLoadProgression = async () => {
    if (!selectedProgression) return;

    setLoadingProgressionId(selectedProgression.id);

    // Convert saved chord data back to NearbyChord format
    const chords: NearbyChord[] = selectedProgression.progression_data.chords.map(savedChord => ({
      rootNote: savedChord.rootNote,
      quality: savedChord.quality as any,
      degree: savedChord.degree,
      function: savedChord.function,
      distance: savedChord.distance,
      commonTones: savedChord.commonTones,
      commonToneNotes: savedChord.commonToneNotes,
      nearestVoicing: {
        rootNote: savedChord.rootNote,
        quality: savedChord.quality as any,
        stringSet: [1, 2, 3],
        inversion: 'root' as const,
        fretPosition: 0,
        frets: [],
        notes: savedChord.chordNotes || [],
      },
      allVoicings: [],
      selectedVoicingIndex: savedChord.selectedVoicingIndex,
      selectedVoicing: savedChord.voicingData,
      chordSymbol: savedChord.chordSymbol,
      chordNotes: savedChord.chordNotes,
    } as any));

    toast({
      title: 'Success',
      description: 'Progression loaded successfully',
    });

    onLoadSuccess?.(
      selectedProgression.id,
      chords,
      selectedProgression.name,
      selectedProgression.description || ''
    );
    onOpenChange(false);

    setLoadingProgressionId(null);
  };

  const handleDeleteProgression = async () => {
    if (!progressionToDelete) return;

    const result = await deleteNearbyProgression(progressionToDelete);

    if (result.success) {
      toast({
        title: 'Success',
        description: 'Progression deleted successfully',
      });
      setProgressions(progressions.filter(p => p.id !== progressionToDelete));
      if (selectedProgression?.id === progressionToDelete) {
        setSelectedProgression(null);
      }
    } else {
      toast({
        title: 'Error',
        description: result.error || 'Failed to delete progression',
        variant: 'destructive',
      });
    }

    setDeleteDialogOpen(false);
    setProgressionToDelete(null);
  };

  // Filter progressions based on search query
  const filteredProgressions = progressions.filter(p =>
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (p.description && p.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  };

  return (
    <>
      <Dialog open={open} onOpenChange={onOpenChange}>
        <DialogContent className="bg-gradient-to-br from-[#1a1a1a] to-[#0f0f0f] border-[#333333] shadow-2xl max-w-4xl h-[600px] flex flex-col">
          <DialogHeader className="pb-4 border-b border-[#2a2a2a]">
            <DialogTitle className="text-2xl font-bold bg-gradient-to-r from-white to-gray-300 bg-clip-text text-transparent flex items-center gap-2">
              <FolderOpen className="w-6 h-6 text-[#3b82f6]" />
              Load Chord Progression
            </DialogTitle>
          </DialogHeader>

          <div className="flex-1 flex gap-4 overflow-hidden py-4">
            {/* Left Panel - Progression List */}
            <div className="w-1/2 flex flex-col gap-3">
              {/* Search */}
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <Input
                  placeholder="Search progressions..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-10 bg-[#0a0a0a] border-[#3a3a3a] text-white placeholder:text-gray-500 focus:border-[#3b82f6] focus:ring-2 focus:ring-[#3b82f6]/20 transition-all"
                />
              </div>

              {/* Progression List */}
              {isLoading ? (
                <div className="flex-1 flex items-center justify-center">
                  <Loader2 className="w-8 h-8 animate-spin text-[#3b82f6]" />
                </div>
              ) : filteredProgressions.length === 0 ? (
                <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                  <Music className="w-16 h-16 mb-4 text-gray-600" />
                  <p className="text-lg font-semibold text-gray-300 mb-2">
                    {searchQuery ? 'No matching progressions' : 'No saved progressions'}
                  </p>
                  <p className="text-sm text-gray-500">
                    {searchQuery ? 'Try a different search term' : 'Save a progression to see it here'}
                  </p>
                </div>
              ) : (
                <ScrollArea className="flex-1">
                  <div className="space-y-2 pr-4">
                    {filteredProgressions.map((progression, progIndex) => {
                      // Color palette for chord buttons (same as nearby diatonic chords)
                      const CHORD_COLORS = [
                        '#ef4444', '#f97316', '#eab308', '#22c55e',
                        '#06b6d4', '#3b82f6', '#8b5cf6'
                      ];

                      return (
                        <div
                          key={progression.id}
                          onClick={() => setSelectedProgression(progression)}
                          className={`group p-3 rounded-xl border cursor-pointer transition-all duration-300 ${
                            selectedProgression?.id === progression.id
                              ? 'border-[#3b82f6] bg-gradient-to-br from-[#3b82f6]/20 to-[#2563eb]/10 shadow-lg shadow-[#3b82f6]/20'
                              : 'border-[#2a2a2a] bg-gradient-to-br from-[#1a1a1a] to-[#0f0f0f] hover:border-[#3b82f6]/50 hover:shadow-md hover:shadow-[#3b82f6]/10'
                          }`}
                        >
                          <div className="flex items-start justify-between mb-2">
                            <h3 className={`font-bold text-sm line-clamp-1 ${
                              selectedProgression?.id === progression.id ? 'text-white' : 'text-gray-200'
                            }`}>
                              {progression.name}
                            </h3>
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                setProgressionToDelete(progression.id);
                                setDeleteDialogOpen(true);
                              }}
                              className="opacity-0 group-hover:opacity-100 transition-opacity p-1 hover:bg-red-500/20 rounded"
                            >
                              <Trash2 className="w-4 h-4 text-red-400" />
                            </button>
                          </div>

                          {/* Colorful chord progression preview */}
                          <div className="flex flex-wrap gap-1 mb-2">
                            {progression.progression_data.chords.slice(0, 7).map((chord, index) => (
                              <div
                                key={index}
                                className="flex items-center gap-1 px-2 py-1 rounded-md text-xs font-semibold"
                                style={{
                                  backgroundColor: CHORD_COLORS[index % CHORD_COLORS.length],
                                  color: '#ffffff'
                                }}
                              >
                                <span className="opacity-70">{index + 1}</span>
                                <span>{chord.chordSymbol || `${chord.rootNote}${chord.quality === 'major' ? '' : chord.quality}`}</span>
                              </div>
                            ))}
                            {progression.progression_data.chords.length > 7 && (
                              <div className="px-2 py-1 text-xs text-gray-500">
                                +{progression.progression_data.chords.length - 7} more
                              </div>
                            )}
                          </div>

                          {progression.description && (
                            <p className="text-xs text-gray-400 line-clamp-1 mb-2">
                              {progression.description}
                            </p>
                          )}
                          <div className="flex items-center gap-3 text-xs text-gray-500">
                            <div className="flex items-center gap-1">
                              <Calendar className="w-3 h-3" />
                              <span>{formatDate(progression.created_at)}</span>
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </ScrollArea>
              )}
            </div>

            {/* Right Panel - Preview */}
            <div className="w-1/2 flex flex-col">
              {selectedProgression ? (
                <div className="flex-1 flex flex-col bg-[#0a0a0a] border border-[#2a2a2a] rounded-xl p-4 min-h-0">
                  <h3 className="text-lg font-bold text-white mb-2">{selectedProgression.name}</h3>
                  {selectedProgression.description && (
                    <p className="text-sm text-gray-400 mb-4">{selectedProgression.description}</p>
                  )}

                  <div className="flex-1 overflow-y-auto min-h-0">
                    <p className="text-xs font-semibold text-gray-400 mb-2">CHORD PROGRESSION</p>
                    <div className="space-y-2 pb-2">
                      {selectedProgression.progression_data.chords.map((chord, index) => (
                        <div
                          key={index}
                          className="flex items-center gap-3 p-2 rounded-lg bg-[#1a1a1a] border border-[#2a2a2a]"
                        >
                          <div className="w-8 h-8 rounded-full bg-[#3b82f6]/20 flex items-center justify-center text-xs font-bold text-[#3b82f6]">
                            {index + 1}
                          </div>
                          <div className="flex-1">
                            <div className="font-semibold text-white text-sm">
                              {chord.chordSymbol || `${chord.rootNote}${chord.quality === 'major' ? '' : chord.quality}`}
                            </div>
                            <div className="text-xs text-gray-500">{chord.degree} - {chord.function}</div>
                          </div>
                          {chord.selectedVoicingIndex !== undefined && (
                            <div className="text-xs text-[#3b82f6] font-semibold">Custom Voicing</div>
                          )}
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="mt-4 pt-4 border-t border-[#2a2a2a]">
                    <Button
                      onClick={handleLoadProgression}
                      disabled={loadingProgressionId === selectedProgression.id}
                      className="w-full h-11 font-semibold bg-gradient-to-r from-[#3b82f6] to-[#2563eb] hover:from-[#2563eb] hover:to-[#1d4ed8] shadow-lg shadow-[#3b82f6]/20 transition-all"
                    >
                      {loadingProgressionId === selectedProgression.id ? (
                        <>
                          <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                          Loading...
                        </>
                      ) : (
                        <>
                          <FolderOpen className="w-4 h-4 mr-2" />
                          Load Progression
                        </>
                      )}
                    </Button>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col items-center justify-center text-center p-8 bg-[#0a0a0a] border border-[#2a2a2a] rounded-xl">
                  <Music className="w-16 h-16 mb-4 text-gray-600" />
                  <p className="text-lg font-semibold text-gray-300 mb-2">No Progression Selected</p>
                  <p className="text-sm text-gray-500">Select a progression to preview</p>
                </div>
              )}
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent className="bg-[#1a1a1a] border-[#333333]">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-white">Delete Progression</AlertDialogTitle>
            <AlertDialogDescription className="text-gray-400">
              Are you sure you want to delete this progression? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel className="bg-transparent border-[#3a3a3a] hover:bg-[#2a2a2a] text-white">
              Cancel
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDeleteProgression}
              className="bg-red-600 hover:bg-red-700 text-white"
            >
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

'use client';

/**
 * AI-Powered Scale/Mode Recommendations
 * Allows users to describe their vision and get AI-generated scale/mode recommendations
 */

import { useState, useEffect } from 'react';
import { ChordInstance, VerseData, AIScaleModeRecommendation } from '@/lib/chord-progression/types';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Loader2, Sparkles, Plus } from 'lucide-react';
import { mapGPTScaleNameToInternal, mapGPTKeyNameToInternal } from '@/lib/scale-mode-mapping';
import { useToast } from '@/hooks/use-toast';

interface AIScaleModeRecommendationsProps {
  currentKey: string;
  currentProgression: ChordInstance[];
  onAddScaleToTimeline?: (scaleName: string, rootNote: string) => void;
  activeVerse?: VerseData;
  onVerseUpdate?: (verseId: string, updates: Partial<VerseData>) => void;
}

export default function AIScaleModeRecommendations({
  currentKey,
  currentProgression,
  onAddScaleToTimeline,
  activeVerse,
  onVerseUpdate,
}: AIScaleModeRecommendationsProps) {
  const [userVision, setUserVision] = useState('');
  const [recommendations, setRecommendations] = useState<AIScaleModeRecommendation[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const { toast } = useToast();

  // Load saved vision and recommendations when activeVerse changes
  useEffect(() => {
    if (activeVerse) {
      if (activeVerse.aiScaleVisionText) {
        setUserVision(activeVerse.aiScaleVisionText);
      }
      if (activeVerse.aiScaleRecommendations && activeVerse.aiScaleRecommendations.length > 0) {
        setRecommendations(activeVerse.aiScaleRecommendations);
      }
    }
  }, [activeVerse?.id]); // Only re-run when verse ID changes

  const handleGenerate = async () => {
    if (!userVision.trim()) {
      toast({
        title: 'Vision Required',
        description: 'Please describe your musical vision to generate recommendations.',
        variant: 'destructive',
      });
      return;
    }

    setIsGenerating(true);
    try {
      const response = await fetch('/api/scale-mode-recommendations/generate', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          userVision,
          chordProgression: currentProgression.map(c => ({
            chordSymbol: c.chordSymbol,
            rootNote: c.rootNote,
            chordQuality: c.chordQuality,
          })),
          currentKey,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to generate recommendations');
      }

      const data = await response.json();
      setRecommendations(data.recommendations || []);

      // Save to database
      if (activeVerse && onVerseUpdate) {
        onVerseUpdate(activeVerse.id, {
          aiScaleVisionText: userVision,
          aiScaleRecommendations: data.recommendations || [],
        });
      }

      toast({
        title: 'Success',
        description: `Generated ${data.recommendations?.length || 0} scale/mode recommendations`,
      });
    } catch (error) {
      console.error('Error generating recommendations:', error);
      toast({
        title: 'Error',
        description: 'Failed to generate recommendations. Please try again.',
        variant: 'destructive',
      });
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAddToTimeline = (recommendation: AIScaleModeRecommendation) => {
    if (!onAddScaleToTimeline) return;

    // Map GPT names to internal format
    const internalScaleName = mapGPTScaleNameToInternal(recommendation.scaleName);
    const internalRootNote = mapGPTKeyNameToInternal(recommendation.rootNote);

    onAddScaleToTimeline(internalScaleName, internalRootNote);

    toast({
      title: 'Added to Timeline',
      description: `${internalRootNote} ${internalScaleName} added to the Scales track`,
    });
  };

  const getScoreColor = (score: number): string => {
    if (score >= 9) return '#4CAF50'; // Green
    if (score >= 7) return '#2196F3'; // Blue
    if (score >= 5) return '#FF9800'; // Orange
    return '#9E9E9E'; // Gray
  };

  return (
    <div className="h-full flex flex-col p-6 overflow-y-auto">
      {/* Input Section - Fixed Width, Left Aligned */}
      <div className="mb-6 max-w-3xl w-full">
        <label className="block text-sm font-semibold text-[#e0e0e0] mb-2">
          Describe Your Vision
        </label>
        <Textarea
          value={userVision}
          onChange={(e) => setUserVision(e.target.value)}
          placeholder="E.g., 'I want a jazzy, sophisticated sound for improvisation' or 'Looking for bluesy scales that work over the whole progression'"
          className="min-h-[100px] bg-[#1a1a1a] border-[#333333] text-white placeholder:text-[#666666] resize-none"
          disabled={isGenerating}
        />
        <div className="flex items-center justify-between mt-3">
          <p className="text-xs text-[#888888]">
            {currentProgression.length > 0
              ? `Current progression: ${currentProgression.map(c => c.chordSymbol).join(' - ')}`
              : 'No chords in progression yet'}
          </p>
          <Button
            onClick={handleGenerate}
            disabled={isGenerating || !userVision.trim()}
            className="gap-2 bg-gradient-to-r from-[#8b5cf6] to-[#7c3aed] hover:from-[#7c3aed] hover:to-[#6d28d9] text-white font-semibold"
          >
            {isGenerating ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                Generating...
              </>
            ) : (
              <>
                <Sparkles className="w-4 h-4" />
                Generate Recommendations
              </>
            )}
          </Button>
        </div>
      </div>

      {/* Recommendations Display - Fixed Width, Left Aligned */}
      {recommendations.length > 0 && (
        <div className="flex-1 max-w-3xl w-full">
          <h3 className="text-lg font-bold text-white mb-4">
            Recommended Scales & Modes
          </h3>
          <div className="grid gap-4">
            {recommendations.map((rec, index) => (
              <div
                key={index}
                className="bg-gradient-to-br from-[#1e1e1e] to-[#1a1a1a] border border-[#333333] rounded-lg p-4 hover:border-[#8b5cf6] transition-all"
              >
                <div className="flex items-start justify-between mb-2">
                  <div>
                    <h4 className="text-lg font-bold text-white">
                      {rec.rootNote} {rec.scaleName}
                    </h4>
                    {rec.genreContext && (
                      <p className="text-xs text-[#888888] mt-1">
                        {rec.genreContext}
                      </p>
                    )}
                  </div>
                  <div
                    className="px-3 py-1 rounded-full text-sm font-bold text-white"
                    style={{ backgroundColor: getScoreColor(rec.compatibilityScore) }}
                  >
                    Γ¡É {rec.compatibilityScore}/10
                  </div>
                </div>
                <p className="text-sm text-[#b0b0b0] mb-3">
                  {rec.rationale}
                </p>
                {onAddScaleToTimeline && (
                  <Button
                    onClick={() => handleAddToTimeline(rec)}
                    size="sm"
                    className="gap-2 bg-[#3b82f6] hover:bg-[#2563eb] text-white font-semibold"
                  >
                    <Plus className="w-3.5 h-3.5" />
                    Add to Timeline
                  </Button>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Empty State */}
      {recommendations.length === 0 && !isGenerating && (
        <div className="flex-1 flex items-center justify-center">
          <div className="text-center max-w-md">
            <Sparkles className="w-16 h-16 mx-auto mb-4 text-[#8b5cf6]" />
            <h3 className="text-xl font-bold text-white mb-2">
              AI-Powered Scale Recommendations
            </h3>
            <p className="text-sm text-[#a0a0a0]">
              Describe your musical vision and get personalized scale/mode recommendations
              that work over your entire chord progression.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

