import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Download, HelpCircle, ArrowLeft, Menu, ZoomIn, ZoomOut, Undo, Redo, History } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { ScaleModeInstance } from '@/lib/chord-progression/types';
import { useRouter } from 'next/navigation';
import { themes } from '@/lib/themes';

export default function ChordProgressionBuilder() {
  const router = useRouter();
  const { getNoteDisplayName, getNotesDisplay } = useNoteDisplay();

  // Colorful Strings state - local to Song Builder
  const [showColorfulStrings, setShowColorfulStrings] = useLocalStorage('song-builder-show-colorful-strings', false);
  const [stringBrightness, setStringBrightness] = useLocalStorage('song-builder-string-brightness', 100);
  const {
    verses,
    activeVerse,
    activeVerseId,
    addVerse,
    updateVerse,
    deleteVerse,
    setActiveVerse,
    updateChords: updateChordsInternal,
    updateScaleModes: updateScaleModesInternal,
    setVerses,
  } = useChordProgressionState();

  // Undo/Redo system
  const {
    execute: executeCommand,
    undo,
    redo,
    canUndo,
    canRedo,
    lastUndoDescription,
    lastRedoDescription,
    getUndoHistory,
    getRedoHistory,
    restoreToUndoState,
    restoreToRedoState,
  } = useUndoRedo(50);

  // Wrapped update functions with undo/redo support
  const updateChords = (newChords: ChordInstance[], description?: string) => {
    if (!activeVerse) return;

    // Auto-detect operation type if no description provided
    let finalDescription = description;
    if (!finalDescription) {
      const oldChords = activeVerse.chordProgression;

      // Check if chords were reordered (same chords, different order)
      if (oldChords.length === newChords.length) {
        const oldIds = oldChords.map(c => c.id).join(',');
        const newIds = newChords.map(c => c.id).join(',');

        if (oldIds !== newIds) {
          finalDescription = 'Reorder chords';
        } else {
          // Check if any chord was moved/resized
          const movedOrResized = newChords.some((newChord, i) => {
            const oldChord = oldChords[i];
            return oldChord.position !== newChord.position || oldChord.width !== newChord.width;
          });
          finalDescription = movedOrResized ? 'Move/resize chord' : 'Update chords';
        }
      } else if (oldChords.length < newChords.length) {
        finalDescription = 'Add chord';
      } else {
        finalDescription = 'Delete chord';
      }
    }

    const command = new UpdateChordsCommand(
      activeVerse.chordProgression,
      newChords,
      updateChordsInternal,
      finalDescription
    );
    executeCommand(command);
  };

  const updateScaleModes = (newScaleModes: ScaleModeInstance[], description?: string) => {
    if (!activeVerse) return;

    const command = new UpdateScaleModesCommand(
      activeVerse.scaleModeAssignments,
      newScaleModes,
      updateScaleModesInternal,
      description || 'Update scale modes'
    );
    executeCommand(command);
  };

  const { toast } = useToast();
  const [pixelsPerBeat, setPixelsPerBeat] = useState(DEFAULT_ZOOM_LEVEL.pixelsPerBeat);
  const [currentProjectId, setCurrentProjectId] = useState<string | null>(null);
  const [currentProjectName, setCurrentProjectName] = useState<string>('');
  const [currentProjectDescription, setCurrentProjectDescription] = useState<string>('');
  const [showSaveDialog, setShowSaveDialog] = useState(false);
  const [showLoadDialog, setShowLoadDialog] = useState(false);
  const [showShortcutsDialog, setShowShortcutsDialog] = useState(false);
  const [showAddChordModal, setShowAddChordModal] = useState(false);
  const [showAddScaleModeModal, setShowAddScaleModeModal] = useState(false);
  const [showKeySelector, setShowKeySelector] = useState(false);
  const [showHistoryModal, setShowHistoryModal] = useState(false);
  const [editingChord, setEditingChord] = useState<ChordInstance | null>(null);
  const [editingScaleMode, setEditingScaleMode] = useState<ScaleModeInstance | null>(null);
  const [selectedChord, setSelectedChord] = useState<ChordInstance | null>(null);
  const [showSettings, setShowSettings] = useState(false);
  const [isGeneratingUpdates, setIsGeneratingUpdates] = useState(false);
  const [generatorPanelRef, setGeneratorPanelRef] = useState<{
    triggerUpdateRecommendations: (updates: any[]) => void;
    setGeneratingUpdates: (isGenerating: boolean) => void;
  } | null>(null);

  const {
    playbackState,
    selectedInstrument,
    setSelectedInstrument,
    volume,
    setVolume,
    midiEnabled,
    setMidiEnabled,
    audioOutputDevice,
    setAudioOutputDevice,
    availableDevices,
    play,
    pause,
    stop,
    seek,
    replay,
    setBPM,
  } = useTimelinePlayback(
    activeVerse?.chordProgression || [],
    activeVerse?.bpm || 120,
    pixelsPerBeat
  );

  // Chord progression compatibility analysis
  const { compatibility, isLoading: isAnalyzing, error: analysisError } = useChordProgressionCompatibility(
    activeVerse?.chordProgression || [],
    activeVerse?.key || 'C'
  );

  // Calculate currently playing chord during playback
  const getCurrentlyPlayingChord = (): ChordInstance | null => {
    if (!playbackState.isPlaying) return null;

    const chords = activeVerse?.chordProgression || [];
    const currentTime = playbackState.currentTime;

    // Find the chord that contains the current playback time
    for (const chord of chords) {
      const chordStartBeat = chord.position / pixelsPerBeat;
      const chordEndBeat = chordStartBeat + chord.duration;

      if (currentTime >= chordStartBeat && currentTime < chordEndBeat) {
        return chord;
      }
    }

    return null;
  };

  // Get the chord to display in the diagrams tab
  const displayChord = playbackState.isPlaying ? getCurrentlyPlayingChord() : selectedChord;

  const handleBPMChange = (newBPM: number) => {
    if (activeVerseId) {
      updateVerse(activeVerseId, { bpm: newBPM });
      setBPM(newBPM);
    }
  };

  const handleKeyChange = (newKey: string) => {
    if (activeVerseId) {
      updateVerse(activeVerseId, { key: newKey });
    }
  };

  const handleQuickSave = async () => {
    if (!currentProjectId || !currentProjectName) return;

    const result = await updateProject(
      currentProjectId,
      currentProjectName,
      currentProjectDescription,
      verses
    );

    if (result.success) {
      toast({
        title: 'Success',
        description: 'Project saved successfully',
      });
    } else {
      toast({
        title: 'Error',
        description: result.error || 'Failed to save project',
        variant: 'destructive',
      });
    }
  };

  const handleSaveSuccess = (projectId: string, projectName?: string, projectDescription?: string) => {
    setCurrentProjectId(projectId);
    if (projectName) setCurrentProjectName(projectName);
    if (projectDescription !== undefined) setCurrentProjectDescription(projectDescription);
  };

  const handleLoadSuccess = (
    projectId: string,
    loadedVerses: VerseData[],
    projectName: string,
    projectDescription: string
  ) => {
    setCurrentProjectId(projectId);
    setCurrentProjectName(projectName);
    setCurrentProjectDescription(projectDescription);
    setVerses(loadedVerses);
    if (loadedVerses.length > 0) {
      setActiveVerse(loadedVerses[0].id);
    }
  };

  const handleAddChord = (chordSymbol: string, duration: number) => {
    if (!activeVerse) return;

    // Calculate position at the end of the rightmost chord (not just the last in the array)
    let position = 0;
    if (activeVerse.chordProgression.length > 0) {
      // Find the rightmost chord by checking position + width
      let maxEndPosition = 0;
      activeVerse.chordProgression.forEach(chord => {
        const endPosition = chord.position + chord.width;
        if (endPosition > maxEndPosition) {
          maxEndPosition = endPosition;
        }
      });
      position = maxEndPosition;
    }
    const startTime = position / pixelsPerBeat;

    // Import chord utilities
    const { parseChordSymbol } = require('@/lib/chord-progression/chord-utils');
    const { getChordTones } = require('@/lib/musicTheory');
    const { NOTE_COLORS } = require('@/lib/musicTheory');

    // Parse chord and generate notes
    const { rootNote, quality } = parseChordSymbol(chordSymbol);
    const notes = getChordTones(rootNote, quality);
    const color = NOTE_COLORS[rootNote] || '#3b82f6';

    const newChord = {
      id: `chord-${Date.now()}`,
      chordSymbol,
      chordQuality: quality,
      notes,
      rootNote,
      startTime,
      position,
      width: duration * pixelsPerBeat,
      duration,
      color,
      voicingIndex: 0,
    };

    updateChords([...activeVerse.chordProgression, newChord], `Add chord ${chordSymbol}`);
  };

  const handleEditChord = (chord: ChordInstance) => {
    setEditingChord(chord);
    setShowAddChordModal(true);
  };

  const handleUpdateChord = (chordSymbol: string, duration: number) => {
    if (!activeVerse || !editingChord) return;

    // Import chord utilities
    const { parseChordSymbol } = require('@/lib/chord-progression/chord-utils');
    const { getChordTones } = require('@/lib/musicTheory');
    const { NOTE_COLORS } = require('@/lib/musicTheory');

    // Parse chord and generate notes
    const { rootNote, quality } = parseChordSymbol(chordSymbol);
    const notes = getChordTones(rootNote, quality);
    const color = NOTE_COLORS[rootNote] || '#3b82f6';

    const updatedChords = activeVerse.chordProgression.map(c =>
      c.id === editingChord.id
        ? {
            ...c,
            chordSymbol,
            chordQuality: quality,
            notes,
            rootNote,
            duration,
            width: duration * pixelsPerBeat,
            color,
          }
        : c
    );

    updateChords(updatedChords, `Edit chord to ${chordSymbol}`);
    setEditingChord(null);
  };

  const handleAddScaleMode = (scaleName: string, duration: number) => {
    if (!activeVerse) return;

    // Calculate position at the end of the rightmost scale mode (not just the last in the array)
    let position = 0;
    if (activeVerse.scaleModeAssignments.length > 0) {
      // Find the rightmost scale mode by checking position + width
      let maxEndPosition = 0;
      activeVerse.scaleModeAssignments.forEach(scaleMode => {
        const endPosition = scaleMode.position + scaleMode.width;
        if (endPosition > maxEndPosition) {
          maxEndPosition = endPosition;
        }
      });
      position = maxEndPosition;
    }
    const startTime = position / pixelsPerBeat;

    const newScaleMode: ScaleModeInstance = {
      id: `scale-${Date.now()}`,
      chordId: '', // Not linked to specific chord
      scaleName,
      rootNote: activeVerse.key,
      compatibilityScore: 10, // Default score
      startTime,
      duration,
      position,
      width: duration * pixelsPerBeat,
    };

    updateScaleModes([...activeVerse.scaleModeAssignments, newScaleMode], `Add scale ${scaleName}`);
  };

  // Handler for adding scale from recommendations (with default 4 beat duration)
  const handleAddScaleFromRecommendations = (scaleName: string, rootNote: string) => {
    handleAddScaleMode(scaleName, 4); // Default to 4 beats
  };

  // Handler for generating chord progression updates from compatibility score
  const handleGenerateProgressionUpdates = async () => {
    if (!activeVerse || activeVerse.chordProgression.length === 0) {
      toast({
        title: 'No Progression',
        description: 'Add some chords to your progression first',
        variant: 'destructive',
      });
      return;
    }

    setIsGeneratingUpdates(true);

    // Notify the generator panel to show loading state and switch tabs
    if (generatorPanelRef?.setGeneratingUpdates) {
      generatorPanelRef.setGeneratingUpdates(true);
    }

    try {
      const response = await fetch('/api/chord-progression/generate-progression-updates', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          currentKey: activeVerse.key,
          currentProgression: activeVerse.chordProgression.map(c => c.chordSymbol),
          currentScaleModes: activeVerse.scaleModeAssignments.map(s => s.scaleName),
          compatibilityScore: compatibility?.score,
          compatibilityRationale: compatibility?.rationale,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to generate updates');
      }

      const data = await response.json();

      // Trigger the generator panel to show the updates
      if (generatorPanelRef?.triggerUpdateRecommendations) {
        generatorPanelRef.triggerUpdateRecommendations(data.updates);
      }

      toast({
        title: 'Success',
        description: `Generated ${data.updates.length} chord progression updates`,
      });
    } catch (error) {
      console.error('Error generating updates:', error);
      toast({
        title: 'Error',
        description: 'Failed to generate chord progression updates',
        variant: 'destructive',
      });

      // Stop generating state on error
      if (generatorPanelRef?.setGeneratingUpdates) {
        generatorPanelRef.setGeneratingUpdates(false);
      }
    } finally {
      setIsGeneratingUpdates(false);
    }
  };

  const handleEditScaleMode = (scaleMode: ScaleModeInstance) => {
    setEditingScaleMode(scaleMode);
    setShowAddScaleModeModal(true);
  };

  const handleUpdateScaleMode = (scaleName: string, duration: number) => {
    if (!activeVerse || !editingScaleMode) return;

    const updatedScaleModes = activeVerse.scaleModeAssignments.map(sm =>
      sm.id === editingScaleMode.id
        ? {
            ...sm,
            scaleName,
            duration,
            width: duration * pixelsPerBeat,
          }
        : sm
    );

    updateScaleModes(updatedScaleModes);
    setEditingScaleMode(null);
  };

  // Keyboard shortcuts
  useKeyboardShortcuts({
    onPlay: play,
    onPause: pause,
    onStop: stop,
    isPlaying: playbackState.isPlaying,
    onSave: () => setShowSaveDialog(true),
    onLoad: () => setShowLoadDialog(true),
    onUndo: undo,
    onRedo: redo,
  });

  return (
    <div className="flex flex-col h-screen bg-[#0a0a0a] text-white">
      {/* Header */}
      <header className="h-20 border-b border-[#333333] flex items-center justify-between px-6">
        <div className="flex items-center gap-4 flex-1">
          {/* Hamburger Menu */}
          <HamburgerMenu
            theme={themes.dark}
            showColorfulStrings={showColorfulStrings}
            stringBrightness={stringBrightness}
            onShowColorfulStringsChange={setShowColorfulStrings}
            onStringBrightnessChange={setStringBrightness}
            onSave={() => {
              if (currentProjectId) {
                handleQuickSave();
              } else {
                setShowSaveDialog(true);
              }
            }}
            onSaveAs={() => setShowSaveDialog(true)}
            onLoad={() => setShowLoadDialog(true)}
            onToggleSettings={() => setShowSettings(!showSettings)}
            onLogout={() => {}}
          />

          {/* Back Button */}
          <Button
            variant="outline"
            size="sm"
            className="gap-2 font-semibold"
            onClick={() => router.push('/')}
          >
            <ArrowLeft className="w-4 h-4" />
            Back
          </Button>
          <div>
            <h1 className="text-2xl font-bold">Song Builder</h1>
            {currentProjectName && (
              <p className="text-sm text-[#a0a0a0]">{currentProjectName}</p>
            )}
          </div>

          {/* Compatibility Score - Left aligned after title */}
          <div className="ml-6">
            <CompatibilityScore
              score={compatibility?.score ?? null}
              rationale={compatibility?.rationale ?? null}
              recommendations={compatibility?.recommendations ?? null}
              isLoading={isAnalyzing}
              error={analysisError}
              onGenerateUpdates={handleGenerateProgressionUpdates}
              isGeneratingUpdates={isGeneratingUpdates}
            />
          </div>
        </div>

        <div className="flex gap-3 items-center">
          {/* Undo/Redo Controls */}
          <div className="flex items-center gap-1 ml-2 pl-2 border-l border-[#333333]">
            <Button
              variant="outline"
              size="sm"
              className="px-2"
              onClick={undo}
              disabled={!canUndo}
              title={lastUndoDescription ? `Undo: ${lastUndoDescription}` : 'Undo (Ctrl+Z)'}
            >
              <Undo className="w-4 h-4" />
            </Button>
            <Button
              variant="outline"
              size="sm"
              className="px-2"
              onClick={redo}
              disabled={!canRedo}
              title={lastRedoDescription ? `Redo: ${lastRedoDescription}` : 'Redo (Ctrl+Shift+Z)'}
            >
              <Redo className="w-4 h-4" />
            </Button>
            <Button
              variant="outline"
              size="sm"
              className="px-2"
              onClick={() => setShowHistoryModal(true)}
              title="View History"
            >
              <History className="w-4 h-4" />
            </Button>
          </div>

          <Button
            variant="outline"
            size="sm"
            className="gap-2 font-semibold"
          >
            <Download className="w-4 h-4" />
            Export
          </Button>

          {/* Zoom Controls */}
          <div className="flex items-center gap-2 ml-2 pl-2 border-l border-[#333333]">
            <span className="text-xs font-semibold text-[#b0b0b0]">Zoom:</span>
            <Button
              variant="secondary"
              size="sm"
              onClick={() => {
                const currentZoomIndex = ZOOM_LEVELS.findIndex(z => z.pixelsPerBeat === pixelsPerBeat);
                const prevIndex = Math.max(currentZoomIndex - 1, 0);
                setPixelsPerBeat(ZOOM_LEVELS[prevIndex].pixelsPerBeat);
              }}
              disabled={ZOOM_LEVELS.findIndex(z => z.pixelsPerBeat === pixelsPerBeat) === 0}
              className="h-7 px-2 font-semibold"
            >
              <ZoomOut className="w-3.5 h-3.5" />
            </Button>
            <span className="text-xs font-bold min-w-[50px] text-center text-white px-2 py-1 rounded-md bg-gradient-to-b from-[#2a2a2a] to-[#1e1e1e] border border-[#3a3a3a]">
              {ZOOM_LEVELS[ZOOM_LEVELS.findIndex(z => z.pixelsPerBeat === pixelsPerBeat)]?.label || '100%'}
            </span>
            <Button
              variant="secondary"
              size="sm"
              onClick={() => {
                const currentZoomIndex = ZOOM_LEVELS.findIndex(z => z.pixelsPerBeat === pixelsPerBeat);
                const nextIndex = Math.min(currentZoomIndex + 1, ZOOM_LEVELS.length - 1);
                setPixelsPerBeat(ZOOM_LEVELS[nextIndex].pixelsPerBeat);
              }}
              disabled={ZOOM_LEVELS.findIndex(z => z.pixelsPerBeat === pixelsPerBeat) === ZOOM_LEVELS.length - 1}
              className="h-7 px-2 font-semibold"
            >
              <ZoomIn className="w-3.5 h-3.5" />
            </Button>
          </div>

          <Button
            variant="ghost"
            size="sm"
            onClick={() => setShowShortcutsDialog(true)}
            title="Keyboard Shortcuts"
            className="hover:bg-[#3b82f6]/10"
          >
            <HelpCircle className="w-4 h-4" />
          </Button>
        </div>
      </header>

      {/* Verse Tabs */}
      <VerseTabsManager
        verses={verses}
        activeVerseId={activeVerseId}
        onVerseSelect={setActiveVerse}
        onVerseAdd={addVerse}
        onVerseUpdate={updateVerse}
        onVerseDelete={deleteVerse}
        onKeyChange={handleKeyChange}
      />

      {/* Main Content Area - Timeline + Generator */}
      <div className="flex-1 overflow-hidden flex flex-col">
        {/* Timeline Visualization */}
        <TimelineVisualization
          chords={activeVerse?.chordProgression || []}
          scaleModes={activeVerse?.scaleModeAssignments || []}
          pixelsPerBeat={pixelsPerBeat}
          onPixelsPerBeatChange={setPixelsPerBeat}
          onChordsUpdate={updateChords}
          onScaleModesUpdate={updateScaleModes}
          playbackState={playbackState}
          bpm={activeVerse?.bpm || 120}
          onAddChordClick={() => {
            setEditingChord(null);
            setShowAddChordModal(true);
          }}
          onAddScaleModeClick={() => {
            setEditingScaleMode(null);
            setShowAddScaleModeModal(true);
          }}
          onEditChordClick={handleEditChord}
          onEditScaleModeClick={handleEditScaleMode}
          currentKey={activeVerse?.key || 'C'}
          onKeyChangeClick={() => setShowKeySelector(true)}
          onChordClick={setSelectedChord}
          onSeek={seek}
        />

        {/* Generator Panel - Always Visible, Below Timeline */}
        <GeneratorPanel
          currentKey={activeVerse?.key || 'C'}
          pixelsPerBeat={pixelsPerBeat}
          onProgressionLoad={(chords) => {
            updateChords(chords);
          }}
          currentProgression={activeVerse?.chordProgression || []}
          currentScaleModes={activeVerse?.scaleModeAssignments || []}
          onAddScaleToTimeline={handleAddScaleFromRecommendations}
          onKeyChangeClick={() => setShowKeySelector(true)}
          verseId={activeVerseId || ''}
          selectedChord={displayChord}
          isPlaying={playbackState.isPlaying}
          currentTime={playbackState.currentTime}
          showColorfulStrings={showColorfulStrings}
          onShowColorfulStringsChange={setShowColorfulStrings}
          stringBrightness={stringBrightness}
          onStringBrightnessChange={setStringBrightness}
          selectedInstrument={selectedInstrument}
          activeVerse={activeVerse}
          onVerseUpdate={updateVerse}
          onGeneratorRef={setGeneratorPanelRef}
        />
      </div>

      {/* Playback Controls */}
      <PlaybackControls
        isPlaying={playbackState.isPlaying}
        bpm={activeVerse?.bpm || 120}
        currentKey={activeVerse?.key || 'C'}
        selectedInstrument={selectedInstrument}
        volume={volume}
        midiEnabled={midiEnabled}
        audioOutputDevice={audioOutputDevice}
        availableDevices={availableDevices}
        onPlay={play}
        onPause={pause}
        onStop={stop}
        onReplay={replay}
        onBPMChange={handleBPMChange}
        onInstrumentChange={setSelectedInstrument}
        onVolumeChange={setVolume}
        onMidiToggle={setMidiEnabled}
        onAudioOutputChange={setAudioOutputDevice}
      />

      {/* Add/Edit Chord Modal */}
      <AddChordModal
        open={showAddChordModal}
        onOpenChange={(open) => {
          setShowAddChordModal(open);
          if (!open) setEditingChord(null);
        }}
        currentKey={activeVerse?.key || 'C'}
        onChordSelect={editingChord ? handleUpdateChord : handleAddChord}
        editingChord={editingChord}
      />

      {/* Add/Edit Scale/Mode Modal */}
      <AddScaleModeModal
        open={showAddScaleModeModal}
        onOpenChange={(open) => {
          setShowAddScaleModeModal(open);
          if (!open) setEditingScaleMode(null);
        }}
        currentKey={activeVerse?.key || 'C'}
        onScaleModeSelect={editingScaleMode ? handleUpdateScaleMode : handleAddScaleMode}
        editingScaleMode={editingScaleMode}
      />

      {/* Save Dialog */}
      <SaveProjectDialog
        open={showSaveDialog}
        onOpenChange={setShowSaveDialog}
        verses={verses}
        currentProjectId={currentProjectId || undefined}
        currentProjectName={currentProjectName}
        currentProjectDescription={currentProjectDescription}
        onSaveSuccess={handleSaveSuccess}
      />

      {/* Load Dialog */}
      <LoadProjectDialog
        open={showLoadDialog}
        onOpenChange={setShowLoadDialog}
        onLoadSuccess={handleLoadSuccess}
      />

      {/* Keyboard Shortcuts Dialog */}
      <KeyboardShortcutsDialog
        open={showShortcutsDialog}
        onOpenChange={setShowShortcutsDialog}
      />

      {/* Key Selector Dialog */}
      <Dialog open={showKeySelector} onOpenChange={setShowKeySelector}>
        <DialogContent className="bg-gradient-to-br from-[#1a1a1a] via-[#141414] to-[#0f0f0f] border-2 border-[#3a3a3a] shadow-2xl w-fit max-w-none">
          <DialogHeader className="pb-6 border-b border-[#2a2a2a]">
            <div className="flex items-start justify-between gap-4 pr-8">
              <div>
                <DialogTitle className="text-3xl font-bold bg-gradient-to-r from-white via-[#e0e0e0] to-[#b0b0b0] bg-clip-text text-transparent">
                  Select Musical Key
                </DialogTitle>
                <p className="text-sm text-[#888888] mt-2 font-medium">
                  Choose the key for your chord progression
                </p>
              </div>
              {/* Previous Section Key Reference */}
              {(() => {
                const currentIndex = verses.findIndex(v => v.id === activeVerseId);
                const previousVerse = currentIndex > 0 ? verses[currentIndex - 1] : null;

                return previousVerse && (
                  <div className="flex flex-col items-end gap-1 flex-shrink-0">
                    <p className="text-xs text-[#888888] font-medium uppercase tracking-wide">
                      Last Section Key
                    </p>
                    <div
                      className="px-4 py-2 rounded-lg font-bold text-white text-lg shadow-lg"
                      style={{
                        backgroundColor: NOTE_COLORS[getNoteDisplayName(previousVerse.key)] || '#888888',
                        border: `2px solid ${NOTE_COLORS[getNoteDisplayName(previousVerse.key)] || '#888888'}`,
                      }}
                    >
                      {getNoteDisplayName(previousVerse.key)}
                    </div>
                    <p className="text-xs text-[#a0a0a0] font-medium">
                      {previousVerse.name}
                    </p>
                  </div>
                );
              })()}
            </div>
          </DialogHeader>
          <div className="flex gap-6 py-6 px-2">
            {/* Key Selection Grid */}
            <div className="grid grid-cols-4 gap-2 w-80">
            {getNotesDisplay().map(displayNote => {
              const internalNote = normalizeNoteFromDisplay(displayNote);
              const noteColor = NOTE_COLORS[displayNote] || '#888888';
              const isActive = activeVerse?.key === internalNote;

              return (
                <button
                  key={displayNote}
                  onClick={() => {
                    handleKeyChange(internalNote);
                    setShowKeySelector(false);
                  }}
                  className="group relative aspect-square rounded-lg font-bold text-white transition-all duration-300 hover:scale-110 active:scale-95 overflow-hidden"
                  style={{
                    background: isActive
                      ? `linear-gradient(135deg, ${noteColor} 0%, ${noteColor}cc 50%, ${noteColor}99 100%)`
                      : `linear-gradient(135deg, ${noteColor}30 0%, ${noteColor}15 100%)`,
                    border: isActive ? `3px solid ${noteColor}` : `2px solid ${noteColor}50`,
                    boxShadow: isActive
                      ? `0 0 30px ${noteColor}80, 0 8px 16px rgba(0, 0, 0, 0.4), inset 0 1px 0 rgba(255,255,255,0.2)`
                      : `0 4px 8px rgba(0, 0, 0, 0.3), inset 0 1px 0 rgba(255,255,255,0.05)`,
                  }}
                >
                  {/* Shine effect on hover */}
                  <div
                    className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                    style={{
                      background: `linear-gradient(135deg, transparent 0%, ${noteColor}40 50%, transparent 100%)`,
                    }}
                  />
                  <span className="relative z-10 text-lg tracking-wide drop-shadow-lg">
                    {displayNote}
                  </span>
                  {isActive && (
                    <div className="absolute top-1 right-1 w-2 h-2 rounded-full bg-white shadow-lg" />
                  )}
                </button>
              );
            })}
            </div>

            {/* Circle of 5ths */}
            <div className="flex-shrink-0 border-l border-[#2a2a2a] pl-6 pr-2">
              <CircleOf5ths
                theme={themes.dark}
                currentKey={activeVerse?.key || 'C'}
                onKeySelect={(key) => {
                  handleKeyChange(key);
                  setShowKeySelector(false);
                }}
                compactMode={false}
                hideControls={true}
                circleSize={400}
                noteCircleScale={1.6}
                previousSectionKey={(() => {
                  const currentIndex = verses.findIndex(v => v.id === activeVerseId);
                  const previousVerse = currentIndex > 0 ? verses[currentIndex - 1] : null;
                  return previousVerse?.key || null;
                })()}
              />
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* History Modal */}
      <Dialog open={showHistoryModal} onOpenChange={setShowHistoryModal}>
        <DialogContent className="bg-[#1a1a1a] border-[#333333] text-white max-w-3xl max-h-[80vh] overflow-hidden flex flex-col">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold flex items-center gap-2">
              <History className="w-5 h-5" />
              Action History Timeline
            </DialogTitle>
            <p className="text-xs text-[#888888] mt-1">
              Click "Restore" to jump to any previous state
            </p>
          </DialogHeader>
          <div className="flex-1 overflow-y-auto pr-2">
            {(() => {
              const undoHistory = getUndoHistory();
              const redoHistory = getRedoHistory();
              const totalHistory = undoHistory.length + redoHistory.length;

              if (totalHistory === 0) {
                return (
                  <div className="flex flex-col items-center justify-center py-12 text-center">
                    <History className="w-12 h-12 text-[#333333] mb-3" />
                    <p className="text-sm text-[#666666]">No actions in history yet</p>
                    <p className="text-xs text-[#444444] mt-1">Make changes to see them here</p>
                  </div>
                );
              }

              // Build unified timeline: redo items (future) + current state + undo items (past)
              const timeline: Array<{
                description: string;
                index: number;
                type: 'undo' | 'redo' | 'current';
                timestamp: number;
              }> = [];

              // Add redo items (future states) - reversed so most recent redo is first
              redoHistory.slice().reverse().forEach((entry, i) => {
                timeline.push({
                  description: entry.description,
                  index: redoHistory.length - 1 - i,
                  type: 'redo',
                  timestamp: entry.timestamp,
                });
              });

              // Add current state marker
              timeline.push({
                description: 'Current State',
                index: -1,
                type: 'current',
                timestamp: Date.now(),
              });

              // Add undo items (past states) - reversed so most recent is first
              undoHistory.slice().reverse().forEach((entry, i) => {
                timeline.push({
                  description: entry.description,
                  index: undoHistory.length - 1 - i,
                  type: 'undo',
                  timestamp: entry.timestamp,
                });
              });

              return (
                <div className="space-y-1.5 py-2">
                  {timeline.map((item, timelineIndex) => {
                    const isCurrent = item.type === 'current';
                    const isRedo = item.type === 'redo';
                    const isUndo = item.type === 'undo';

                    return (
                      <div
                        key={timelineIndex}
                        className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all ${
                          isCurrent
                            ? 'bg-gradient-to-r from-[#3b82f6]/20 to-[#6366f1]/20 border-2 border-[#3b82f6] shadow-lg'
                            : isRedo
                            ? 'bg-[#0a0a0a] border border-[#2a2a2a] hover:border-[#10b981]/50'
                            : 'bg-[#0a0a0a] border border-[#2a2a2a] hover:border-[#3b82f6]/50'
                        }`}
                      >
                        {/* Timeline connector */}
                        <div className="flex flex-col items-center gap-1">
                          {isCurrent ? (
                            <div className="w-3 h-3 rounded-full bg-[#3b82f6] shadow-lg shadow-[#3b82f6]/50" />
                          ) : isRedo ? (
                            <Redo className="w-4 h-4 text-[#10b981]" />
                          ) : (
                            <Undo className="w-4 h-4 text-[#888888]" />
                          )}
                        </div>

                        {/* Description */}
                        <div className="flex-1 min-w-0">
                          <p className={`text-sm font-medium ${isCurrent ? 'text-[#3b82f6]' : 'text-white'}`}>
                            {item.description}
                          </p>
                          {!isCurrent && (
                            <p className="text-xs text-[#666666] mt-0.5">
                              {isRedo ? 'Future state' : 'Past state'} ΓÇó {new Date(item.timestamp).toLocaleTimeString()}
                            </p>
                          )}
                        </div>

                        {/* Restore button */}
                        {!isCurrent && (
                          <Button
                            size="sm"
                            variant="outline"
                            className={`gap-1.5 font-semibold ${
                              isRedo
                                ? 'border-[#10b981] text-[#10b981] hover:bg-[#10b981]/10'
                                : 'border-[#3b82f6] text-[#3b82f6] hover:bg-[#3b82f6]/10'
                            }`}
                            onClick={() => {
                              if (isRedo) {
                                restoreToRedoState(item.index);
                              } else {
                                restoreToUndoState(item.index);
                              }
                              setShowHistoryModal(false);
                              toast({
                                title: 'State Restored',
                                description: `Restored to: ${item.description}`,
                              });
                            }}
                          >
                            {isRedo ? <Redo className="w-3.5 h-3.5" /> : <Undo className="w-3.5 h-3.5" />}
                            Restore
                          </Button>
                        )}
                      </div>
                    );
                  })}
                </div>
              );
            })()}
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

import { useState, useRef, useEffect } from 'react';
import { ChordInstance, InstrumentType } from '@/lib/chord-progression/types';
import { generateChordVoicing, getChordColor } from '@/lib/chord-progression/chord-utils';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Sparkles, Music, BookOpen, Heart, TrendingUp, Play, Loader2, Plus, ChevronDown, ChevronUp } from 'lucide-react';
import ReplaceProgressionModal from './ReplaceProgressionModal';
import { ChordProgressionAudioEngineSmplr } from '@/lib/chord-progression/audio-engine-smplr';
import * as Tone from 'tone';
import { ThemeConfig } from '@/lib/themes';
import RecommendationChordDiagramSidebar from './RecommendationChordDiagramSidebar';

interface ChordProgressionRecommendation {
  id: string;
  progression: string[];
  name: string;
  rationale: string;
  musicTheoryBasis: string;
  mood: string;
  complexity: number;
  isModification?: boolean;
  variationType?: string;
}

interface ChordProgressionRecommendationsProps {
  recommendations: ChordProgressionRecommendation[];
  currentKey: string;
  pixelsPerBeat: number;
  onImplement: (chords: ChordInstance[]) => void;
  isModification: boolean;
  currentProgression?: ChordInstance[];
  onSaveProgression?: (name: string) => Promise<void>;
  selectedInstrument?: InstrumentType;
  complexity?: number;
  length?: number;
  currentScaleModes?: string[];
  theme: ThemeConfig;
  isUpdateMode?: boolean;
}

export default function ChordProgressionRecommendations({
  recommendations,
  currentKey,
  pixelsPerBeat,
  onImplement,
  isModification,
  currentProgression = [],
  onSaveProgression,
  selectedInstrument = 'piano',
  complexity = 5,
  length = 4,
  currentScaleModes = [],
  theme,
  isUpdateMode = false,
}: ChordProgressionRecommendationsProps) {
  const [showReplaceModal, setShowReplaceModal] = useState(false);
  const [pendingChords, setPendingChords] = useState<ChordInstance[] | null>(null);
  const [selectedRecId, setSelectedRecId] = useState<string | null>(null);
  const [previewingId, setPreviewingId] = useState<string | null>(null);
  const [currentPreviewChordIndex, setCurrentPreviewChordIndex] = useState<number>(-1);
  const [isLoadingAdditional, setIsLoadingAdditional] = useState(false);
  const [additionalRecommendations, setAdditionalRecommendations] = useState<ChordProgressionRecommendation[]>([]);
  const [expandedVariations, setExpandedVariations] = useState<{ [key: string]: ChordProgressionRecommendation[] }>({});
  const [loadingVariations, setLoadingVariations] = useState<string | null>(null);
  const [showAdditionalSection, setShowAdditionalSection] = useState(false);
  const [showChordDiagramSidebar, setShowChordDiagramSidebar] = useState(false);
  const [selectedProgressionForDiagrams, setSelectedProgressionForDiagrams] = useState<ChordProgressionRecommendation | null>(null);

  const audioEngineRef = useRef<ChordProgressionAudioEngineSmplr | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Initialize audio engine
  useEffect(() => {
    if (typeof window === 'undefined') return;

    audioContextRef.current = new AudioContext();
    audioEngineRef.current = new ChordProgressionAudioEngineSmplr(audioContextRef.current, {
      instrument: selectedInstrument,
    });

    return () => {
      if (audioEngineRef.current) {
        audioEngineRef.current.stop();
      }
    };
  }, []);

  // Update instrument when it changes
  useEffect(() => {
    if (audioEngineRef.current && selectedInstrument) {
      audioEngineRef.current.setInstrument(selectedInstrument);
    }
  }, [selectedInstrument]);

  if (recommendations.length === 0) {
    return null;
  }

  // Sort recommendations by complexity (highest to lowest)
  const sortedRecommendations = [...recommendations].sort((a, b) => b.complexity - a.complexity);

  const handleImplement = (rec: ChordProgressionRecommendation) => {
    const chordInstances: ChordInstance[] = rec.progression.map((chordSymbol, index) => {
      const voicing = generateChordVoicing(chordSymbol);
      const startTime = index * 4;

      return {
        id: crypto.randomUUID(),
        chordSymbol,
        chordQuality: getChordQuality(chordSymbol),
        notes: voicing,
        rootNote: getRootNote(chordSymbol),
        startTime,
        duration: 4,
        position: startTime * pixelsPerBeat,
        width: 4 * pixelsPerBeat,
        color: getChordColor(chordSymbol),
        voicingIndex: 0,
      };
    });

    // Check if we need to show the replace modal
    const hasExistingProgression = currentProgression.length > 0;
    const isCreatingNew = !isModification;

    if (hasExistingProgression && isCreatingNew) {
      // Show modal to warn about replacing
      setPendingChords(chordInstances);
      setShowReplaceModal(true);
    } else {
      // Directly implement (either modifying or no existing progression)
      onImplement(chordInstances);
    }
  };

  const handleConfirmReplace = () => {
    if (pendingChords) {
      onImplement(pendingChords);
      setPendingChords(null);
    }
    setShowReplaceModal(false);
  };

  const handleSaveAndReplace = async (name: string) => {
    if (onSaveProgression) {
      await onSaveProgression(name);
    }
  };

  const handlePreview = async (rec: ChordProgressionRecommendation) => {
    if (!audioEngineRef.current || !audioContextRef.current) return;

    // Stop if already previewing this one
    if (previewingId === rec.id) {
      audioEngineRef.current.stop();
      setPreviewingId(null);
      setCurrentPreviewChordIndex(-1);
      return;
    }

    // Stop any current preview
    if (previewingId) {
      audioEngineRef.current.stop();
      setCurrentPreviewChordIndex(-1);
    }

    setPreviewingId(rec.id);
    setCurrentPreviewChordIndex(-1);

    try {
      // Create chord instances for preview
      const previewChords: ChordInstance[] = rec.progression.map((chordSymbol, index) => {
        const voicing = generateChordVoicing(chordSymbol);
        const startTime = index * 2; // 2 beats per chord

        return {
          id: crypto.randomUUID(),
          chordSymbol,
          chordQuality: getChordQuality(chordSymbol),
          notes: voicing,
          rootNote: getRootNote(chordSymbol),
          startTime,
          duration: 2, // 2 beats duration
          position: startTime * pixelsPerBeat,
          width: 2 * pixelsPerBeat,
          color: getChordColor(chordSymbol),
          voicingIndex: 0,
        };
      });

      // Check if playPreview method exists (it should after page refresh)
      if (typeof audioEngineRef.current.playPreview === 'function') {
        // Use the new playPreview method that plays chords immediately in sequence
        // This bypasses Transport scheduling and plays chords directly with pauses
        await audioEngineRef.current.playPreview(previewChords, 120);

        // Highlight each chord as it plays
        // Each chord plays for 1.8s with 0.2s pause = 2s total per chord
        for (let i = 0; i < previewChords.length; i++) {
          setTimeout(() => {
            setCurrentPreviewChordIndex(i);
          }, i * 2000);
        }

        // Auto-stop and reset preview state after all chords finish
        const totalDurationMs = previewChords.length * 2000;
        setTimeout(() => {
          setPreviewingId(null);
          setCurrentPreviewChordIndex(-1);
        }, totalDurationMs + 100); // Add small buffer
      } else {
        // Fallback: Recreate audio engine with new code
        console.log('ΓÜá∩╕Å Audio engine needs refresh - recreating...');
        audioEngineRef.current = new ChordProgressionAudioEngineSmplr(audioContextRef.current, {
          instrument: selectedInstrument,
        });

        // Try again with new instance
        await audioEngineRef.current.playPreview(previewChords, 120);

        // Highlight each chord as it plays
        for (let i = 0; i < previewChords.length; i++) {
          setTimeout(() => {
            setCurrentPreviewChordIndex(i);
          }, i * 2000);
        }

        const totalDurationMs = previewChords.length * 2000;
        setTimeout(() => {
          setPreviewingId(null);
          setCurrentPreviewChordIndex(-1);
        }, totalDurationMs + 100);
      }
    } catch (error) {
      console.error('Error previewing progression:', error);
      setPreviewingId(null);
    }
  };

  const handleLoadAdditionalRecommendations = async () => {
    setIsLoadingAdditional(true);
    try {
      const allRecommendations = [...recommendations, ...additionalRecommendations];

      // Use different endpoint based on whether we're in update mode or regular mode
      const endpoint = isUpdateMode
        ? '/api/chord-progression/generate-additional-updates'
        : '/api/chord-progression/generate-additional-recommendations';

      const requestBody = isUpdateMode
        ? {
            currentKey,
            currentProgression: currentProgression.map(c => c.chordSymbol),
            existingUpdates: allRecommendations,
            currentScaleModes,
          }
        : {
            currentKey,
            complexity,
            numChords: length,
            numRecommendations: 4,
            existingRecommendations: allRecommendations,
            currentScaleModes,
          };

      const response = await fetch(endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(requestBody),
      });

      if (!response.ok) {
        throw new Error(`Failed to generate additional ${isUpdateMode ? 'updates' : 'recommendations'}`);
      }

      const data = await response.json();
      setAdditionalRecommendations([...additionalRecommendations, ...data.recommendations]);
      setShowAdditionalSection(true);
    } catch (error) {
      console.error(`Error loading additional ${isUpdateMode ? 'updates' : 'recommendations'}:`, error);
    } finally {
      setIsLoadingAdditional(false);
    }
  };

  const handleLoadSimilarVariations = async (rec: ChordProgressionRecommendation) => {
    setLoadingVariations(rec.id);
    try {
      const response = await fetch('/api/chord-progression/generate-similar-variations', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          currentKey,
          originalProgression: rec.progression,
          originalName: rec.name,
          originalRationale: rec.rationale,
          originalMusicTheoryBasis: rec.musicTheoryBasis,
          numVariations: 4,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to generate similar variations');
      }

      const data = await response.json();
      setExpandedVariations({
        ...expandedVariations,
        [rec.id]: data.variations,
      });
    } catch (error) {
      console.error('Error loading similar variations:', error);
    } finally {
      setLoadingVariations(null);
    }
  };

  const getComplexityColor = (complexity: number): string => {
    if (complexity >= 8) return '#ef4444'; // Red - Very Complex
    if (complexity >= 6) return '#f59e0b'; // Orange - Moderate
    if (complexity >= 4) return '#3b82f6'; // Blue - Balanced
    return '#10b981'; // Green - Simple
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-2 pb-2 border-b border-[#333333]">
        <Sparkles className="w-5 h-5 text-[#8b5cf6]" />
        <h3 className="text-lg font-semibold text-[#e0e0e0]">
          {isUpdateMode ? 'Recommended Chord Updates' : 'Recommended Chord Progressions'}
        </h3>
        <span className="text-sm text-[#666666] ml-auto">
          {recommendations.length} {recommendations.length === 1 ? 'recommendation' : 'recommendations'}
        </span>
      </div>

      {/* Grid of Recommendation Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {sortedRecommendations.map((rec) => {
          const isSelected = selectedRecId === rec.id;

          return (
            <div
              key={rec.id}
              onClick={() => setSelectedRecId(rec.id)}
              className="bg-[#1a1a1a] border-2 rounded-xl p-5 cursor-pointer transition-all duration-300 hover:shadow-xl"
              style={{
                borderColor: isSelected ? '#3b82f6' : '#333333',
                transform: isSelected ? 'translateY(-4px)' : 'translateY(0)',
                boxShadow: isSelected
                  ? '0 8px 24px rgba(59, 130, 246, 0.3)'
                  : '0 2px 8px rgba(0, 0, 0, 0.2)',
              }}
            >
              {/* Card Header */}
              <div className="flex items-start justify-between mb-4">
                <div className="flex-1">
                  <h4 className="text-base font-bold text-[#e0e0e0] mb-2 line-clamp-2">
                    {rec.name}
                  </h4>
                  <div className="flex flex-wrap gap-1.5">
                    <Badge
                      className="text-xs px-2 py-0.5"
                      style={{
                        backgroundColor: '#8b5cf6',
                        color: 'white',
                      }}
                    >
                      <Heart className="w-3 h-3 mr-1" />
                      {rec.mood}
                    </Badge>
                    <Badge
                      className="text-xs px-2 py-0.5"
                      style={{
                        backgroundColor: getComplexityColor(rec.complexity),
                        color: 'white',
                      }}
                    >
                      <TrendingUp className="w-3 h-3 mr-1" />
                      {rec.complexity}/10
                    </Badge>
                  </div>
                </div>
              </div>

              {/* Chord Progression */}
              <div className="flex flex-wrap gap-1.5 mb-4 pb-4 border-b border-[#2a2a2a]">
                {rec.progression.map((chord, idx) => {
                  const isCurrentlyPlaying = previewingId === rec.id && currentPreviewChordIndex === idx;
                  return (
                    <div key={idx} className="flex items-center gap-1">
                      <Badge
                        className="text-white text-sm px-2.5 py-1 font-semibold transition-all duration-300"
                        style={{
                          backgroundColor: isCurrentlyPlaying ? '#22c55e' : '#3b82f6',
                          boxShadow: isCurrentlyPlaying ? '0 0 20px rgba(34, 197, 94, 0.6)' : 'none',
                          transform: isCurrentlyPlaying ? 'scale(1.1)' : 'scale(1)',
                        }}
                      >
                        {chord}
                      </Badge>
                      {idx < rec.progression.length - 1 && (
                        <span className="text-[#555555] text-xs">ΓåÆ</span>
                      )}
                    </div>
                  );
                })}
              </div>

              {/* Rationale */}
              <div className="space-y-2 mb-3">
                <div className="flex items-center gap-1.5 text-[#e0e0e0] text-xs font-semibold">
                  <Music className="w-3.5 h-3.5 text-[#3b82f6]" />
                  Why This Works
                </div>
                <p className="text-[#a0a0a0] text-xs leading-relaxed line-clamp-3">
                  {rec.rationale}
                </p>
              </div>

              {/* Music Theory Basis */}
              <div className="space-y-2 mb-4">
                <div className="flex items-center gap-1.5 text-[#e0e0e0] text-xs font-semibold">
                  <BookOpen className="w-3.5 h-3.5 text-[#8b5cf6]" />
                  Music Theory
                </div>
                <p className="text-[#a0a0a0] text-xs leading-relaxed line-clamp-3">
                  {rec.musicTheoryBasis}
                </p>
              </div>

              {/* Action Buttons */}
              <div className="space-y-2">
                {/* Preview and Add to Timeline buttons */}
                <div className="flex items-center gap-2">
                  <Button
                    onClick={(e) => {
                      e.stopPropagation();
                      handlePreview(rec);
                    }}
                    variant="outline"
                    className="flex-1 border-[#3b82f6] text-[#3b82f6] hover:bg-[#3b82f6]/10 text-xs font-medium"
                    size="sm"
                    disabled={previewingId !== null && previewingId !== rec.id}
                  >
                    {previewingId === rec.id ? (
                      <>
                        <Loader2 className="w-3 h-3 mr-1 animate-spin" />
                        Playing...
                      </>
                    ) : (
                      <>
                        <Play className="w-3 h-3 mr-1" />
                        Preview
                      </>
                    )}
                  </Button>
                  <Button
                    onClick={(e) => {
                      e.stopPropagation();
                      handleImplement(rec);
                    }}
                    className="flex-1 bg-gradient-to-r from-[#3b82f6] to-[#8b5cf6] hover:from-[#2563eb] hover:to-[#7c3aed] text-white text-xs font-medium shadow-lg"
                    size="sm"
                  >
                    {isModification ? 'Apply' : 'Add to Timeline'}
                  </Button>
                </div>

                {/* Show Chords and Similar Variations buttons */}
                <div className="flex items-center gap-2">
                  <Button
                    onClick={(e) => {
                      e.stopPropagation();
                      setSelectedProgressionForDiagrams(rec);
                      setShowChordDiagramSidebar(true);
                    }}
                    variant="ghost"
                    className="flex-1 text-[#3b82f6] hover:bg-[#3b82f6]/10 text-xs"
                    size="sm"
                  >
                    <Music className="w-3 h-3 mr-1" />
                    Show Chords
                  </Button>
                  <Button
                    onClick={(e) => {
                      e.stopPropagation();
                      if (expandedVariations[rec.id]) {
                        // Collapse variations
                        const newVariations = { ...expandedVariations };
                        delete newVariations[rec.id];
                        setExpandedVariations(newVariations);
                      } else {
                        // Load variations
                        handleLoadSimilarVariations(rec);
                      }
                    }}
                    variant="ghost"
                    className="flex-1 text-[#8b5cf6] hover:bg-[#8b5cf6]/10 text-xs"
                    size="sm"
                    disabled={loadingVariations === rec.id}
                  >
                    {loadingVariations === rec.id ? (
                      <>
                        <Loader2 className="w-3 h-3 mr-1 animate-spin" />
                        Loading...
                      </>
                    ) : expandedVariations[rec.id] ? (
                      <>
                        <ChevronUp className="w-3 h-3 mr-1" />
                        Hide Variations
                      </>
                    ) : (
                      <>
                        <Sparkles className="w-3 h-3 mr-1" />
                        Show Variations
                      </>
                    )}
                  </Button>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Similar Variations Section */}
      {Object.entries(expandedVariations).map(([recId, variations]) => {
        const originalRec = [...recommendations, ...additionalRecommendations].find(r => r.id === recId);
        if (!originalRec || variations.length === 0) return null;

        return (
          <div key={`variations-${recId}`} className="space-y-4 mt-6 p-4 bg-[#0f0f0f] rounded-xl border border-[#333333]">
            <div className="flex items-center gap-2 pb-2 border-b border-[#2a2a2a]">
              <Sparkles className="w-4 h-4 text-[#8b5cf6]" />
              <h4 className="text-sm font-semibold text-[#e0e0e0]">
                Similar Variations of "{originalRec.name}"
              </h4>
              <Badge className="text-xs bg-[#8b5cf6]/20 text-[#8b5cf6] border border-[#8b5cf6]/30">
                {variations.length} variations
              </Badge>
            </div>

            {/* Original Progression Reference */}
            <div className="p-3 bg-[#1a1a1a] rounded-lg border border-[#2a2a2a]">
              <div className="text-xs text-[#888888] mb-1">Original:</div>
              <div className="flex flex-wrap gap-1.5">
                {originalRec.progression.map((chord, idx) => (
                  <div key={idx} className="flex items-center gap-1">
                    <Badge className="bg-[#3b82f6]/30 text-[#3b82f6] text-xs px-2 py-0.5 font-semibold border border-[#3b82f6]/50">
                      {chord}
                    </Badge>
                    {idx < originalRec.progression.length - 1 && (
                      <span className="text-[#555555] text-xs">ΓåÆ</span>
                    )}
