'use client';

/**
 * Play Song Panel - Dual fretboard system with triads and CAGED integration
 */

import { useState, useEffect, useMemo } from 'react';
import { ChordInstance, ScaleModeInstance } from '@/lib/chord-progression/types';
import { ThemeConfig } from '@/lib/themes';
import { TriadPosition } from '@/lib/triad-positions';
import { ChordVoicing } from '@/lib/chord-voicings';
import { getCurrentChordAndScale, getTriadPositionsForChord } from '@/lib/chord-progression/song-progression-utils';
import DualFretboardDisplay from './DualFretboardDisplay';
import SongChordDiagramSidebar from './SongChordDiagramSidebar';
import SongOverlappingChordsSidebar from './SongOverlappingChordsSidebar';

interface PlaySongPanelProps {
  currentChords: ChordInstance[];
  currentScales: ScaleModeInstance[];
  currentKey: string;
  isPlaying: boolean;
  currentTime: number;
  tuning: string[];
  stringCount: 6 | 7;
  theme: ThemeConfig;
  showColorfulStrings?: boolean;
  onShowColorfulStringsChange?: (enabled: boolean) => void;
  stringBrightness?: number;
  onStringBrightnessChange?: (brightness: number) => void;
  onGenerateProgression?: () => void;
}

export default function PlaySongPanel({
  currentChords,
  currentScales,
  currentKey,
  isPlaying,
  currentTime,
  tuning,
  stringCount,
  theme,
  showColorfulStrings = false,
  onShowColorfulStringsChange,
  stringBrightness = 100,
  onStringBrightnessChange,
  onGenerateProgression,
}: PlaySongPanelProps) {
  // State for selected chord from progression
  const [selectedChordIndex, setSelectedChordIndex] = useState<number>(0);

  // State for selected triad position
  const [selectedTriadPosition, setSelectedTriadPosition] = useState<TriadPosition | null>(null);

  // State for custom voicings (per chord)
  const [customVoicings, setCustomVoicings] = useState<Map<string, ChordVoicing>>(new Map());

  // State for CAGED guide
  const [showCAGEDGuide, setShowCAGEDGuide] = useState<boolean>(true);
  const [selectedCAGEDShapes, setSelectedCAGEDShapes] = useState<string[]>(['C', 'A', 'G', 'E', 'D']);

  // State for CAGED zone navigation
  const [currentCAGEDZone, setCurrentCAGEDZone] = useState<string>('E'); // Default to E shape
  const CAGED_SHAPES = ['C', 'A', 'G', 'E', 'D'] as const;

  // State for position navigation (like triads & CAGED screen)
  const [allTriadPositions, setAllTriadPositions] = useState<TriadPosition[]>([]);
  const [currentPositionIndex, setCurrentPositionIndex] = useState<number>(0);

  // State for unified chord diagram sidebar
  const [showChordDiagramSidebar, setShowChordDiagramSidebar] = useState<boolean>(false);
  const [sidebarActiveTab, setSidebarActiveTab] = useState<'triads' | 'chords' | 'overlapping'>('triads');

  // State for visible scale notes from 2nd fretboard (for overlapping chords)
  const [visibleScaleNotes, setVisibleScaleNotes] = useState<string[]>([]);

  // State for allowed chords from chord progression (for overlapping chords)
  const [allowedChords, setAllowedChords] = useState<Array<{ rootNote: string; chordQuality: string }>>([]);

  // Get current chord and scale based on playback time
  const { chord: currentChord, scale: currentScale } = useMemo(() => {
    return getCurrentChordAndScale(currentChords, currentScales, currentTime);
  }, [currentChords, currentScales, currentTime]);

  // Update selected chord index when playback changes
  useEffect(() => {
    if (isPlaying && currentChord) {
      const index = currentChords.findIndex(c => c.id === currentChord.id);
      if (index !== -1) {
        setSelectedChordIndex(index);
      }
    }
  }, [isPlaying, currentChord, currentChords]);

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Only handle if not typing in an input
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) {
        return;
      }

      switch (e.key) {
        case 'ArrowLeft':
          e.preventDefault();
          setSelectedChordIndex(prev => Math.max(0, prev - 1));
          setSelectedTriadPosition(null);
          break;
        case 'ArrowRight':
          e.preventDefault();
          setSelectedChordIndex(prev => Math.min(currentChords.length - 1, prev + 1));
          setSelectedTriadPosition(null);
          break;
        case 'Home':
          e.preventDefault();
          setSelectedChordIndex(0);
          setSelectedTriadPosition(null);
          break;
        case 'End':
          e.preventDefault();
          setSelectedChordIndex(currentChords.length - 1);
          setSelectedTriadPosition(null);
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentChords.length]);

  // Get selected chord (either from user selection or playback)
  const selectedChord = useMemo(() => {
    if (isPlaying && currentChord) {
      return currentChord;
    }
    return currentChords[selectedChordIndex] || null;
  }, [isPlaying, currentChord, currentChords, selectedChordIndex]);

  // Get selected scale (either from user selection or playback)
  const selectedScale = useMemo(() => {
    if (isPlaying && currentScale) {
      return currentScale;
    }
    // Find scale matching selected chord
    const chordStartTime = selectedChord?.startTime || 0;
    return currentScales.find(scale =>
      chordStartTime >= scale.startTime &&
      chordStartTime < scale.startTime + scale.duration
    ) || null;
  }, [isPlaying, currentScale, currentScales, selectedChord]);

  // Handle chord selection from progression
  const handleChordSelect = (index: number) => {
    setSelectedChordIndex(index);
    setSelectedTriadPosition(null); // Reset triad position when changing chords
  };

  // Handle voicing change from voicing selector
  const handleVoicingChange = (chordIndex: number, voicing: ChordVoicing) => {
    const chord = currentChords[chordIndex];
    if (chord) {
      const newVoicings = new Map(customVoicings);
      newVoicings.set(chord.id, voicing);
      setCustomVoicings(newVoicings);
    }
  };

  // Handle triad position selection
  const handleTriadPositionSelect = (position: TriadPosition, allPositions: TriadPosition[]) => {
    setSelectedTriadPosition(position);
    // Update current zone to match selected position
    if (position.cagedShape) {
      setCurrentCAGEDZone(position.cagedShape);
    }

    // Store all positions and find the index of the selected position
    setAllTriadPositions(allPositions);
    const index = allPositions.findIndex(p =>
      p.fretPosition === position.fretPosition &&
      p.stringPositions.every((sp, i) =>
        sp.stringIndex === position.stringPositions[i]?.stringIndex &&
        sp.fret === position.stringPositions[i]?.fret
      )
    );
    setCurrentPositionIndex(index >= 0 ? index : 0);
  };

  // Handle position navigation (like triads & CAGED screen)
  const handleNavigatePrevious = () => {
    if (allTriadPositions.length === 0) return;

    const newIndex = currentPositionIndex <= 0
      ? allTriadPositions.length - 1
      : currentPositionIndex - 1;

    setCurrentPositionIndex(newIndex);
    const newPosition = allTriadPositions[newIndex];
    setSelectedTriadPosition(newPosition);

    // Update CAGED zone to match new position
    if (newPosition.cagedShape) {
      setCurrentCAGEDZone(newPosition.cagedShape);
    }
  };

  const handleNavigateNext = () => {
    if (allTriadPositions.length === 0) return;

    const newIndex = currentPositionIndex >= allTriadPositions.length - 1
      ? 0
      : currentPositionIndex + 1;

    setCurrentPositionIndex(newIndex);
    const newPosition = allTriadPositions[newIndex];
    setSelectedTriadPosition(newPosition);

    // Update CAGED zone to match new position
    if (newPosition.cagedShape) {
      setCurrentCAGEDZone(newPosition.cagedShape);
    }
  };

  // Get custom voicing for selected chord
  const customVoicing = useMemo(() => {
    if (!selectedChord) return undefined;
    return customVoicings.get(selectedChord.id);
  }, [selectedChord, customVoicings]);

  // Filter chords that are playable in the current CAGED zone
  const chordsInZone = useMemo(() => {
    return currentChords.map(chord => {
      const positions = getTriadPositionsForChord(chord, 24, undefined);
      const positionsInZone = positions.filter(pos => pos.cagedShape === currentCAGEDZone);

      return {
        chord,
        isPlayableInZone: positionsInZone.length > 0,
        positionsInZone,
        allPositions: positions, // Include all positions for reference
      };
    });
  }, [currentChords, currentCAGEDZone]);

  // Handle empty chord progression
  if (currentChords.length === 0) {
    return (
      <div className="h-full flex items-center justify-center p-6">
        <div
          className="text-center p-12 rounded-lg border-2 border-dashed"
          style={{
            borderColor: theme.border,
            backgroundColor: theme.bgPrimary + '40'
          }}
        >
          <div className="text-6xl mb-4">≡ƒÄ╕</div>
          <h3 className="text-xl font-bold mb-2" style={{ color: theme.textPrimary }}>
            No Chord Progression
          </h3>
          <p className="text-sm mb-4" style={{ color: theme.textSecondary }}>
            Create a chord progression in the "Chord Progressions" tab to get started
          </p>
          <p className="text-xs" style={{ color: theme.textSecondary }}>
            Keyboard shortcuts: ΓåÉ ΓåÆ to navigate chords
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full flex overflow-hidden relative">
      {/* Main Content Area */}
      <div className="flex-1 overflow-auto p-6">
        {/* Dual Fretboard Display */}
        <DualFretboardDisplay
          selectedChord={selectedChord}
          selectedScale={selectedScale}
          selectedTriadPosition={selectedTriadPosition}
          onTriadPositionSelect={handleTriadPositionSelect}
          customVoicing={customVoicing}
          theme={theme}
          tuning={tuning}
          stringCount={stringCount}
          showCAGEDGuide={showCAGEDGuide}
          selectedCAGEDShapes={selectedCAGEDShapes}
          currentKey={currentKey}
          currentCAGEDZone={currentCAGEDZone}
          onNavigatePrevious={handleNavigatePrevious}
          onNavigateNext={handleNavigateNext}
          allChords={currentChords}
          selectedChordIndex={selectedChordIndex}
          onChordSelect={handleChordSelect}
          onVoicingChange={handleVoicingChange}
          customVoicings={customVoicings}
          currentTime={currentTime}
          isPlaying={isPlaying}
          onShowChordDiagrams={() => {
            setSidebarActiveTab('triads');
            setShowChordDiagramSidebar(true);
          }}
          onGenerateProgression={onGenerateProgression}
          showColorfulStrings={showColorfulStrings}
          stringBrightness={stringBrightness}
          onFilteredScaleNotesChange={setVisibleScaleNotes}
          onAllowedChordsChange={setAllowedChords}
        />
      </div>

      {/* Unified Chord Diagram Sidebar with Tabs */}
      <SongChordDiagramSidebar
        theme={theme}
        chordsInZone={chordsInZone}
        selectedTriadPosition={selectedTriadPosition}
        isVisible={showChordDiagramSidebar}
        onClose={() => setShowChordDiagramSidebar(false)}
        tuning={tuning}
        stringCount={stringCount}
        onNavigatePrevious={handleNavigatePrevious}
        onNavigateNext={handleNavigateNext}
        visibleScaleNotes={visibleScaleNotes}
        allowedChords={allowedChords}
        activeTab={sidebarActiveTab}
        onTabChange={setSidebarActiveTab}
      />
    </div>
  );
}

'use client';

import { useMemo, useState } from 'react';
import { ThemeConfig } from '@/lib/themes';
import { X, Music } from 'lucide-react';
import ChordDiagram from '@/components/ChordDiagram';
import { ChordVoicing } from '@/lib/chord-voicings';
import { NOTE_COLORS } from '@/lib/musicTheory';
import { generateChordVoicing, parseChordSymbol } from '@/lib/chord-progression/chord-utils';
import { getStandardChordVoicings } from '@/lib/chord-database';

interface ChordProgressionRecommendation {
  id: string;
  progression: string[];
  name: string;
  rationale: string;
  musicTheoryBasis: string;
  mood: string;
  complexity: number;
}

interface RecommendationChordDiagramSidebarProps {
  theme: ThemeConfig;
  progression: ChordProgressionRecommendation | null;
  isVisible?: boolean;
  onClose?: () => void;
  tuning?: string[];
  stringCount?: number;
  maxFret?: number; // Maximum fret to show voicings for (default 24)
}

export default function RecommendationChordDiagramSidebar({
  theme,
  progression,
  isVisible = true,
  onClose,
  tuning = ['E', 'A', 'D', 'G', 'B', 'E'],
  stringCount = 6,
  maxFret = 24, // Default to 24 frets to include octave positions
}: RecommendationChordDiagramSidebarProps) {
  // State for selected chord and position
  const [selectedChordIndex, setSelectedChordIndex] = useState<number | null>(null);
  const [selectedPositionTab, setSelectedPositionTab] = useState<string>('all');

  // Helper function to organize voicings by fret position
  const organizeVoicingsByPosition = (voicings: ChordVoicing[]) => {
    // Group voicings by approximate fret position (in groups of 3 frets)
    const positionGroups: { [key: string]: ChordVoicing[] } = {};

    voicings.forEach(voicing => {
      // Only include voicings within the max fret range
      if (voicing.startFret > maxFret) return;

      const positionKey = Math.floor(voicing.startFret / 3);
      const positionName = voicing.startFret === 0
        ? 'Open'
        : `Fret ${positionKey * 3}-${(positionKey + 1) * 3}`;

      if (!positionGroups[positionName]) {
        positionGroups[positionName] = [];
      }
      positionGroups[positionName].push(voicing);
    });

    return Object.entries(positionGroups).map(([name, voicings]) => ({
      name,
      voicings: voicings.sort((a, b) => a.startFret - b.startFret),
    }));
  };

  // Calculate chord voicings organized by fret positions
  const chordVoicingsData = useMemo(() => {
    if (!progression) return [];

    return progression.progression.map((chordSymbol) => {
      const { rootNote, quality } = parseChordSymbol(chordSymbol);
      const chordNotes = generateChordVoicing(chordSymbol);

      // Get all standard voicings from the database
      const allVoicings = getStandardChordVoicings(rootNote, quality, tuning);

      // Organize voicings by fret position
      const positionGroups = organizeVoicingsByPosition(allVoicings);

      return {
        chordSymbol,
        chordNotes,
        rootNote,
        quality,
        allVoicings,
        positionGroups,
      };
    });
  }, [progression, tuning]);

  // Get the currently selected chord's voicing data
  const selectedChordData = useMemo(() => {
    if (selectedChordIndex === null || !chordVoicingsData[selectedChordIndex]) {
      return null;
    }
    return chordVoicingsData[selectedChordIndex];
  }, [selectedChordIndex, chordVoicingsData]);

  // Get voicings for the selected position tab
  const displayedVoicings = useMemo(() => {
    if (!selectedChordData) return [];

    if (selectedPositionTab === 'all') {
      // Show all voicings (limit to first 8 for performance)
      return selectedChordData.allVoicings.slice(0, 8);
    } else {
      // Show voicings for specific position group
      const positionGroup = selectedChordData.positionGroups.find(
        g => g.name === selectedPositionTab
      );
      return positionGroup?.voicings || [];
    }
  }, [selectedChordData, selectedPositionTab]);

  if (!isVisible || !progression) return null;

  return (
    <div
      className="fixed right-0 flex flex-col shadow-2xl"
      style={{
        width: '420px',
        top: '64px', // Start immediately below header (h-16 = 64px)
        bottom: '48px', // End above playback controls (h-12 = 48px)
        height: 'auto', // Let top and bottom define the height
        background: 'linear-gradient(to bottom, #1a1a1a, #0f0f0f)',
        borderLeft: `2px solid ${theme.border}`,
        zIndex: 'var(--cpb-z-right-sidebar)',
      }}
    >
      {/* Header */}
      <div
        className="flex items-center justify-between p-4 border-b"
        style={{ borderColor: theme.border }}
      >
        <div className="flex items-center gap-2">
          <Music className="w-5 h-5" style={{ color: theme.accentPrimary }} />
          <h3 className="text-base font-bold" style={{ color: theme.textPrimary }}>
            Chord Diagrams
          </h3>
        </div>
        {onClose && (
          <button
            onClick={onClose}
            className="p-1.5 rounded hover:bg-opacity-80 transition-all"
            style={{
              color: theme.textSecondary,
              background: theme.bgTertiary,
            }}
            title="Close sidebar"
          >
            <X className="w-4 h-4" />
          </button>
        )}
      </div>

      {/* Progression Name */}
      <div className="px-4 py-3 border-b" style={{ borderColor: theme.border }}>
        <h4 className="text-sm font-semibold" style={{ color: theme.textPrimary }}>
          {progression.name}
        </h4>
        <p className="text-xs mt-1" style={{ color: theme.textSecondary }}>
          {progression.progression.join(' ΓåÆ ')}
        </p>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-y-auto">
        {chordVoicingsData.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full p-4">
            <Music className="w-12 h-12 mb-3" style={{ color: theme.textSecondary }} />
            <p className="text-sm text-center" style={{ color: theme.textSecondary }}>
              No chord diagrams available
            </p>
          </div>
        ) : selectedChordIndex === null ? (
          /* Chord Selection Grid - Initial View */
          <div className="p-4">
            <p className="text-xs mb-3" style={{ color: theme.textSecondary }}>
              Select a chord to view all positions:
            </p>
            <div className="grid grid-cols-2 gap-4">
              {chordVoicingsData.map((data, index) => {
                const chordColor = NOTE_COLORS[data.rootNote] || '#6b7280';
                const firstVoicing = data.allVoicings[0];

                return (
                  <button
                    key={`chord-${index}`}
                    onClick={() => {
                      setSelectedChordIndex(index);
                      setSelectedPositionTab('all');
                    }}
                    className="rounded-lg p-4 flex flex-col items-center gap-2 overflow-hidden hover:opacity-80 transition-opacity cursor-pointer"
                    style={{
                      background: theme.bgTertiary,
                      border: `1px solid ${theme.border}`,
                    }}
                  >
                    {/* Chord Symbol */}
                    <div
                      className="w-full rounded-lg px-3 py-2 flex items-center justify-center gap-2"
                      style={{
                        background: chordColor,
                        boxShadow: `0 0 8px ${chordColor}66`,
                      }}
                    >
                      <span className="text-sm font-bold text-white">
                        {data.chordSymbol}
                      </span>
                    </div>

                    {/* Chord Diagram Preview */}
                    {firstVoicing ? (
                      <ChordDiagram
                        voicing={firstVoicing}
                        theme={theme}
                        stringCount={stringCount}
                        compact={true}
                      />
                    ) : (
                      <div className="text-xs text-center py-4" style={{ color: theme.textSecondary }}>
                        No voicing available
                      </div>
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        ) : (
          /* Position Tabs and Diagrams - Detail View */
          <div className="flex flex-col h-full">
            {/* Back Button and Chord Title */}
            <div className="px-4 py-3 border-b" style={{ borderColor: theme.border }}>
              <button
                onClick={() => {
                  setSelectedChordIndex(null);
                  setSelectedPositionTab('all');
                }}
                className="px-3 py-2 rounded-lg mb-3 text-sm font-medium hover:opacity-90 transition-all flex items-center gap-2"
                style={{
                  background: theme.bgTertiary,
                  color: theme.accentPrimary,
                  border: `1px solid ${theme.border}`,
                }}
              >
                <span>ΓåÉ</span>
                <span>Back to all chords</span>
              </button>
              <h4 className="text-sm font-semibold" style={{ color: theme.textPrimary }}>
                {selectedChordData?.chordSymbol} - All Positions
              </h4>
            </div>

            {/* Position Tabs - Multi-row Grid Layout */}
            <div className="px-4 py-3 border-b" style={{ borderColor: theme.border }}>
              <div className="grid grid-cols-3 gap-2">
                {/* All Positions Tab */}
                <button
                  onClick={() => setSelectedPositionTab('all')}
                  className="px-3 py-2 rounded text-xs font-medium transition-all"
                  style={{
                    background: selectedPositionTab === 'all' ? theme.accentPrimary : theme.bgTertiary,
                    color: selectedPositionTab === 'all' ? '#ffffff' : theme.textSecondary,
                    border: `1px solid ${selectedPositionTab === 'all' ? theme.accentPrimary : theme.border}`,
                  }}
                >
                  All ({selectedChordData?.allVoicings.length || 0})
                </button>

                {/* Position Group Tabs */}
                {selectedChordData?.positionGroups.map((positionGroup) => (
                  <button
                    key={positionGroup.name}
                    onClick={() => setSelectedPositionTab(positionGroup.name)}
                    className="px-3 py-2 rounded text-xs font-medium transition-all"
                    style={{
                      background: selectedPositionTab === positionGroup.name ? theme.accentPrimary : theme.bgTertiary,
                      color: selectedPositionTab === positionGroup.name ? '#ffffff' : theme.textSecondary,
                      border: `1px solid ${selectedPositionTab === positionGroup.name ? theme.accentPrimary : theme.border}`,
                    }}
                  >
                    {positionGroup.name} ({positionGroup.voicings.length})
                  </button>
                ))}
              </div>
            </div>

            {/* Chord Diagrams for Selected Position */}
            <div className="flex-1 overflow-y-auto p-4">
              {displayedVoicings.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full">
                  <Music className="w-12 h-12 mb-3" style={{ color: theme.textSecondary }} />
                  <p className="text-sm text-center" style={{ color: theme.textSecondary }}>
                    No voicings available for this position
                  </p>
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-4">
                  {displayedVoicings.map((voicing, index) => {
                    const chordColor = NOTE_COLORS[selectedChordData?.rootNote || ''] || '#6b7280';

                    return (
                      <div
                        key={`voicing-${index}`}
                        className="rounded-lg p-4 flex flex-col items-center gap-2 overflow-hidden"
                        style={{
                          background: theme.bgTertiary,
                          border: `1px solid ${theme.border}`,
                        }}
                      >
                        {/* Position Label */}
                        <div
                          className="w-full rounded-lg px-2 py-1 text-center"
                          style={{
                            background: chordColor + '33',
                            border: `1px solid ${chordColor}66`,
                          }}
                        >
                          <span className="text-xs font-medium" style={{ color: theme.textPrimary }}>
                            {voicing.commonName || `Fret ${voicing.startFret}`}
                          </span>
                        </div>

                        {/* Chord Diagram */}
                        <ChordDiagram
                          voicing={voicing}
                          theme={theme}
                          stringCount={stringCount}
                          compact={true}
                        />
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

/**
 * MIDI Configuration Modal
 * Allows users to configure MIDI pedal buttons and assign functions
 */

import React, { useState, useEffect } from 'react';
import { X, RefreshCw, Save, RotateCcw, Zap, Trash2, Plus, AlertCircle, Download, Upload } from 'lucide-react';
import { ThemeConfig } from '@/lib/themes';
import { useMIDIPedal } from './MIDIContext';
import { MIDIButtonConfig, MIDI_ACTION_LABELS, MIDIButtonAction, MIDIProfile } from '@/lib/midi/midiTypes';
import { isMIDISupported, getAvailableActionsForButton } from '@/lib/midi/midiUtils';

interface MIDIConfigModalProps {
  isOpen: boolean;
  onClose: () => void;
  theme: ThemeConfig;
}

export default function MIDIConfigModal({ isOpen, onClose, theme }: MIDIConfigModalProps) {
  const {
    config,
    availableDevices,
    selectedDevice,
    isLearning,
    learningButtonId,
    lastMIDIMessage,
    updateConfig,
    selectDevice,
    startLearning,
    stopLearning,
    resetConfig,
    saveConfig,
    clearAllButtons,
  } = useMIDIPedal();

  const [localConfig, setLocalConfig] = useState(config);
  const [hasChanges, setHasChanges] = useState(false);
  const [profiles, setProfiles] = useState<MIDIProfile[]>([]);
  const [profileName, setProfileName] = useState('');
  const [selectedProfileId, setSelectedProfileId] = useState<string | null>(null);
  const [isSavingProfile, setIsSavingProfile] = useState(false);
  const [isLoadingProfiles, setIsLoadingProfiles] = useState(false);

  // Sync local config with context config
  useEffect(() => {
    setLocalConfig(config);
  }, [config]);

  // Check for changes
  useEffect(() => {
    const changed = JSON.stringify(localConfig) !== JSON.stringify(config);
    setHasChanges(changed);
  }, [localConfig, config]);

  // Load profiles when device changes
  useEffect(() => {
    if (selectedDevice?.name) {
      loadProfiles();
    }
  }, [selectedDevice?.name]);

  // Load profiles from API
  const loadProfiles = async () => {
    if (!selectedDevice?.name) return;

    setIsLoadingProfiles(true);
    try {
      const response = await fetch(`/api/midi/profiles?deviceName=${encodeURIComponent(selectedDevice.name)}`);
      if (response.ok) {
        const data = await response.json();
        setProfiles(data.profiles || []);
      }
    } catch (error) {
      console.error('Error loading profiles:', error);
    } finally {
      setIsLoadingProfiles(false);
    }
  };

  // Save current configuration as a profile
  const handleSaveProfile = async () => {
    if (!profileName.trim() || !selectedDevice?.name) return;

    setIsSavingProfile(true);
    try {
      const response = await fetch('/api/midi/profiles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name: profileName.trim(),
          deviceName: selectedDevice.name,
          config: localConfig,
        }),
      });

      if (response.ok) {
        setProfileName('');
        await loadProfiles();
        alert('Profile saved successfully!');
      } else {
        alert('Failed to save profile');
      }
    } catch (error) {
      console.error('Error saving profile:', error);
      alert('Error saving profile');
    } finally {
      setIsSavingProfile(false);
    }
  };

  // Load a profile
  const handleLoadProfile = async (profileId: string) => {
    const profile = profiles.find(p => p.id === profileId);
    if (!profile) return;

    setLocalConfig(profile.config);
    setSelectedProfileId(profileId);
  };

  // Delete a profile
  const handleDeleteProfile = async (profileId: string) => {
    if (!confirm('Delete this profile?')) return;

    try {
      const response = await fetch(`/api/midi/profiles?id=${profileId}`, {
        method: 'DELETE',
      });

      if (response.ok) {
        await loadProfiles();
        if (selectedProfileId === profileId) {
          setSelectedProfileId(null);
        }
      } else {
        alert('Failed to delete profile');
      }
    } catch (error) {
      console.error('Error deleting profile:', error);
      alert('Error deleting profile');
    }
  };

  if (!isOpen) return null;

  const handleDeviceChange = (deviceId: string) => {
    selectDevice(deviceId);
  };

  const handleButtonActionChange = (buttonId: string, action: MIDIButtonAction) => {
    setLocalConfig(prev => ({
      ...prev,
      buttons: prev.buttons.map(btn =>
        btn.id === buttonId ? { ...btn, action } : btn
      ),
    }));
  };

  const handleLearnButton = (action: MIDIButtonAction) => {
    if (isLearning && learningButtonId === action) {
      stopLearning();
    } else {
      // Use the action as the learning ID
      startLearning(action);
    }
  };

  const handleSave = async () => {
    // Ensure enabled is true if we have a device and buttons assigned
    const configToSave = {
      ...localConfig,
      enabled: selectedDevice ? true : localConfig.enabled,
    };

    console.log('[MIDI Config] Saving configuration:', configToSave);

    // updateConfig already calls saveMIDIConfig internally (saves to localStorage)
    updateConfig(configToSave);

    // Save to server (midi.json) as the active configuration
    try {
      const response = await fetch('/api/midi/config', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          config: configToSave,
        }),
      });

      if (response.ok) {
        console.log('[MIDI Config] Successfully saved to server');
      } else {
        console.error('[MIDI Config] Failed to save to server');
      }
    } catch (error) {
      console.error('[MIDI Config] Error saving to server:', error);
    }

    // Also update the profile if one is selected
    if (selectedProfileId && selectedDevice?.name) {
      try {
        await fetch('/api/midi/profiles', {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            id: selectedProfileId,
            config: configToSave,
          }),
        });
      } catch (error) {
        console.error('[MIDI Config] Error updating profile:', error);
      }
    }

    onClose();
  };

  const handleReset = () => {
    if (confirm('Are you sure you want to reset all MIDI configuration to defaults?')) {
      resetConfig();
      setLocalConfig(config);
    }
  };

  const handleCancel = () => {
    if (hasChanges) {
      if (confirm('You have unsaved changes. Are you sure you want to close?')) {
        setLocalConfig(config);
        onClose();
      }
    } else {
      onClose();
    }
  };

  if (!isMIDISupported()) {
    return (
      <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
        <div
          className="rounded-lg p-6 max-w-md w-full mx-4"
          style={{
            background: theme.bgSecondary,
            border: `1px solid ${theme.border}`,
          }}
        >
          <h2 className="text-xl font-bold mb-4" style={{ color: theme.textPrimary }}>
            MIDI Not Supported
          </h2>
          <p className="mb-4" style={{ color: theme.textSecondary }}>
            Your browser does not support the Web MIDI API. Please use Chrome, Edge, or Opera to use MIDI pedal features.
          </p>
          <button
            onClick={onClose}
            className="w-full px-4 py-2 rounded-lg font-medium"
            style={{
              background: theme.accentPrimary,
              color: '#ffffff',
            }}
          >
            Close
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div
        className="rounded-lg w-full max-w-3xl max-h-[90vh] overflow-hidden flex flex-col"
        style={{
          background: theme.bgSecondary,
          border: `1px solid ${theme.border}`,
        }}
      >
        {/* Header */}
        <div
          className="flex items-center justify-between p-4 border-b"
          style={{ borderColor: theme.border }}
        >
          <h2 className="text-xl font-bold" style={{ color: theme.textPrimary }}>
            Configure MIDI Pedalboard
          </h2>
          <button
            onClick={handleCancel}
            className="p-1 rounded hover:opacity-70 transition-opacity"
            style={{ color: theme.textSecondary }}
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6">
          {/* Device Selection Section */}
          <div>
            <h3 className="text-sm font-bold mb-3" style={{ color: theme.textPrimary }}>
              1. Select MIDI Device
            </h3>
            <div className="flex gap-2">
              <select
                value={selectedDevice?.id || ''}
                onChange={(e) => handleDeviceChange(e.target.value)}
                className="flex-1 px-3 py-2 rounded-lg text-sm"
                style={{
                  background: theme.bgTertiary,
                  color: theme.textPrimary,
                  border: `1px solid ${theme.border}`,
                }}
              >
                <option value="">No Device Selected</option>
                {availableDevices.map(device => (
                  <option key={device.id} value={device.id}>
                    {device.name} {device.manufacturer ? `(${device.manufacturer})` : ''}
                  </option>
                ))}
              </select>
              <button
                onClick={() => window.location.reload()}
                className="px-3 py-2 rounded-lg hover:opacity-70 transition-opacity"
                style={{
                  background: theme.bgTertiary,
                  color: theme.textPrimary,
                  border: `1px solid ${theme.border}`,
                }}
                title="Refresh devices"
              >
                <RefreshCw className="h-4 w-4" />
              </button>
            </div>

            {/* Profile Management */}
            {selectedDevice && (
              <div className="mt-4 space-y-3">
                {/* Save Profile */}
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={profileName}
                    onChange={(e) => setProfileName(e.target.value)}
                    placeholder="Profile name..."
                    className="flex-1 px-3 py-2 rounded-lg text-sm"
                    style={{
                      background: theme.bgSecondary,
                      color: theme.textPrimary,
                      border: `1px solid ${theme.border}`,
                    }}
                  />
                  <button
                    onClick={handleSaveProfile}
                    disabled={!profileName.trim() || isSavingProfile}
                    className="px-4 py-2 rounded-lg text-sm font-medium transition-all disabled:opacity-30 disabled:cursor-not-allowed flex items-center gap-2"
                    style={{
                      background: theme.accentPrimary,
                      color: '#ffffff',
                      border: `1px solid ${theme.accentPrimary}`,
                    }}
                  >
                    <Save className="h-4 w-4" />
                    {isSavingProfile ? 'Saving...' : 'Save Profile'}
                  </button>
                </div>

                {/* Load Profile */}
                {profiles.length > 0 && (
                  <div className="flex gap-2">
                    <select
                      value={selectedProfileId || ''}
                      onChange={(e) => e.target.value && handleLoadProfile(e.target.value)}
                      className="flex-1 px-3 py-2 rounded-lg text-sm"
                      style={{
                        background: theme.bgSecondary,
                        color: theme.textPrimary,
                        border: `1px solid ${theme.border}`,
                      }}
                    >
                      <option value="">Load a profile...</option>
                      {profiles.map(profile => (
                        <option key={profile.id} value={profile.id}>
                          {profile.name}
                        </option>
                      ))}
                    </select>
                    {selectedProfileId && (
                      <button
                        onClick={() => handleDeleteProfile(selectedProfileId)}
                        className="px-3 py-2 rounded-lg text-sm font-medium transition-all hover:opacity-70"
                        style={{
                          background: '#dc2626',
                          color: '#ffffff',
                          border: '1px solid #b91c1c',
                        }}
                        title="Delete selected profile"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    )}
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Button Assignment Section */}
          <div>
            <h3 className="text-sm font-bold mb-3" style={{ color: theme.textPrimary }}>
              2. Set MIDI Pedal Buttons
            </h3>

            {!selectedDevice ? (
              <div
                className="rounded-lg p-4 text-center"
                style={{
                  background: theme.bgTertiary,
                  border: `1px solid ${theme.border}`,
                }}
              >
                <AlertCircle className="h-8 w-8 mx-auto mb-2" style={{ color: theme.textSecondary }} />
                <p className="text-sm" style={{ color: theme.textSecondary }}>
                  Please select a MIDI device first
                </p>
              </div>
            ) : (
              <>
                <p className="text-xs mb-4" style={{ color: theme.textSecondary }}>
                  Click "Assign Button" next to each action, then press the corresponding button on your MIDI pedal.
                </p>

                {/* Action Assignment List */}
                <div className="space-y-3">
                  {(['prev', 'next', 'scale-left', 'scale-right'] as MIDIButtonAction[]).map((action) => {
                    // Find if this action is already assigned to a button
                    const assignedButton = localConfig.buttons.find(b => b.action === action);
                    const isLearningThis = isLearning && learningButtonId === action;

                    return (
                      <div
                        key={action}
                        className="rounded-lg p-4"
                        style={{
                          background: theme.bgTertiary,
                          border: `2px solid ${isLearningThis ? theme.accentPrimary : theme.border}`,
                        }}
                      >
                        <div className="flex items-center justify-between gap-3">
                          {/* Action Info */}
                          <div className="flex-1">
                            <div className="flex items-center gap-2 mb-1">
                              <span className="text-sm font-bold" style={{ color: theme.textPrimary }}>
                                {MIDI_ACTION_LABELS[action]}
                              </span>
                              {assignedButton && (
                                <span
                                  className="text-xs px-2 py-0.5 rounded"
                                  style={{
                                    background: theme.accentPrimary,
                                    color: '#ffffff',
                                  }}
                                >
                                  Assigned
                                </span>
                              )}
                            </div>

                            {assignedButton ? (
                              <div className="text-xs" style={{ color: theme.textSecondary }}>
                                {assignedButton.messageType === 'cc' && `CC ${assignedButton.ccNumber}`}
                                {assignedButton.messageType === 'note' && `Note ${assignedButton.noteNumber}`}
                                {assignedButton.messageType === 'program' && `Program ${assignedButton.programNumber}`}
                                {' ΓÇó Channel '}{assignedButton.channel}
                              </div>
                            ) : (
                              <div className="text-xs" style={{ color: theme.textSecondary }}>
                                Not assigned
                              </div>
                            )}
                          </div>

                          {/* Assign/Reassign Button */}
                          <button
                            onClick={() => handleLearnButton(action)}
                            className="px-4 py-2 rounded-lg text-xs font-medium transition-all flex items-center gap-2"
                            style={{
                              background: isLearningThis ? theme.accentPrimary : theme.bgSecondary,
                              color: isLearningThis ? '#ffffff' : theme.textPrimary,
                              border: `1px solid ${theme.border}`,
                            }}
                          >
                            <Zap className="h-3.5 w-3.5" />
                            {isLearningThis ? 'Listening...' : assignedButton ? 'Reassign' : 'Assign Button'}
                          </button>
                        </div>

                        {/* Learning Feedback */}
                        {isLearningThis && (
                          <div className="mt-3 pt-3" style={{ borderTop: `1px solid ${theme.border}` }}>
                            <div className="flex items-center gap-2 text-xs" style={{ color: theme.accentPrimary }}>
                              <div className="animate-pulse">ΓùÅ</div>
                              <span>Press a button on your MIDI pedal...</span>
                            </div>
                            {lastMIDIMessage && (
                              <div className="mt-2 text-xs font-mono p-2 rounded" style={{
                                background: theme.bgSecondary,
                                color: theme.textPrimary,
                              }}>
                                Detected: {lastMIDIMessage.type === 'cc' ? 'CC' : 'Note'} {lastMIDIMessage.number} ΓÇó
                                Ch {lastMIDIMessage.channel} ΓÇó
                                Val {lastMIDIMessage.value}
                              </div>
                            )}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>

                {/* Clear All Button */}
                {localConfig.buttons.length > 0 && (
                  <button
                    onClick={() => {
                      if (confirm('Clear all button assignments?')) {
                        clearAllButtons();
                      }
                    }}
                    className="w-full mt-4 px-3 py-2 rounded-lg text-xs font-medium hover:opacity-70 transition-opacity"
                    style={{
                      background: theme.bgTertiary,
                      color: theme.textSecondary,
                      border: `1px solid ${theme.border}`,
                    }}
                  >
                    Clear All Assignments
                  </button>
                )}
              </>
            )}
          </div>

          {/* Configuration Summary */}
          <div>
            <h3 className="text-sm font-bold mb-3" style={{ color: theme.textPrimary }}>
              3. Configuration Summary
            </h3>
            <div
              className="rounded-lg p-4 space-y-2"
              style={{
                background: theme.bgTertiary,
                border: `1px solid ${theme.border}`,
              }}
            >
              <div className="flex justify-between text-xs">
                <span style={{ color: theme.textSecondary }}>Assigned Actions:</span>
                <span className="font-medium" style={{ color: theme.textPrimary }}>
                  {localConfig.buttons.filter(b => b.action !== 'none').length} / 4
                </span>
              </div>

              <div className="pt-2 mt-2" style={{ borderTop: `1px solid ${theme.border}` }}>
                <p className="text-xs mb-2" style={{ color: theme.textSecondary }}>
                  Status:
                </p>
                <div className="space-y-1">
                  {(['prev', 'next', 'scale-left', 'scale-right'] as MIDIButtonAction[]).map(action => {
                    const assigned = localConfig.buttons.find(b => b.action === action);
                    return (
                      <div key={action} className="flex items-center justify-between text-xs">
                        <span style={{ color: theme.textSecondary }}>
                          {MIDI_ACTION_LABELS[action]}:
                        </span>
                        <span
                          className="font-medium"
                          style={{ color: assigned ? '#22c55e' : theme.textSecondary }}
                        >
                          {assigned ? 'Γ£ô Assigned' : 'Not assigned'}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>

              {lastMIDIMessage && (
                <div className="pt-2 mt-2" style={{ borderTop: `1px solid ${theme.border}` }}>
                  <p className="text-xs mb-1" style={{ color: theme.textSecondary }}>
                    Last MIDI Message:
                  </p>
                  <div className="text-xs font-mono p-2 rounded" style={{
                    background: theme.bgSecondary,
                    color: theme.textPrimary,
                  }}>
                    {lastMIDIMessage.type === 'cc' ? 'CC' : 'Note'} {lastMIDIMessage.number} ΓÇó
                    Ch {lastMIDIMessage.channel} ΓÇó
                    Val {lastMIDIMessage.value}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Footer Actions */}
        <div
          className="flex items-center justify-between gap-3 p-4 border-t"
          style={{ borderColor: theme.border }}
        >
          <button
            onClick={handleReset}
            className="px-3 py-2 rounded-lg text-sm font-medium transition-all hover:opacity-70 flex items-center gap-2"
            style={{
              background: theme.bgTertiary,
              color: theme.textPrimary,
              border: `1px solid ${theme.border}`,
            }}
            title="Reset all configuration to defaults"
          >
            <RotateCcw className="h-4 w-4" />
            Reset All
          </button>

          <div className="flex gap-2">
            <button
              onClick={handleCancel}
              className="px-4 py-2 rounded-lg text-sm font-medium transition-all hover:opacity-70"
              style={{
                background: theme.bgTertiary,
                color: theme.textPrimary,
                border: `1px solid ${theme.border}`,
              }}
            >
              Cancel
            </button>
            <button
              onClick={handleSave}
              className="px-6 py-2.5 rounded-lg text-sm font-semibold transition-all hover:opacity-90 flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed shadow-md"
              style={{
                background: '#3b82f6',
                color: '#ffffff',
                border: '2px solid #2563eb',
              }}
            >
              <Save className="h-4 w-4" />
              Save Configuration
