/**
 * Optimized chord drag hook using CSS transforms for instant visual feedback
 * Only updates React state on drag end for maximum performance
 */

import { useState, useCallback, useRef } from 'react';
import { ChordInstance } from '@/lib/chord-progression/types';

export type DragMode = 'move' | 'resize-left' | 'resize-right' | 'resize-left-push' | 'resize-right-push';

interface DragState {
  isDragging: boolean;
  mode: DragMode | null;
  chordId: string | null;
  startX: number;
  currentX: number;
  startPosition: number;
  startWidth: number;
}

interface SnapIndicator {
  show: boolean;
  position: number;
  type: 'start' | 'end';
  targetChordId: string | null;
}

interface InsertionPreview {
  show: boolean;
  position: number;
}

export function useChordDragOptimized(
  chords: ChordInstance[],
  onChordsUpdate: (chords: ChordInstance[]) => void,
  pixelsPerBeat: number
) {
  const [dragState, setDragState] = useState<DragState>({
    isDragging: false,
    mode: null,
    chordId: null,
    startX: 0,
    currentX: 0,
    startPosition: 0,
    startWidth: 0,
  });

  const [snapIndicator, setSnapIndicator] = useState<SnapIndicator>({
    show: false,
    position: 0,
    type: 'start',
    targetChordId: null,
  });

  const [insertionPreview, setInsertionPreview] = useState<InsertionPreview>({
    show: false,
    position: 0,
  });

  const [selectedChordIds, setSelectedChordIds] = useState<Set<string>>(new Set());

  // Selection box state for drag-to-select
  const [selectionBox, setSelectionBox] = useState<{
    isSelecting: boolean;
    startX: number;
    startY: number;
    currentX: number;
    currentY: number;
  }>({
    isSelecting: false,
    startX: 0,
    startY: 0,
    currentX: 0,
    currentY: 0,
  });

  const originalChordsRef = useRef<ChordInstance[]>([]);
  const selectedChordsStartPositions = useRef<Map<string, number>>(new Map());
  const currentXRef = useRef<number>(0); // Track currentX synchronously for immediate visual feedback

  /**
   * Snap to grid (quarter beats)
   */
  const snapToGrid = useCallback((value: number): number => {
    const gridSize = pixelsPerBeat / 4;
    return Math.round(value / gridSize) * gridSize;
  }, [pixelsPerBeat]);

  /**
   * Check if near another chord for snapping
   */
  const isNearby = useCallback((value: number, target: number, threshold: number = 8): boolean => {
    return Math.abs(value - target) <= threshold;
  }, []);

  /**
   * Find snap target for resize operations
   */
  const findSnapTarget = useCallback((
    currentChordId: string,
    position: number,
    isStart: boolean
  ): { snapPosition: number; targetChordId: string | null } | null => {
    const SNAP_THRESHOLD = 8;

    for (const chord of chords) {
      if (chord.id === currentChordId) continue;

      const chordStart = chord.position;
      const chordEnd = chord.position + chord.width;

      if (isStart) {
        if (isNearby(position, chordStart, SNAP_THRESHOLD)) {
          return { snapPosition: chordStart, targetChordId: chord.id };
        }
        if (isNearby(position, chordEnd, SNAP_THRESHOLD)) {
          return { snapPosition: chordEnd, targetChordId: chord.id };
        }
      } else {
        if (isNearby(position, chordStart, SNAP_THRESHOLD)) {
          return { snapPosition: chordStart, targetChordId: chord.id };
        }
        if (isNearby(position, chordEnd, SNAP_THRESHOLD)) {
          return { snapPosition: chordEnd, targetChordId: chord.id };
        }
      }
    }

    return null;
  }, [chords, isNearby]);

  /**
   * Start dragging - no state updates, just track initial values
   */
  const startDrag = useCallback((chordId: string, mode: DragMode, clientX: number) => {
    const chord = chords.find(c => c.id === chordId);
    if (!chord) return;

    originalChordsRef.current = JSON.parse(JSON.stringify(chords));
    currentXRef.current = clientX; // Initialize ref

    // Store start positions for all selected chords for multi-select drag
    if (mode === 'move' && selectedChordIds.has(chordId)) {
      selectedChordsStartPositions.current.clear();
      chords.forEach(c => {
        if (selectedChordIds.has(c.id)) {
          selectedChordsStartPositions.current.set(c.id, c.position);
        }
      });
    }

    setDragState({
      isDragging: true,
      mode,
      chordId,
      startX: clientX,
      currentX: clientX,
      startPosition: chord.position,
      startWidth: chord.width,
    });
  }, [chords, selectedChordIds]);

  /**
   * Handle drag - update currentX and calculate insertion preview for move operations
   */
  const handleDrag = useCallback((clientX: number) => {
    if (!dragState.isDragging) return;

    // Update ref immediately for synchronous access in getChordTransform
    currentXRef.current = clientX;

    setDragState(prev => ({
      ...prev,
      currentX: clientX,
    }));

    // Show insertion preview line for move operations
    if (dragState.mode === 'move' && dragState.chordId) {
      const deltaX = clientX - dragState.startX;

      // Check if we're dragging multiple selected chords
      const isMultiSelect = selectedChordIds.size > 1 && selectedChordIds.has(dragState.chordId);

      if (isMultiSelect) {
        // For multi-select, show the preview at the start of where the group will be placed
        const draggedChordOriginal = originalChordsRef.current.find(c => c.id === dragState.chordId);
        if (draggedChordOriginal) {
          const draggedTargetPosition = snapToGrid(Math.max(0, draggedChordOriginal.position + deltaX));

          // Find all selected chords and sort by original position
          const selectedChords = originalChordsRef.current
            .filter(c => selectedChordIds.has(c.id))
            .sort((a, b) => a.position - b.position);

          // Calculate offset from dragged chord to the start of the group
          const groupStartOffset = draggedChordOriginal.position - selectedChords[0].position;
          const groupTargetStartPosition = Math.max(0, draggedTargetPosition - groupStartOffset);

          setInsertionPreview({
            show: true,
            position: groupTargetStartPosition,
          });
        }
      } else {
        // Single chord - show preview at the dragged chord's position
        const newPosition = snapToGrid(Math.max(0, dragState.startPosition + deltaX));
        setInsertionPreview({
          show: true,
          position: newPosition,
        });
      }
    } else {
      setInsertionPreview({ show: false, position: 0 });
    }
  }, [dragState.isDragging, dragState.mode, dragState.chordId, dragState.startX, dragState.startPosition, snapToGrid, selectedChordIds]);

  /**
   * Detect collision and calculate push offset for other blocks
   */
  const getCollisionPushOffset = useCallback((chordId: string): number => {
    if (!dragState.isDragging || dragState.mode !== 'move' || !dragState.chordId) {
      return 0;
    }

    // Don't push the dragged chord itself
    if (chordId === dragState.chordId) {
      return 0;
    }

    const deltaX = dragState.currentX - dragState.startX;
    const draggedChord = chords.find(c => c.id === dragState.chordId);
    const targetChord = chords.find(c => c.id === chordId);

    if (!draggedChord || !targetChord) return 0;

    // Calculate new position of dragged chord
    const newDraggedPosition = Math.max(0, dragState.startPosition + deltaX);
    const newDraggedEnd = newDraggedPosition + draggedChord.width;

    // Check if dragged chord overlaps with target chord
    const targetStart = targetChord.position;
    const targetEnd = targetChord.position + targetChord.width;

    // If dragged chord overlaps target, push target to the right
    if (newDraggedPosition < targetEnd && newDraggedEnd > targetStart) {
      // Push target so its start aligns with dragged chord's end
      const pushOffset = newDraggedEnd - targetStart;
      return pushOffset;
    }

    return 0;
  }, [dragState, chords]);

  /**
   * Get visual transform for a chord during drag
   * This is used by the ChordCard to apply CSS transforms
   * Uses currentXRef for synchronous access to avoid render delays
   */
  const getChordTransform = useCallback((chordId: string): { deltaX: number; deltaWidth: number } => {
    if (!dragState.isDragging) {
      return { deltaX: 0, deltaWidth: 0 };
    }

    // Use ref for immediate synchronous access to currentX
    const deltaX = currentXRef.current - dragState.startX;
    const isSelected = selectedChordIds.has(chordId);
    const isDraggedChord = dragState.chordId === chordId;
    const isDraggingSelectedChord = dragState.chordId && selectedChordIds.has(dragState.chordId);

    // For move operations with multi-select
    if (dragState.mode === 'move') {
      // If this chord is selected and we're dragging any selected chord, move it together
      if (isSelected && isDraggingSelectedChord) {
        return { deltaX: deltaX, deltaWidth: 0 };
      }

      // Don't animate collision pushing during drag - only show glow line
      // The actual pushing happens on drag end
      return { deltaX: 0, deltaWidth: 0 };
    }

    // Handle the dragged chord itself for resize operations
    if (!isDraggedChord) {
      return { deltaX: 0, deltaWidth: 0 };
    }

    if (dragState.mode === 'resize-right' || dragState.mode === 'resize-right-push') {
      return { deltaX: 0, deltaWidth: deltaX };
    } else if (dragState.mode === 'resize-left' || dragState.mode === 'resize-left-push') {
      return { deltaX: deltaX, deltaWidth: -deltaX };
    }

    return { deltaX: 0, deltaWidth: 0 };
  }, [dragState, selectedChordIds]);

  /**
   * End drag - apply all changes to actual state
   */
  const endDrag = useCallback(() => {
    if (!dragState.isDragging || !dragState.chordId || !dragState.mode) {
      setDragState({
        isDragging: false,
        mode: null,
        chordId: null,
        startX: 0,
        currentX: 0,
        startPosition: 0,
        startWidth: 0,
      });
      setSnapIndicator({ show: false, position: 0, type: 'start', targetChordId: null });
      setInsertionPreview({ show: false, position: 0 });
      return;
    }

    const deltaX = dragState.currentX - dragState.startX;
    const updatedChords = [...originalChordsRef.current];
    const chordIndex = updatedChords.findIndex(c => c.id === dragState.chordId);

    if (chordIndex === -1) {
      setDragState({
        isDragging: false,
        mode: null,
        chordId: null,
        startX: 0,
        currentX: 0,
        startPosition: 0,
        startWidth: 0,
      });
      return;
    }

    const chord = updatedChords[chordIndex];

    // Apply the drag changes based on mode
    if (dragState.mode === 'move') {
      // Check if we're moving multiple selected chords
      const isMultiSelect = selectedChordIds.size > 1 && selectedChordIds.has(dragState.chordId);

      if (isMultiSelect) {
        // Move all selected chords together with proper reordering
        const positionDelta = deltaX;

        // Find the dragged chord to use as the reference for the group's target position
        const draggedChordOriginal = originalChordsRef.current.find(c => c.id === dragState.chordId);
        if (!draggedChordOriginal) return;

        // Calculate the target position for the dragged chord (this is where the yellow line shows)
        const draggedTargetPosition = snapToGrid(Math.max(0, draggedChordOriginal.position + positionDelta));

        // Separate selected and non-selected chords, preserving their original relative positions
        const selectedChords: Array<{ chord: ChordInstance; originalIndex: number; originalPosition: number }> = [];
        const nonSelectedChords: Array<{ chord: ChordInstance; originalIndex: number }> = [];

        originalChordsRef.current.forEach((c, i) => {
          if (selectedChordIds.has(c.id)) {
            selectedChords.push({
              chord: c,
              originalIndex: i,
              originalPosition: c.position,
            });
          } else {
            nonSelectedChords.push({ chord: c, originalIndex: i });
          }
        });

        // Sort selected chords by their original position to maintain relative order
        selectedChords.sort((a, b) => a.originalPosition - b.originalPosition);

        // Calculate the offset from the dragged chord to the start of the selected group
        const draggedChordInGroup = selectedChords.find(sc => sc.chord.id === dragState.chordId);
        if (!draggedChordInGroup) return;

        const groupStartOffset = draggedChordInGroup.originalPosition - selectedChords[0].originalPosition;

        // The group should start at: draggedTargetPosition - groupStartOffset
        const groupTargetStartPosition = Math.max(0, draggedTargetPosition - groupStartOffset);

        // Calculate total width of the selected group
        let totalGroupWidth = 0;
        selectedChords.forEach(({ chord }) => {
          totalGroupWidth += chord.width;
        });
        const groupTargetEndPosition = groupTargetStartPosition + totalGroupWidth;

        // Find insertion point: where should the selected group be inserted among non-selected chords?
        // Use the start position of the group to determine insertion
        let insertionIndex = 0;
        for (let i = 0; i < nonSelectedChords.length; i++) {
          const nonSelectedStart = nonSelectedChords[i].chord.position;
          if (groupTargetStartPosition >= nonSelectedStart + nonSelectedChords[i].chord.width) {
            insertionIndex = i + 1;
          }
        }

        // Build the final chord order: non-selected before insertion + selected group + non-selected after insertion
        const reorderedChords: ChordInstance[] = [];

        // Add non-selected chords before the insertion point
        for (let i = 0; i < insertionIndex; i++) {
          reorderedChords.push(nonSelectedChords[i].chord);
        }

        // Add all selected chords in their relative order
        selectedChords.forEach(({ chord }) => {
          reorderedChords.push(chord);
        });

        // Add non-selected chords after the insertion point
        for (let i = insertionIndex; i < nonSelectedChords.length; i++) {
          reorderedChords.push(nonSelectedChords[i].chord);
        }

        // Recalculate positions to place chords sequentially without gaps or overlaps
        let currentPosition = 0;
        const finalChords = reorderedChords.map((c) => {
          const updatedChord = {
            ...c,
            position: currentPosition,
            startTime: currentPosition / pixelsPerBeat,
          };
          currentPosition += c.width;
          return updatedChord;
        });

        // Update the chords array with the reordered and repositioned chords
        updatedChords.splice(0, updatedChords.length, ...finalChords);
      } else {
        // Single chord move
        let newPosition = snapToGrid(Math.max(0, dragState.startPosition + deltaX));

        // Check for snap targets at the new position
        const snapTargetStart = findSnapTarget(dragState.chordId, newPosition, true);
        if (snapTargetStart) {
          newPosition = snapTargetStart.snapPosition;
        }

        updatedChords[chordIndex] = {
          ...chord,
          position: newPosition,
          startTime: newPosition / pixelsPerBeat,
        };

        // Apply collision pushing to other chords
        const newDraggedEnd = newPosition + chord.width;

        updatedChords.forEach((c, i) => {
          if (i === chordIndex) return; // Skip the dragged chord

          const targetStart = c.position;
          const targetEnd = c.position + c.width;

          // If dragged chord overlaps with this chord, push it to the right
          if (newPosition < targetEnd && newDraggedEnd > targetStart) {
            const pushedPosition = newDraggedEnd;
            updatedChords[i] = {
              ...c,
              position: pushedPosition,
              startTime: pushedPosition / pixelsPerBeat,
            };
          }
        });
      }
    } else if (dragState.mode === 'resize-left') {
      let newPosition = Math.max(0, dragState.startPosition + deltaX);
      let newWidth = Math.max(pixelsPerBeat / 4, dragState.startWidth - deltaX);

      const snapTarget = findSnapTarget(dragState.chordId, newPosition, true);
      if (snapTarget) {
        newPosition = snapTarget.snapPosition;
        newWidth = dragState.startPosition + dragState.startWidth - newPosition;
      }

      updatedChords[chordIndex] = {
        ...chord,
        position: newPosition,
        width: newWidth,
        startTime: newPosition / pixelsPerBeat,
        duration: newWidth / pixelsPerBeat,
      };
    } else if (dragState.mode === 'resize-right') {
      let newWidth = Math.max(pixelsPerBeat / 4, dragState.startWidth + deltaX);
      const newEndPosition = dragState.startPosition + newWidth;

      const snapTarget = findSnapTarget(dragState.chordId, newEndPosition, false);
      if (snapTarget) {
        newWidth = snapTarget.snapPosition - dragState.startPosition;
      }

      updatedChords[chordIndex] = {
        ...chord,
        width: newWidth,
        duration: newWidth / pixelsPerBeat,
      };
    } else if (dragState.mode === 'resize-left-push') {
      const newPosition = snapToGrid(Math.max(0, dragState.startPosition + deltaX));
      const newWidth = snapToGrid(Math.max(pixelsPerBeat / 4, dragState.startWidth - deltaX));
      const pushAmount = newPosition - dragState.startPosition;

      updatedChords[chordIndex] = {
        ...chord,
        position: newPosition,
        width: newWidth,
        startTime: newPosition / pixelsPerBeat,
        duration: newWidth / pixelsPerBeat,
      };

      updatedChords.forEach((c, i) => {
        if (i !== chordIndex && c.position + c.width <= dragState.startPosition) {
          updatedChords[i] = {
            ...c,
            position: Math.max(0, c.position + pushAmount),
            startTime: Math.max(0, c.position + pushAmount) / pixelsPerBeat,
          };
        }
      });
    } else if (dragState.mode === 'resize-right-push') {
      const newWidth = snapToGrid(Math.max(pixelsPerBeat / 4, dragState.startWidth + deltaX));
      const pushAmount = newWidth - dragState.startWidth;

      updatedChords[chordIndex] = {
        ...chord,
        width: newWidth,
        duration: newWidth / pixelsPerBeat,
      };

      const currentEndPosition = dragState.startPosition + dragState.startWidth;
      updatedChords.forEach((c, i) => {
        if (i !== chordIndex && c.position >= currentEndPosition) {
          updatedChords[i] = {
            ...c,
            position: c.position + pushAmount,
            startTime: (c.position + pushAmount) / pixelsPerBeat,
          };
        }
      });
    }

    onChordsUpdate(updatedChords);

    setDragState({
      isDragging: false,
      mode: null,
      chordId: null,
      startX: 0,
      currentX: 0,
      startPosition: 0,
      startWidth: 0,
    });

    setSnapIndicator({ show: false, position: 0, type: 'start', targetChordId: null });
    setInsertionPreview({ show: false, position: 0 });
  }, [dragState, pixelsPerBeat, snapToGrid, findSnapTarget, onChordsUpdate]);

  /**
   * Handle chord selection (with Ctrl/Cmd for multi-select)
   */
  const handleChordSelect = useCallback((chordId: string, isMultiSelect: boolean) => {
    setSelectedChordIds(prev => {
      const newSet = new Set(prev);

      if (isMultiSelect) {
        // Toggle selection
        if (newSet.has(chordId)) {
          newSet.delete(chordId);
        } else {
          newSet.add(chordId);
        }
      } else {
        // Single select
        newSet.clear();
        newSet.add(chordId);
      }

      return newSet;
    });
  }, []);

  /**
   * Clear all selections
   */
  const clearSelection = useCallback(() => {
    setSelectedChordIds(new Set());
  }, []);

  /**
   * Start selection box drag
   */
  const startSelectionBox = useCallback((clientX: number, clientY: number, isMultiSelect: boolean) => {
    if (!isMultiSelect) {
      setSelectedChordIds(new Set());
    }
    setSelectionBox({
      isSelecting: true,
      startX: clientX,
      startY: clientY,
      currentX: clientX,
      currentY: clientY,
    });
  }, []);

  /**
   * Update selection box during drag
   */
  const updateSelectionBox = useCallback((clientX: number, clientY: number, trackRect: DOMRect) => {
    if (!selectionBox.isSelecting) return;

    setSelectionBox(prev => ({
      ...prev,
      currentX: clientX,
      currentY: clientY,
    }));

    // Calculate selection box bounds relative to track
    const boxLeft = Math.min(selectionBox.startX, clientX) - trackRect.left;
    const boxRight = Math.max(selectionBox.startX, clientX) - trackRect.left;
    const boxTop = Math.min(selectionBox.startY, clientY) - trackRect.top;
    const boxBottom = Math.max(selectionBox.startY, clientY) - trackRect.top;

    // Find chords that intersect with selection box
    const newSelectedIds = new Set<string>();
    chords.forEach(chord => {
      const chordLeft = chord.position;
      const chordRight = chord.position + chord.width;
      const chordTop = 0;
      const chordBottom = 120; // Track height

      // Check if chord intersects with selection box
      if (
        chordLeft < boxRight &&
        chordRight > boxLeft &&
        chordTop < boxBottom &&
        chordBottom > boxTop
      ) {
        newSelectedIds.add(chord.id);
      }
    });

    setSelectedChordIds(newSelectedIds);
  }, [selectionBox, chords]);

  /**
   * End selection box drag
   */
  const endSelectionBox = useCallback(() => {
    setSelectionBox({
      isSelecting: false,
      startX: 0,
      startY: 0,
      currentX: 0,
      currentY: 0,
    });
  }, []);

  return {
    dragState,
    snapIndicator,
    insertionPreview,
    selectedChordIds,
    selectionBox,
    startDrag,
    handleDrag,
    endDrag,
    getChordTransform,
    handleChordSelect,
    clearSelection,
    startSelectionBox,
    updateSelectionBox,
    endSelectionBox,
  };
}

/**
 * Hook for analyzing chord progression compatibility with the current key
 * Triggers API calls when chords are added, removed, or reordered
 */

import { useState, useEffect, useRef } from 'react';
import { ChordInstance } from '@/lib/chord-progression/types';

interface CompatibilityResult {
  score: number;
  rationale: string;
  recommendations: string;
}

interface UseChordProgressionCompatibilityReturn {
  compatibility: CompatibilityResult | null;
  isLoading: boolean;
  error: string | null;
}

export function useChordProgressionCompatibility(
  chords: ChordInstance[],
  currentKey: string
): UseChordProgressionCompatibilityReturn {
  const [compatibility, setCompatibility] = useState<CompatibilityResult | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Track previous chord progression to detect changes
  const prevChordsRef = useRef<string>('');
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    // Create a string representation of the chord progression for comparison
    const currentChordString = chords.map(c => c.chordSymbol).join(',');

    // Only analyze if:
    // 1. There are chords in the progression
    // 2. The progression has changed (added, removed, or reordered)
    // 3. We have a valid key
    if (
      chords.length === 0 ||
      currentChordString === prevChordsRef.current ||
      !currentKey
    ) {
      // If no chords, clear the compatibility result
      if (chords.length === 0 && compatibility !== null) {
        setCompatibility(null);
      }
      return;
    }

    // Update the previous chords reference
    prevChordsRef.current = currentChordString;

    // Cancel any pending request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    // Create new abort controller for this request
    abortControllerRef.current = new AbortController();

    const analyzeCompatibility = async () => {
      setIsLoading(true);
      setError(null);

      try {
        const chordProgression = chords.map(c => c.chordSymbol);

        const response = await fetch('/api/chord-progression/analyze-compatibility', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            key: currentKey,
            chordProgression,
          }),
          signal: abortControllerRef.current?.signal,
        });

        if (!response.ok) {
          throw new Error('Failed to analyze compatibility');
        }

        const result: CompatibilityResult = await response.json();
        setCompatibility(result);
      } catch (err) {
        // Ignore abort errors
        if (err instanceof Error && err.name === 'AbortError') {
          return;
        }

        console.error('Error analyzing chord progression compatibility:', err);
        setError(err instanceof Error ? err.message : 'Unknown error');
      } finally {
        setIsLoading(false);
      }
    };

    analyzeCompatibility();

    // Cleanup function
    return () => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, [chords, currentKey]); // Re-run when chords or key changes

  return {
    compatibility,
    isLoading,
    error,
  };
}

/**
 * Optimized scale mode drag hook using CSS transforms for instant visual feedback
 * Only updates React state on drag end for maximum performance
 */

import { useState, useCallback, useRef } from 'react';
import { ScaleModeInstance } from '@/lib/chord-progression/types';
import { ScaleModeDragMode } from '@/components/chord-progression/ScaleModeCard';

interface ScaleModeDragState {
  isDragging: boolean;
  dragType: ScaleModeDragMode | null;
  scaleModeId: string | null;
  startX: number;
  currentX: number;
  startTime: number;
  startDuration: number;
}

interface SnapIndicator {
  show: boolean;
  position: number;
  type: 'start' | 'end';
  targetScaleModeId: string | null;
}

interface InsertionPreview {
  show: boolean;
  position: number;
}

export function useScaleModeDragOptimized(
  scaleModes: ScaleModeInstance[],
  onScaleModesUpdate: (scaleModes: ScaleModeInstance[]) => void,
  pixelsPerBeat: number
) {
  const [dragState, setDragState] = useState<ScaleModeDragState>({
    isDragging: false,
    dragType: null,
    scaleModeId: null,
    startX: 0,
    currentX: 0,
    startTime: 0,
    startDuration: 0,
  });

  const [snapIndicator, setSnapIndicator] = useState<SnapIndicator>({
    show: false,
    position: 0,
    type: 'start',
    targetScaleModeId: null,
  });

  const [insertionPreview, setInsertionPreview] = useState<InsertionPreview>({
    show: false,
    position: 0,
  });

  const [selectedScaleModeIds, setSelectedScaleModeIds] = useState<Set<string>>(new Set());

  // Selection box state for drag-to-select
  const [selectionBox, setSelectionBox] = useState<{
    isSelecting: boolean;
    startX: number;
    startY: number;
    currentX: number;
    currentY: number;
  }>({
    isSelecting: false,
    startX: 0,
    startY: 0,
    currentX: 0,
    currentY: 0,
  });

  const originalScaleModesRef = useRef<ScaleModeInstance[]>([]);
  const currentXRef = useRef<number>(0); // Track currentX synchronously for immediate visual feedback

  /**
   * Check if near another scale mode for snapping
   */
  const isNearby = useCallback((value: number, target: number, threshold: number = 8): boolean => {
    return Math.abs(value - target) <= threshold;
  }, []);

  /**
   * Find snap target for resize operations
   */
  const findSnapTarget = useCallback((
    currentScaleModeId: string,
    position: number,
    isStart: boolean
  ): { snapPosition: number; targetScaleModeId: string | null } | null => {
    const SNAP_THRESHOLD = 8;

    for (const scaleMode of scaleModes) {
      if (scaleMode.id === currentScaleModeId) continue;

      const scaleModeStart = scaleMode.position;
      const scaleModeEnd = scaleMode.position + scaleMode.width;

      if (isStart) {
        if (isNearby(position, scaleModeStart, SNAP_THRESHOLD)) {
          return { snapPosition: scaleModeStart, targetScaleModeId: scaleMode.id };
        }
        if (isNearby(position, scaleModeEnd, SNAP_THRESHOLD)) {
          return { snapPosition: scaleModeEnd, targetScaleModeId: scaleMode.id };
        }
      } else {
        if (isNearby(position, scaleModeStart, SNAP_THRESHOLD)) {
          return { snapPosition: scaleModeStart, targetScaleModeId: scaleMode.id };
        }
        if (isNearby(position, scaleModeEnd, SNAP_THRESHOLD)) {
          return { snapPosition: scaleModeEnd, targetScaleModeId: scaleMode.id };
        }
      }
    }

    return null;
  }, [scaleModes, isNearby]);

  /**
   * Start dragging
   */
  const handleDragStart = useCallback((
    scaleModeId: string,
    dragType: ScaleModeDragMode,
    startX: number
  ) => {
    const scaleMode = scaleModes.find(sm => sm.id === scaleModeId);
    if (!scaleMode) return;

    originalScaleModesRef.current = JSON.parse(JSON.stringify(scaleModes));
    currentXRef.current = startX; // Initialize ref

    // Store start positions for all selected scale modes for multi-select drag
    if (dragType === 'move' && selectedScaleModeIds.has(scaleModeId)) {
      scaleModes.forEach(sm => {
        if (selectedScaleModeIds.has(sm.id)) {
          // Store initial positions for group drag
        }
      });
    }

    setDragState({
      isDragging: true,
      dragType,
      scaleModeId,
      startX,
      currentX: startX,
      startTime: scaleMode.startTime,
      startDuration: scaleMode.duration,
    });
  }, [scaleModes, selectedScaleModeIds]);

  /**
   * Handle drag - update currentX and calculate insertion preview for move operations
   */
  const handleDragMove = useCallback((clientX: number) => {
    if (!dragState.isDragging) return;

    // Update ref immediately for synchronous access in getScaleModeTransform
    currentXRef.current = clientX;

    setDragState(prev => ({
      ...prev,
      currentX: clientX,
    }));

    // Show insertion preview line for move operations
    if (dragState.dragType === 'move' && dragState.scaleModeId) {
      const deltaX = clientX - dragState.startX;
      const deltaBeats = deltaX / pixelsPerBeat;
      const newStart = Math.max(0, dragState.startTime + deltaBeats);
      const newPosition = newStart * pixelsPerBeat;

      setInsertionPreview({
        show: true,
        position: newPosition,
      });
    } else {
      setInsertionPreview({ show: false, position: 0 });
    }
  }, [dragState.isDragging, dragState.dragType, dragState.scaleModeId, dragState.startX, dragState.startTime, pixelsPerBeat]);

  /**
   * Detect collision and calculate push offset for other blocks
   */
  const getCollisionPushOffset = useCallback((scaleModeId: string): number => {
    if (!dragState.isDragging || dragState.dragType !== 'move' || !dragState.scaleModeId) {
      return 0;
    }

    // Don't push the dragged scale mode itself
    if (scaleModeId === dragState.scaleModeId) {
      return 0;
    }

    const deltaX = dragState.currentX - dragState.startX;
    const draggedScaleMode = scaleModes.find(sm => sm.id === dragState.scaleModeId);
    const targetScaleMode = scaleModes.find(sm => sm.id === scaleModeId);

    if (!draggedScaleMode || !targetScaleMode) return 0;

    // Calculate new position of dragged scale mode
    const deltaBeats = deltaX / pixelsPerBeat;
    const newDraggedStart = Math.max(0, dragState.startTime + deltaBeats);
    const newDraggedPosition = newDraggedStart * pixelsPerBeat;
    const newDraggedEnd = newDraggedPosition + draggedScaleMode.width;

    // Check if dragged scale mode overlaps with target scale mode
    const targetStart = targetScaleMode.position;
    const targetEnd = targetScaleMode.position + targetScaleMode.width;

    // If dragged scale mode overlaps target, push target to the right
    if (newDraggedPosition < targetEnd && newDraggedEnd > targetStart) {
      // Push target so its start aligns with dragged scale mode's end
      const pushOffset = newDraggedEnd - targetStart;
      return pushOffset;
    }

    return 0;
  }, [dragState, scaleModes, pixelsPerBeat]);

  /**
   * Get visual transform for a scale mode during drag
   * Uses currentXRef for synchronous access to avoid render delays
   */
  const getScaleModeTransform = useCallback((scaleModeId: string): { deltaX: number; deltaWidth: number } => {
    if (!dragState.isDragging) {
      return { deltaX: 0, deltaWidth: 0 };
    }

    // Use ref for immediate synchronous access to currentX
    const deltaX = currentXRef.current - dragState.startX;
    const isSelected = selectedScaleModeIds.has(scaleModeId);
    const isDraggedScaleMode = dragState.scaleModeId === scaleModeId;
    const isMultiSelect = selectedScaleModeIds.size > 1 && selectedScaleModeIds.has(dragState.scaleModeId || '');

    // For move operations
    if (dragState.dragType === 'move') {
      // If multi-select is active and this scale mode is selected, move it with the group
      if (isMultiSelect && isSelected) {
        return { deltaX: deltaX, deltaWidth: 0 };
      }

      // If single select and this is the dragged scale mode, move it
      if (!isMultiSelect && isDraggedScaleMode) {
        return { deltaX: deltaX, deltaWidth: 0 };
      }

      // Don't animate collision pushing during drag - only show glow line
      // The actual pushing happens on drag end
      return { deltaX: 0, deltaWidth: 0 };
    }

    // Handle resize operations (only for the dragged scale mode, not multi-select)
    if (!isDraggedScaleMode) {
      return { deltaX: 0, deltaWidth: 0 };
    }

    if (dragState.dragType === 'resize-right' || dragState.dragType === 'resize-right-push') {
      return { deltaX: 0, deltaWidth: deltaX };
    } else if (dragState.dragType === 'resize-left' || dragState.dragType === 'resize-left-push') {
      return { deltaX: deltaX, deltaWidth: -deltaX };
    }

    return { deltaX: 0, deltaWidth: 0 };
  }, [dragState, selectedScaleModeIds]);

  /**
   * End drag - apply all changes to actual state
   */
  const handleDragEnd = useCallback(() => {
    if (!dragState.isDragging || !dragState.scaleModeId || !dragState.dragType) {
      setDragState({
        isDragging: false,
        dragType: null,
        scaleModeId: null,
        startX: 0,
        currentX: 0,
        startTime: 0,
        startDuration: 0,
      });
      setSnapIndicator({ show: false, position: 0, type: 'start', targetScaleModeId: null });
      setInsertionPreview({ show: false, position: 0 });
      return;
    }

    const deltaX = dragState.currentX - dragState.startX;
    const deltaBeats = deltaX / pixelsPerBeat;
    const scaleModeIndex = originalScaleModesRef.current.findIndex(sm => sm.id === dragState.scaleModeId);

    if (scaleModeIndex === -1) {
      setDragState({
        isDragging: false,
        dragType: null,
        scaleModeId: null,
        startX: 0,
        currentX: 0,
        startTime: 0,
        startDuration: 0,
      });
      return;
    }

    const updatedScaleModes = [...originalScaleModesRef.current];
    const scaleMode = updatedScaleModes[scaleModeIndex];

    // Apply the drag changes based on type
    if (dragState.dragType === 'move') {
      // Check if we're moving multiple selected scale modes
      const isMultiSelect = selectedScaleModeIds.size > 1 && selectedScaleModeIds.has(dragState.scaleModeId);

      if (isMultiSelect) {
        // Move all selected scale modes together
        const timeDelta = deltaBeats;

        // Find the rightmost edge of all selected scale modes after moving
        let maxEndPosition = 0;

        updatedScaleModes.forEach((sm, i) => {
          if (selectedScaleModeIds.has(sm.id)) {
            const newStart = Math.max(0, sm.startTime + timeDelta);
            const newPos = newStart * pixelsPerBeat;
            const newEnd = newPos + sm.width;
            maxEndPosition = Math.max(maxEndPosition, newEnd);

            updatedScaleModes[i] = {
              ...sm,
              startTime: newStart,
              position: newPos,
            };
          }
        });

        // Apply collision pushing to non-selected scale modes with cascading
        // Sort scale modes by position to handle cascading pushes correctly
        const sortedIndices = updatedScaleModes
          .map((sm, i) => ({ scaleMode: sm, index: i }))
          .sort((a, b) => a.scaleMode.position - b.scaleMode.position);

        // Track which scale modes have been pushed and need to cascade
        const pushedScaleModes = new Map<number, number>(); // index -> new position

        sortedIndices.forEach(({ scaleMode: sm, index: i }) => {
          if (!selectedScaleModeIds.has(sm.id)) {
            let currentPosition = pushedScaleModes.get(i) ?? sm.position;
            const targetEnd = currentPosition + sm.width;

            // Check if any selected scale mode overlaps with this scale mode
            let maxPushPosition = currentPosition;

            updatedScaleModes.forEach((selectedSM) => {
              if (selectedScaleModeIds.has(selectedSM.id)) {
                const selectedStart = selectedSM.position;
                const selectedEnd = selectedSM.position + selectedSM.width;

                // If selected scale mode overlaps, push this scale mode to the right
                if (selectedStart < targetEnd && selectedEnd > currentPosition) {
                  maxPushPosition = Math.max(maxPushPosition, selectedEnd);
                }
              }
            });

            // Check if any previously pushed scale mode overlaps with this scale mode
            pushedScaleModes.forEach((pushedPos, pushedIndex) => {
              const pushedSM = updatedScaleModes[pushedIndex];
              const pushedEnd = pushedPos + pushedSM.width;

              if (pushedPos < targetEnd && pushedEnd > currentPosition) {
                maxPushPosition = Math.max(maxPushPosition, pushedEnd);
              }
            });

            if (maxPushPosition > currentPosition) {
              pushedScaleModes.set(i, maxPushPosition);
              const pushedStartTime = maxPushPosition / pixelsPerBeat;
              updatedScaleModes[i] = {
                ...sm,
                position: maxPushPosition,
                startTime: pushedStartTime,
              };
            }
          }
        });
      } else {
        // Single scale mode move
        const newStart = Math.max(0, dragState.startTime + deltaBeats);
        const newPosition = newStart * pixelsPerBeat;

        // Check for snap targets at the new position
        const snapTargetStart = findSnapTarget(dragState.scaleModeId, newPosition, true);
        const finalStart = snapTargetStart ? snapTargetStart.snapPosition / pixelsPerBeat : newStart;
        const finalPosition = finalStart * pixelsPerBeat;

        updatedScaleModes[scaleModeIndex] = {
          ...scaleMode,
          startTime: finalStart,
          position: finalPosition,
        };

        // Apply collision pushing to other scale modes
        const newDraggedEnd = finalPosition + scaleMode.width;

        updatedScaleModes.forEach((sm, i) => {
          if (i === scaleModeIndex) return; // Skip the dragged scale mode

          const targetStart = sm.position;
          const targetEnd = sm.position + sm.width;

          // If dragged scale mode overlaps with this scale mode, push it to the right
          if (finalPosition < targetEnd && newDraggedEnd > targetStart) {
            const pushedPosition = newDraggedEnd;
            const pushedStartTime = pushedPosition / pixelsPerBeat;
            updatedScaleModes[i] = {
              ...sm,
              position: pushedPosition,
              startTime: pushedStartTime,
            };
          }
        });
      }
    } else if (dragState.dragType === 'resize-left' || dragState.dragType === 'resize-left-push') {
      let newStart = Math.max(0, dragState.startTime + deltaBeats);
      let newDuration = Math.max(1, dragState.startDuration - (newStart - dragState.startTime));
      const newPosition = newStart * pixelsPerBeat;

      const snapTarget = findSnapTarget(dragState.scaleModeId, newPosition, true);
      if (snapTarget) {
        newStart = snapTarget.snapPosition / pixelsPerBeat;
        newDuration = dragState.startTime + dragState.startDuration - newStart;
      }

      updatedScaleModes[scaleModeIndex] = {
        ...scaleMode,
        startTime: newStart,
        duration: newDuration,
        position: newStart * pixelsPerBeat,
        width: newDuration * pixelsPerBeat,
      };
    } else if (dragState.dragType === 'resize-right' || dragState.dragType === 'resize-right-push') {
      let newDuration = Math.max(1, dragState.startDuration + deltaBeats);
      const newEndPosition = (dragState.startTime + newDuration) * pixelsPerBeat;

      const snapTarget = findSnapTarget(dragState.scaleModeId, newEndPosition, false);
      if (snapTarget) {
        newDuration = (snapTarget.snapPosition / pixelsPerBeat) - dragState.startTime;
      }

      updatedScaleModes[scaleModeIndex] = {
        ...scaleMode,
        duration: newDuration,
        width: newDuration * pixelsPerBeat,
      };
    }

    onScaleModesUpdate(updatedScaleModes);

    setDragState({
      isDragging: false,
      dragType: null,
      scaleModeId: null,
      startX: 0,
      currentX: 0,
      startTime: 0,
      startDuration: 0,
    });

    setSnapIndicator({ show: false, position: 0, type: 'start', targetScaleModeId: null });
    setInsertionPreview({ show: false, position: 0 });
  }, [dragState, pixelsPerBeat, findSnapTarget, onScaleModesUpdate]);

  /**
   * Handle scale mode selection (with Ctrl/Cmd for multi-select)
   */
  const handleScaleModeSelect = useCallback((scaleModeId: string, isMultiSelect: boolean) => {
    setSelectedScaleModeIds(prev => {
      const newSet = new Set(prev);

      if (isMultiSelect) {
        // Toggle selection
        if (newSet.has(scaleModeId)) {
          newSet.delete(scaleModeId);
        } else {
          newSet.add(scaleModeId);
        }
      } else {
        // Single select
        newSet.clear();
        newSet.add(scaleModeId);
      }

      return newSet;
    });
  }, []);

  /**
   * Clear all selections
   */
  const clearSelection = useCallback(() => {
    setSelectedScaleModeIds(new Set());
  }, []);

  /**
   * Start selection box drag
   */
  const startSelectionBox = useCallback((clientX: number, clientY: number, isMultiSelect: boolean) => {
    if (!isMultiSelect) {
      setSelectedScaleModeIds(new Set());
    }
    setSelectionBox({
      isSelecting: true,
      startX: clientX,
      startY: clientY,
      currentX: clientX,
      currentY: clientY,
    });
  }, []);

  /**
   * Update selection box during drag
   */
  const updateSelectionBox = useCallback((clientX: number, clientY: number, trackRect: DOMRect) => {
    if (!selectionBox.isSelecting) return;

    setSelectionBox(prev => ({
      ...prev,
      currentX: clientX,
      currentY: clientY,
    }));

    // Calculate selection box bounds relative to track
    const boxLeft = Math.min(selectionBox.startX, clientX) - trackRect.left;
    const boxRight = Math.max(selectionBox.startX, clientX) - trackRect.left;
    const boxTop = Math.min(selectionBox.startY, clientY) - trackRect.top;
    const boxBottom = Math.max(selectionBox.startY, clientY) - trackRect.top;

    // Find scale modes that intersect with selection box
    const newSelectedIds = new Set<string>();
    scaleModes.forEach(scaleMode => {
      const scaleModeLeft = scaleMode.position;
      const scaleModeRight = scaleMode.position + scaleMode.width;
      const scaleModeTop = 0;
      const scaleModeBottom = 120; // Track height

      // Check if scale mode intersects with selection box
      if (
        scaleModeLeft < boxRight &&
        scaleModeRight > boxLeft &&
        scaleModeTop < boxBottom &&
        scaleModeBottom > boxTop
      ) {
        newSelectedIds.add(scaleMode.id);
      }
    });

    setSelectedScaleModeIds(newSelectedIds);
  }, [selectionBox, scaleModes]);

  /**
   * End selection box drag
   */
  const endSelectionBox = useCallback(() => {
    setSelectionBox({
      isSelecting: false,
      startX: 0,
      startY: 0,
      currentX: 0,
      currentY: 0,
    });
  }, []);

  return {
    dragState,
    snapIndicator,
    insertionPreview,
    selectedScaleModeIds,
    selectionBox,
    handleDragStart,
    handleDragMove,
    handleDragEnd,
    getScaleModeTransform,
    handleScaleModeSelect,
    clearSelection,
    startSelectionBox,
    updateSelectionBox,
    endSelectionBox,
  };
}

/**
 * Timeline playback hook with enhanced Tone.js and smplr integration
 */

import { useState, useEffect, useRef, useCallback } from 'react';
import { ChordProgressionAudioEngineSmplr } from '@/lib/chord-progression/audio-engine-smplr';
import { MusicalTimeTracker } from '@/lib/chord-progression/musical-time-tracker';
import { PlayheadAnimator, PlayheadState } from '@/lib/chord-progression/playhead-animator';
import { BeatCounter } from '@/lib/chord-progression/beat-counter';
import { ChordInstance, InstrumentType, PlaybackState } from '@/lib/chord-progression/types';

export function useTimelinePlayback(
  chords: ChordInstance[],
  bpm: number,
  pixelsPerBeat: number
) {
  const [playbackState, setPlaybackState] = useState<PlaybackState>({
    isPlaying: false,
    currentTime: 0,
    playbackPosition: 0,
    loopEnabled: true,
    loopStart: 0,
    loopEnd: 0,
  });

  const [selectedInstrument, setSelectedInstrument] = useState<InstrumentType>('piano');
  const [isLoading, setIsLoading] = useState(false);
  const [volume, setVolume] = useState(80);
  const [midiEnabled, setMidiEnabled] = useState(true);
  const [audioOutputDevice, setAudioOutputDevice] = useState<string | undefined>(undefined);
  const [availableDevices, setAvailableDevices] = useState<MediaDeviceInfo[]>([]);

  const audioEngineRef = useRef<ChordProgressionAudioEngineSmplr | null>(null);
  const timeTrackerRef = useRef<MusicalTimeTracker | null>(null);
  const playheadAnimatorRef = useRef<PlayheadAnimator | null>(null);
  const beatCounterRef = useRef<BeatCounter | null>(null);
  const contextRef = useRef<AudioContext | null>(null);

  // Initialize audio context and components
  useEffect(() => {
    if (typeof window === 'undefined') return;

    contextRef.current = new AudioContext();
    timeTrackerRef.current = new MusicalTimeTracker({ numerator: 4, denominator: 4 });
    playheadAnimatorRef.current = new PlayheadAnimator(pixelsPerBeat, bpm);
    beatCounterRef.current = new BeatCounter(timeTrackerRef.current);
    audioEngineRef.current = new ChordProgressionAudioEngineSmplr(contextRef.current, {
      instrument: selectedInstrument,
    });

    // Load available audio output devices
    const loadDevices = async () => {
      try {
        const devices = await navigator.mediaDevices.enumerateDevices();
        const audioOutputs = devices.filter(device => device.kind === 'audiooutput');
        setAvailableDevices(audioOutputs);

        // Set default device if available
        if (audioOutputs.length > 0 && !audioOutputDevice) {
          setAudioOutputDevice('default');
        }
      } catch (error) {
        console.error('Failed to enumerate audio devices:', error);
      }
    };

    loadDevices();

    // Listen for device changes
    navigator.mediaDevices.addEventListener('devicechange', loadDevices);

    return () => {
      navigator.mediaDevices.removeEventListener('devicechange', loadDevices);
      playheadAnimatorRef.current?.stop();
      beatCounterRef.current?.stop();
      audioEngineRef.current?.dispose();
      contextRef.current?.close();
    };
  }, []);

  // Update playhead animator when zoom or BPM changes
  useEffect(() => {
    playheadAnimatorRef.current?.setPixelsPerBeat(pixelsPerBeat);
    playheadAnimatorRef.current?.setBPM(bpm);
    timeTrackerRef.current?.setBPM(bpm);
    audioEngineRef.current?.setBPM(bpm);
  }, [pixelsPerBeat, bpm]);

  // Subscribe to playhead updates
  useEffect(() => {
    if (!playheadAnimatorRef.current) return;

    const unsubscribe = playheadAnimatorRef.current.onUpdate((state: PlayheadState) => {
      setPlaybackState(prev => ({
        ...prev,
        currentTime: state.beats,
        playbackPosition: state.position,
        isPlaying: state.isPlaying,
      }));
    });

    return unsubscribe;
  }, []);

  // Load progression when chords change
  useEffect(() => {
    if (!audioEngineRef.current || !chords || chords.length === 0) return;

    const validChords = chords.filter(chord =>
      chord && chord.notes && Array.isArray(chord.notes) && chord.notes.length > 0
    );

    if (validChords.length > 0) {
      setIsLoading(true);
      audioEngineRef.current.loadProgression(validChords, bpm)
        .then(() => setIsLoading(false))
        .catch(err => {
          console.error('Failed to load progression:', err);
          setIsLoading(false);
        });
    }
  }, [chords, bpm]);

  // Update instrument
  useEffect(() => {
    if (!audioEngineRef.current) return;

    setIsLoading(true);
    audioEngineRef.current.setInstrument(selectedInstrument)
      .then(() => setIsLoading(false))
      .catch(err => {
        console.error('Failed to change instrument:', err);
        setIsLoading(false);
      });
  }, [selectedInstrument]);

  // Update volume
  useEffect(() => {
    if (!audioEngineRef.current) return;
    audioEngineRef.current.setVolume(volume / 100);
  }, [volume]);

  // Update MIDI enabled state
  useEffect(() => {
    if (!audioEngineRef.current) return;
    audioEngineRef.current.setMuted(!midiEnabled);
  }, [midiEnabled]);

  // Update audio output device
  useEffect(() => {
    if (!audioEngineRef.current || !audioOutputDevice) return;

    audioEngineRef.current.setOutputDevice(audioOutputDevice)
      .catch(err => {
        console.error('Failed to set output device:', err);
      });
  }, [audioOutputDevice]);

  // Playback controls
  const play = useCallback(async () => {
    if (!audioEngineRef.current || !playheadAnimatorRef.current || !contextRef.current) return;

    const validChords = chords.filter(chord =>
      chord && chord.notes && Array.isArray(chord.notes) && chord.notes.length > 0
    );

    if (validChords.length === 0) {
      console.warn('No chords to play');
      return;
    }

    try {
      // Resume audio context (required for browser autoplay policy)
      await contextRef.current.resume();

      // Calculate end of last chord
      const totalBeats = validChords[validChords.length - 1].startTime + validChords[validChords.length - 1].duration;

      // Set max beats so playhead stops at end of last chord
      playheadAnimatorRef.current.setMaxBeats(totalBeats);

      // Start audio engine
      await audioEngineRef.current.play();

      // Start playhead animation
      playheadAnimatorRef.current.start();

      // Start beat counter
      beatCounterRef.current?.start(totalBeats);

      setPlaybackState(prev => ({ ...prev, isPlaying: true }));
    } catch (error) {
      console.error('Failed to start playback:', error);
      alert('Unable to start audio. Please try again.');
    }
  }, [chords]);

  const pause = useCallback(() => {
    audioEngineRef.current?.pause();
    playheadAnimatorRef.current?.stop();
    setPlaybackState(prev => ({ ...prev, isPlaying: false }));
  }, []);

  const stop = useCallback(() => {
    audioEngineRef.current?.stop();
    playheadAnimatorRef.current?.stop();
    beatCounterRef.current?.stop();
    setPlaybackState(prev => ({
      ...prev,
      isPlaying: false,
      currentTime: 0,
      playbackPosition: 0,
    }));
  }, []);

  const seek = useCallback((beats: number) => {
    audioEngineRef.current?.seek(beats);
    playheadAnimatorRef.current?.seekToPixels(beats * pixelsPerBeat);
    setPlaybackState(prev => ({
      ...prev,
      currentTime: beats,
      playbackPosition: beats * pixelsPerBeat,
    }));
  }, [pixelsPerBeat]);

  const replay = useCallback(async () => {
    stop();
    setTimeout(() => play(), 100);
  }, [stop, play]);

  const setBPM = useCallback((newBPM: number) => {
    audioEngineRef.current?.setBPM(newBPM);
    playheadAnimatorRef.current?.setBPM(newBPM);
    timeTrackerRef.current?.setBPM(newBPM);
  }, []);

  return {
    playbackState,
    selectedInstrument,
    setSelectedInstrument,
    volume,
    setVolume,
    midiEnabled,
    setMidiEnabled,
    audioOutputDevice,
    setAudioOutputDevice,
    availableDevices,
    isLoading,
    play,
    pause,
    stop,
    seek,
    replay,
    setBPM,
  };
}

