export function useSupabaseStorage<T>(key: string, defaultValue: T): [T, (value: T) => void] {
  const queryClient = useQueryClient();
  const [userId, setUserId] = useState<string | null>(null);
  const [isClient, setIsClient] = useState(false);
  const [isLoaded, setIsLoaded] = useState(false);
  const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const supabase = createClient();

  // ALWAYS use defaultValue for initial state to prevent hydration mismatch
  // We'll load from cache/database after mount
  const [value, setValue] = useState<T>(defaultValue);

  useEffect(() => {
    setIsClient(true);
  }, []);

  // Update localStorage cache whenever value changes for instant future loads
  useEffect(() => {
    if (!isClient) return;

    try {
      const localStorageKey = `cache-${key}`;
      localStorage.setItem(localStorageKey, JSON.stringify(value));
    } catch (error) {
      // Ignore localStorage errors
    }
  }, [value, key, isClient]);

  // Load value on mount
  useEffect(() => {
    if (!isClient || isLoaded) return;

    async function loadValue() {
      try {
        // First, try to load from localStorage cache for instant render
        let cachedValue: T | null = null;
        try {
          const localStorageKey = `cache-${key}`;
          const cached = localStorage.getItem(localStorageKey);
          if (cached) {
            cachedValue = JSON.parse(cached) as T;
            setValue(cachedValue);
            if (key === 'guitar-app-root-note' || key === 'guitar-app-scale-name') {
              console.log(`≡ƒôª Cache loaded ${key}:`, cachedValue, '(default was:', defaultValue, ')');
            }
          }
        } catch (error) {
          // Ignore localStorage errors
        }

        const { data: { user }, error: authError } = await supabase.auth.getUser();

        // Silently handle auth errors (user not logged in)
        if (authError) {
          setIsLoaded(true);
          return;
        }

        if (user) {
          setUserId(user.id);

          // Check if this is a user_settings key
          const columnName = KEY_TO_COLUMN_MAP[key];

          if (columnName) {
            // Load from user_settings table
            const { data, error } = await supabase
              .from('user_settings')
              .select(columnName)
              .eq('user_id', user.id)
              .single();

            if (!error && data && data[columnName as keyof typeof data] !== undefined) {
              let loadedValue = data[columnName as keyof typeof data] as T;

              // CRITICAL: Normalize root_note values to sharp notation after loading
              // This ensures database values are always in sharp notation (A#, C#, etc.)
              // even if flat notation (Bb, Db, etc.) was somehow stored
              if (columnName === 'root_note' && typeof loadedValue === 'string') {
                const normalizedValue = normalizeNoteFromDisplay(loadedValue);
                if (key === 'guitar-app-root-note') {
                  console.log(`≡ƒöì Database loaded ${key}:`, loadedValue, 'ΓåÆ normalized:', normalizedValue, '(default was:', defaultValue, ')');
                }
                loadedValue = normalizedValue as T;
              }
              // CRITICAL: Normalize scale_name values to database format after loading
              // This ensures "Aeolian (Natural Minor)" ΓåÆ "Aeolian", "Ionian (Major)" ΓåÆ "Ionian"
              else if (columnName === 'scale_name' && typeof loadedValue === 'string') {
                const normalizedValue = normalizeScaleNameFromDisplay(loadedValue);
                if (key === 'guitar-app-scale-name') {
                  console.log(`≡ƒöì Database loaded ${key}:`, loadedValue, 'ΓåÆ normalized:', normalizedValue, '(default was:', defaultValue, ')');
                }
                loadedValue = normalizedValue as T;
              }
              else if (key === 'guitar-app-root-note' || key === 'guitar-app-scale-name') {
                console.log(`≡ƒöì Database loaded ${key}:`, loadedValue, '(default was:', defaultValue, ')');
              }

              // Only update if the value is different from cache to prevent unnecessary re-renders
              if (JSON.stringify(loadedValue) !== JSON.stringify(cachedValue)) {
                if (key === 'guitar-app-root-note' || key === 'guitar-app-scale-name') {
                  console.log(`Γ£à Database value different from cache, updating ${key}:`, loadedValue);
                }
                setValue(loadedValue);
              } else {
                if (key === 'guitar-app-root-note' || key === 'guitar-app-scale-name') {
                  console.log(`Γ£à Database matches cache for ${key}, no update needed`);
                }
              }
            } else if (error && key === 'guitar-app-root-note') {
              console.log(`ΓÜá∩╕Å Error loading ${key} from database:`, error, 'Keeping cached/default value');
            }
          } else if (key === 'guitar-app-manual-selections') {
            // Load manual selections
            const { data, error } = await supabase
              .from('user_manual_selections')
              .select('*')
              .eq('user_id', user.id)
              .order('timestamp', { ascending: true });

            if (!error && data) {
              const selections = data.map(row => ({
                key: row.key,
                scaleName: row.scale_name,
                timestamp: row.timestamp,
              }));
              setValue(selections as T);
            }
          } else if (key === 'midi-pedal-config') {
            // Load MIDI config
            const { data, error } = await supabase
              .from('user_midi_config')
              .select('active_config')
              .eq('user_id', user.id)
              .single();

            if (!error && data && data.active_config) {
              setValue(data.active_config as T);
            }
          }
        }
      } catch (error) {
        // Only log unexpected errors, not auth failures
        if (error && typeof error === 'object' && 'status' in error && error.status !== 400) {
          console.error(`Error loading ${key}:`, error);
        }
      } finally {
        setIsLoaded(true);
      }
    }

    loadValue();
  }, [key, isClient, isLoaded, supabase]);

  // Debounced save function
  const debouncedSave = useCallback(async (newValue: T) => {
    if (!userId) return;

    try {
      const columnName = KEY_TO_COLUMN_MAP[key];

      if (columnName) {
        // CRITICAL: Normalize root_note values to sharp notation before saving
        // This ensures database always stores sharp notation (A#, C#, etc.)
        // even if flat notation (Bb, Db, etc.) is passed in
        let valueToSave = newValue;
        if (columnName === 'root_note' && typeof newValue === 'string') {
          valueToSave = normalizeNoteFromDisplay(newValue) as T;
          console.log(`≡ƒÆ╛ Saving ${key}: "${newValue}" ΓåÆ normalized: "${valueToSave}"`);
        }
        // CRITICAL: Normalize scale_name values to database format before saving
        // This ensures "Aeolian (Natural Minor)" ΓåÆ "Aeolian", "Ionian (Major)" ΓåÆ "Ionian"
        else if (columnName === 'scale_name' && typeof newValue === 'string') {
          valueToSave = normalizeScaleNameFromDisplay(newValue) as T;
          console.log(`≡ƒÆ╛ Saving ${key}: "${newValue}" ΓåÆ normalized: "${valueToSave}"`);
        }

        // Save to user_settings table
        await supabase
          .from('user_settings')
          .upsert({
            user_id: userId,
            [columnName]: valueToSave,
          }, {
            onConflict: 'user_id',
          });

        // Invalidate React Query cache to trigger refetch
        queryClient.invalidateQueries({ queryKey: queryKeys.userSettings(userId) });
      } else if (key === 'guitar-app-manual-selections') {
        // Save manual selections
        const selections = newValue as any[];

        // Delete existing selections
        await supabase
          .from('user_manual_selections')
          .delete()
          .eq('user_id', userId);

        // Insert new selections
        if (selections && selections.length > 0) {
          await supabase
            .from('user_manual_selections')
            .insert(
              selections.map((sel: any) => ({
                user_id: userId,
                // CRITICAL: Normalize key to sharp notation before saving
                key: normalizeNoteFromDisplay(sel.key),
                scale_name: sel.scaleName,
                timestamp: sel.timestamp,
              }))
            );
        }

        // Invalidate React Query cache
        queryClient.invalidateQueries({ queryKey: queryKeys.userManualSelections(userId) });
      } else if (key === 'midi-pedal-config') {
        // Save MIDI config
        await supabase
          .from('user_midi_config')
          .upsert({
            user_id: userId,
            active_config: newValue,
          }, {
            onConflict: 'user_id',
          });

        // Invalidate React Query cache
        queryClient.invalidateQueries({ queryKey: queryKeys.userMidiConfig(userId) });
      }
    } catch (error) {
      console.error(`Error saving ${key}:`, error);
    }
  }, [userId, key, supabase, queryClient]);

  // Update value with debounced save
  const updateValue = useCallback((newValue: T) => {
    // Optimistic update
    setValue(newValue);

    if (!userId) return;

    // Clear existing timeout
    if (saveTimeoutRef.current) {
      clearTimeout(saveTimeoutRef.current);
    }

    // Set new timeout
    saveTimeoutRef.current = setTimeout(() => {
      debouncedSave(newValue);
    }, DEBOUNCE_DELAY);
  }, [userId, debouncedSave]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (saveTimeoutRef.current) {
        clearTimeout(saveTimeoutRef.current);
      }
    };
  }, []);

  return [value, updateValue];
}

/**
 * Client-only wrapper for Tone.js audio engine
 * This file ensures Tone.js is only loaded on the client side
 * Using Tone.js v14.7.77 (no AudioWorklet issues)
 */

'use client';

import { ChordInstance, InstrumentType } from './types';

// Dynamic import for Tone.js to avoid SSR issues
let Tone: typeof import('tone') | null = null;

export class ChordProgressionAudioEngine {
  private synth: any | null = null;
  private part: any | null = null;
  private currentInstrument: InstrumentType = 'piano';
  private isInitialized = false;

  constructor() {
    // Only initialize on client side
    if (typeof window !== 'undefined') {
      this.loadTone();
    }
  }

  /**
   * Dynamically load Tone.js module
   */
  private async loadTone() {
    if (Tone) return;

    try {
      const module = await import('tone');
      Tone = module;
      await this.initializeSynth();
    } catch (error) {
      console.error('Failed to load Tone.js:', error);
    }
  }

  /**
   * Initialize Tone.js synthesizer based on selected instrument
   * Note: This creates audio nodes but doesn't start AudioContext
   */
  private async initializeSynth() {
    if (!Tone) {
      await this.loadTone();
      if (!Tone) return;
    }

    try {
      if (this.synth) {
        this.synth.dispose();
      }

      if (this.currentInstrument === 'piano') {
        // Piano: Clean, bright tone
        this.synth = new Tone.PolySynth(Tone.Synth, {
          oscillator: { type: 'sine' },
          envelope: {
            attack: 0.005,
            decay: 0.1,
            sustain: 0.3,
            release: 1,
          },
        }).toDestination();
        this.synth.volume.value = -8;
      } else if (this.currentInstrument === 'guitar') {
        // Guitar: Warmer, plucked tone
        this.synth = new Tone.PolySynth(Tone.Synth, {
          oscillator: { type: 'triangle' },
          envelope: {
            attack: 0.01,
            decay: 0.2,
            sustain: 0.2,
            release: 1.5,
          },
        }).toDestination();
        this.synth.volume.value = -10;
      }
    } catch (error) {
      console.error('Failed to initialize synth:', error);
    }
  }

  /**
   * Set instrument type and reinitialize synth
   */
  public async setInstrument(instrument: InstrumentType) {
    this.currentInstrument = instrument;
    await this.initializeSynth();
  }

  /**
   * Load chord progression into Tone.js Part
   */
  public async loadProgression(chords: ChordInstance[], bpm: number) {
    if (!Tone) {
      await this.loadTone();
      if (!Tone) return;
    }

    // Validate chords array
    if (!chords || chords.length === 0) {
      console.warn('No chords to load');
      return;
    }

    Tone.Transport.bpm.value = bpm;

    if (this.part) {
      this.part.dispose();
    }

    // Convert ChordInstance to Tone.js events with validation
    const events = chords
      .filter(chord => chord && chord.notes && Array.isArray(chord.notes))
      .map(chord => ({
        time: `${chord.startTime}n`,
        duration: `${chord.duration}n`,
        notes: chord.notes.map(note => note + '4'),
      }));

    if (events.length === 0) {
      console.warn('No valid chord events to play');
      return;
    }

    // Create Tone.Part for scheduled playback
    this.part = new Tone.Part((time: number, event: any) => {
      this.synth?.triggerAttackRelease(event.notes, event.duration, time);
    }, events);

    // Calculate total duration for looping
    const totalDuration = this.getTotalDuration(chords);
    this.part.loop = true;
    this.part.loopEnd = `${totalDuration}n`;
  }

  /**
   * Start playback
   * This must be called from a user gesture (click, tap, etc.)
   */
  public async play() {
    if (!Tone) {
      await this.loadTone();
      if (!Tone) return;
    }

    try {
      // Start AudioContext - this MUST be called from a user gesture
      if (!this.isInitialized) {
        await Tone.start();
        this.isInitialized = true;
        console.log('AudioContext started successfully');
      }

      // Ensure synth is initialized
      if (!this.synth) {
        await this.initializeSynth();
      }

      Tone.Transport.start();
      this.part?.start(0);
    } catch (error) {
      console.error('Failed to start audio playback:', error);
      throw error;
    }
  }

  /**
   * Pause playback
   */
  public async pause() {
    if (!Tone) return;
    Tone.Transport.pause();
  }

  /**
   * Stop playback and reset to start
   */
  public async stop() {
    if (!Tone) return;
    Tone.Transport.stop();
    Tone.Transport.position = 0;
  }

  /**
   * Seek to specific time (in beats)
   */
  public async seek(beats: number) {
    if (!Tone) return;
    Tone.Transport.position = `${beats}n`;
  }

  /**
   * Get current playback position (in beats)
   */
  public getCurrentTime(): number {
    if (!Tone) return 0;
    const position = Tone.Transport.position;
    // Parse "bars:beats:sixteenths" format
    const positionStr = position.toString();
    const [bars, beats, sixteenths] = positionStr.split(':').map(Number);
    return (bars || 0) * 4 + (beats || 0) + (sixteenths || 0) / 4;
  }

  /**
   * Set BPM
   */
  public async setBPM(bpm: number) {
    if (!Tone) return;
    Tone.Transport.bpm.value = bpm;
  }

  /**
   * Calculate total duration of progression
   */
  private getTotalDuration(chords: ChordInstance[]): number {
    if (chords.length === 0) return 0;
    const lastChord = chords[chords.length - 1];
    return lastChord.startTime + lastChord.duration;
  }

  /**
   * Clean up resources
   */
  public dispose() {
    this.part?.dispose();
    this.synth?.dispose();
    if (Tone) {
      Tone.Transport.stop();
    }
  }
}

